import dotenv from 'dotenv';
dotenv.config();

import { prisma } from '../src/lib/prisma';

async function main() {
  console.log('--- Diagnóstico de Datos para Botica Juan ---');

  // Buscar clientes que contengan "Botica" o "Juan"
  const clientes = await prisma.clientes.findMany({
    where: {
      OR: [
        { razon_social: { contains: 'Botica', mode: 'insensitive' } },
        { nombre_comercial: { contains: 'Botica', mode: 'insensitive' } },
      ],
    },
  });

  if (clientes.length === 0) {
    console.log('No se encontró ningún cliente con ese nombre.');
    return;
  }

  for (const c of clientes) {
    console.log(`\nCliente: ID=${c.id}, Razón Social="${c.razon_social}", RUC=${c.ruc}`);

    // Contar cotizaciones por estado
    const cots = await prisma.cotizaciones.findMany({
      where: { cliente_id: c.id },
    });
    console.log(`Total cotizaciones: ${cots.length}`);
    const cotsPorEstado = cots.reduce((acc: any, curr: any) => {
      acc[curr.estado] = (acc[curr.estado] || 0) + 1;
      return acc;
    }, {});
    console.log('Cotizaciones por estado:', cotsPorEstado);

    // Contar pedidos por estado
    const peds = await prisma.pedidos.findMany({
      where: { cliente_id: c.id },
    });
    console.log(`Total pedidos: ${peds.length}`);
    const pedsPorEstado = peds.reduce((acc: any, curr: any) => {
      acc[curr.estado] = (acc[curr.estado] || 0) + 1;
      return acc;
    }, {});
    console.log('Pedidos por estado:', pedsPorEstado);

    // Ver los últimos 3 pedidos
    console.log('Últimos 3 pedidos en la DB:');
    peds.slice(0, 3).forEach(p => {
      console.log(`  - ID=${p.id}, Estado=${p.estado}, Total=${p.total}, Creado=${p.created_at}`);
    });
  }
}

main()
  .catch(console.error)
  .finally(() => prisma.$disconnect());

"use client";

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { Lock, Mail, Loader2, ArrowRight, ShieldCheck, AlertCircle } from 'lucide-react';
import Link from 'next/link';
import GoldenThreadBackground from "@/components/auth/GoldenThreadBackground";

export default function LoginAdminPage() {
  const router = useRouter();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      if (!email.toLowerCase().endsWith('@guor.com')) {
        throw new Error('Acceso restringido: Solo correos @guor.com');
      }

      const res = await fetch('/api/auth/login', {
        method: 'POST',
        body: JSON.stringify({ email, password }),
        headers: { 'Content-Type': 'application/json' }
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data.error || 'Credenciales incorrectas');

      const role = data.role?.toLowerCase().trim();
      const staffRoles = ['gerente','administrador','recepcionista','disenador','cortador','ayudante','representante_taller', 'almacenero'];

      if (staffRoles.includes(role)) {
        router.push('/admin/Panel-Administrativo/dashboard');
      } else if (role === 'cliente') {
        router.push('/portal/dashboard');
      } else {
        throw new Error('Sin permisos');
      }
    } catch (err: any) {
      setError(err.message);
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center px-4 relative">

      {/* BACKGROUND ANIMADO */}
      <GoldenThreadBackground />

      {/* CARD */}
      <div
        className="relative z-10 w-full max-w-md p-10 rounded-[2.5rem]"
        style={{
          background: "#fff4e2",
          border: "1px solid #e4c28a",
          boxShadow: "0 20px 60px rgba(35,30,29,0.1)"
        }}
      >

        {/* HEADER */}
        <div className="mb-8 text-center">
          <div
            className="w-12 h-12 rounded-xl flex items-center justify-center mx-auto mb-4 shadow-md"
            style={{ background: "#231e1d", color: "#e4c28a" }}
          >
            <ShieldCheck size={28} />
          </div>

          <h1 className="text-2xl font-black uppercase" style={{ color: "#231e1d" }}>
            GUOR CORPORATIVO
          </h1>

          <p className="text-[10px] font-bold uppercase mt-1" style={{ color: "rgba(35,30,29,0.5)" }}>
            PANEL ADMINISTRATIVO GUOR
          </p>
        </div>

        {/* ERROR */}
        {error && (
          <div
            className="mb-6 p-4 text-[11px] font-bold rounded-2xl flex items-center gap-3"
            style={{ background: "#fbddd3", border: "1px solid #b5854b", color: "#b5854b" }}
          >
            <AlertCircle size={16} /> {error}
          </div>
        )}

        {/* FORM */}
        <form onSubmit={handleLogin} className="space-y-5">

          {/* EMAIL */}
          <div className="relative">
            <Mail className="absolute left-4 top-1/2 -translate-y-1/2" size={18} style={{ color: "rgba(35,30,29,0.3)" }} />
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="Usuario Corporativo"
              required
              style={{
                width: "100%",
                padding: "1rem 1rem 1rem 3rem",
                background: "#fff4e2",
                border: "1px solid #e4c28a",
                borderRadius: "1rem",
                fontSize: "0.875rem",
                fontWeight: "700",
                color: "#231e1d",
                outline: "none",
                transition: "all 0.3s"
              }}
              onFocus={e => e.target.style.borderColor = "#b5854b"}
              onBlur={e => e.target.style.borderColor = "#e4c28a"}
            />
          </div>

          {/* PASSWORD */}
          <div className="relative">
            <Lock className="absolute left-4 top-1/2 -translate-y-1/2" size={18} style={{ color: "rgba(35,30,29,0.3)" }} />
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Contraseña"
              required
              style={{
                width: "100%",
                padding: "1rem 1rem 1rem 3rem",
                background: "#fff4e2",
                border: "1px solid #e4c28a",
                borderRadius: "1rem",
                fontSize: "0.875rem",
                fontWeight: "700",
                color: "#231e1d",
                outline: "none",
                transition: "all 0.3s"
              }}
              onFocus={e => e.target.style.borderColor = "#b5854b"}
              onBlur={e => e.target.style.borderColor = "#e4c28a"}
            />
          </div>

          {/* RECUPERAR */}
          <Link
            href="/recuperar-password"
            className="block text-right text-[10px] font-bold uppercase"
            style={{ color: "rgba(35,30,29,0.5)" }}
          >
            ¿OLVIDASTE TU CLAVE?
          </Link>

          {/* BOTÓN */}
          <button
            disabled={loading}
            type="submit"
            className="w-full py-4 rounded-2xl font-black text-xs uppercase flex items-center justify-center gap-3 transition-all duration-300"
            style={{
              background: "#231e1d",
              color: "#fff4e2",
              border: "2px solid #231e1d"
            }}
            onMouseEnter={e => {
              if (!loading) {
                const el = e.currentTarget as HTMLElement;
                el.style.background = "#b5854b";
                el.style.borderColor = "#b5854b";
                el.style.color = "#231e1d";
              }
            }}
            onMouseLeave={e => {
              const el = e.currentTarget as HTMLElement;
              el.style.background = "#231e1d";
              el.style.borderColor = "#231e1d";
              el.style.color = "#fff4e2";
            }}
          >
            {loading ? (
              <><Loader2 className="animate-spin" size={18} /> VERIFICANDO...</>
            ) : (
              <>INGRESAR AL SISTEMA <ArrowRight size={16} /></>
            )}
          </button>

        </form>

        {/* FOOTER */}
        <div className="mt-8 text-center">
          <Link
            href="/"
            className="text-[10px] font-bold uppercase"
            style={{ color: "rgba(35,30,29,0.5)" }}
          >
            ← VOLVER A LA PÁGINA PRINCIPAL
          </Link>
        </div>

      </div>
    </div>
  );
}

"use client";

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { Lock, Mail, Loader2, UserPlus, Eye, EyeOff, AlertCircle } from 'lucide-react';
import Link from 'next/link';

export default function LoginClientePage() {
  const router = useRouter();

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [showPass, setShowPass] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      if (email.toLowerCase().endsWith('@guor.com')) {
        throw new Error('Las cuentas corporativas deben ingresar por el Portal Administrativo.');
      }

      const res = await fetch('/api/auth/login', {
        method: 'POST',
        body: JSON.stringify({ email, password }),
        headers: { 'Content-Type': 'application/json' }
      });

      const data = await res.json();

      if (!res.ok) throw new Error(data.error || 'Credenciales inválidas');

      const role = data.role?.toLowerCase().trim();

      if (role === 'cliente') {
        router.push('/portal/dashboard');
      } else {
        router.push('/admin/Panel-Administrativo/dashboard');
      }

    } catch (err: any) {
      setError(err.message);
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl w-full mx-auto grid grid-cols-1 md:grid-cols-2 bg-[#fbddd3] rounded-[3rem] shadow-2xl overflow-hidden border border-[#e4c28a]">

      {/* IZQUIERDA CON IMAGEN */}
      <div
        className="p-12 text-white flex flex-col justify-center relative overflow-hidden bg-cover bg-center"
        style={{
          backgroundImage: "url('/imagen-fondo.jpeg')"
        }}
      >
        {/* OVERLAY OSCURO (para que el texto se vea bien) */}
        <div className="absolute inset-0 bg-[#231e1d]/75"></div>

        {/* CONTENIDO */}
        <div className="relative z-10">



          <span className="bg-[#b5854b] text-white px-4 py-1 rounded-full text-[10px] font-black uppercase tracking-widest w-fit mb-6">
            Beneficio Exclusivo B2B
          </span>

          <h2 className="text-5xl font-serif italic leading-tight mb-4">
            ¡Bienvenido a la <br />
            <span className="not-italic font-black text-6xl text-[#e4c28a]">Familia!</span>
          </h2>

          <p className="text-white/70 font-medium text-sm leading-relaxed mb-8">
            Regístrate hoy como socio estratégico y obtén un{" "}
            <span className="text-[#e4c28a] font-black">20% de descuento</span> en tu primera orden.
          </p>

          <Link
            href="/registro-cliente"
            className="flex items-center gap-3 text-sm font-black uppercase tracking-widest bg-[#b5854b] text-white px-8 py-4 rounded-2xl w-fit hover:bg-[#e4c28a] hover:text-[#231e1d] transition shadow-lg"
          >
            <UserPlus size={18} /> Crear Cuenta
          </Link>

        </div>
      </div>

      {/* FORM */}
      <div className="p-12 bg-[#fff4e2] flex flex-col justify-center">

        <div className="mb-10 text-center md:text-left">
          <h1 className="text-3xl font-black text-[#231e1d] tracking-tighter italic">
            Iniciar Sesión
          </h1>
          <p className="text-[#231e1d]/50 text-[10px] font-bold uppercase tracking-[0.2em] mt-1">
            Portal de Socios GUOR
          </p>
        </div>

        {error && (
          <div className="mb-6 p-4 bg-[#fbddd3] border border-[#e4c28a] text-[#231e1d] text-[11px] font-bold rounded-2xl flex items-center gap-3">
            <AlertCircle size={16} />
            {error}
          </div>
        )}

        <form onSubmit={handleLogin} className="space-y-6">

          {/* EMAIL */}
          <div className="group">
            <label className="text-[10px] font-black text-[#231e1d]/50 uppercase tracking-widest ml-1">
              Email de Socio
            </label>

            <div className="relative mt-1">
              <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-[#231e1d]/30 group-focus-within:text-[#b5854b]" size={18} />

              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="socio@empresa.com"
                className="w-full pl-12 pr-4 py-4 bg-[#fbddd3] border border-[#e4c28a] rounded-2xl text-sm outline-none focus:border-[#b5854b] transition font-bold text-[#231e1d]"
                required
              />
            </div>
          </div>

          {/* PASSWORD */}
          <div className="group">
            <label className="text-[10px] font-black text-[#231e1d]/50 uppercase tracking-widest ml-1">
              Clave de Acceso
            </label>

            <div className="relative mt-1">
              <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-[#231e1d]/30 group-focus-within:text-[#b5854b]" size={18} />

              <input
                type={showPass ? "text" : "password"}
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="••••••••"
                className="w-full pl-12 pr-12 py-4 bg-[#fbddd3] border border-[#e4c28a] rounded-2xl text-sm outline-none focus:border-[#b5854b] transition font-bold text-[#231e1d]"
                required
              />

              <button
                type="button"
                onClick={() => setShowPass(!showPass)}
                className="absolute right-4 top-1/2 -translate-y-1/2 text-[#231e1d]/40 hover:text-[#b5854b]"
              >
                {showPass ? <EyeOff size={18} /> : <Eye size={18} />}
              </button>
            </div>
          </div>

          <Link
            href="/recuperar-password"
            className="block text-[10px] font-black text-[#b5854b] uppercase hover:underline"
          >
            ¿Olvidaste tu contraseña?
          </Link>

          <button
            disabled={loading}
            type="submit"
            className="w-full py-5 bg-[#231e1d] text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] hover:bg-[#b5854b] transition flex items-center justify-center gap-3"
          >
            {loading ? <Loader2 className="animate-spin" size={18} /> : "Entrar al Portal"}
          </button>

        </form>

        <div className="mt-8 text-center">
          <Link
            href="/"
            className="text-[10px] font-black text-[#231e1d]/50 uppercase hover:text-[#b5854b]"
          >
            ← Volver a la página principal
          </Link>
        </div>

      </div>
    </div>
  );
}

"use client";

import { useState, useRef } from 'react';
import {
  Mail, ArrowLeft, Loader2, SendHorizontal,
  CheckCircle2, Lock, Eye, EyeOff, KeyRound, ArrowRight
} from 'lucide-react';
import Link from 'next/link';
import { motion, AnimatePresence } from 'framer-motion';
import GoldenThreadBackground from "@/components/auth/GoldenThreadBackground";
import Image from 'next/image';

type Step = 'email' | 'otp' | 'password' | 'success';

const STEP_INDEX: Record<Step, number> = { email: 0, otp: 1, password: 2, success: 3 };
const STEP_LABELS = ['Correo', 'Código', 'Contraseña'];

const slideVariants = {
  enter: { opacity: 0, x: 24 },
  center: { opacity: 1, x: 0 },
  exit: { opacity: 0, x: -24 },
};

export default function RecoverPasswordPage() {
  const [step, setStep] = useState<Step>('email');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [email, setEmail] = useState('');
  const [otp, setOtp] = useState(['', '', '', '', '', '']);
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);
  const [accessToken, setAccessToken] = useState('');
  const otpRefs = useRef<(HTMLInputElement | null)[]>([]);

  /* ── helpers ── */
  const handleEmailSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true); setError(null);
    try {
      const res = await fetch('/api/auth/send-otp', {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || 'No se pudo enviar el código');
      setStep('otp');
    } catch (err: any) { setError(err.message); }
    finally { setLoading(false); }
  };

  const handleOtpInput = (index: number, value: string) => {
    if (!/^[0-9]?$/.test(value)) return;
    const next = [...otp]; next[index] = value; setOtp(next);
    if (value && index < 5) otpRefs.current[index + 1]?.focus();
  };

  const handleOtpKeyDown = (index: number, e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Backspace' && !otp[index] && index > 0)
      otpRefs.current[index - 1]?.focus();
  };

  const handleOtpPaste = (e: React.ClipboardEvent) => {
    const pasted = e.clipboardData.getData('text').replace(/[^0-9]/g, '').slice(0, 6);
    if (pasted.length === 6) { setOtp(pasted.split('')); otpRefs.current[5]?.focus(); }
  };

  const handleOtpSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const code = otp.join('');
    if (code.length !== 6) { setError('Ingresa el código completo de 6 dígitos'); return; }
    setLoading(true); setError(null);
    try {
      const res = await fetch('/api/auth/verify-otp', {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, otp: code }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || 'Código incorrecto o expirado');
      setAccessToken(data.access_token);
      setStep('password');
    } catch (err: any) {
      setError(err.message);
      setOtp(['', '', '', '', '', '']);
      otpRefs.current[0]?.focus();
    } finally { setLoading(false); }
  };

  const handlePasswordSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault(); setError(null);
    const formData = new FormData(e.currentTarget);
    const password = formData.get('password') as string;
    const confirm = formData.get('confirm') as string;
    const hasUpper = /[A-Z]/.test(password), hasLower = /[a-z]/.test(password);
    const hasNumber = /[0-9]/.test(password), hasSpecial = /[!@#$%^&*(),.?":{}|<>]/.test(password);
    if (!hasUpper || !hasLower || !hasNumber || !hasSpecial) {
      setError('La contraseña debe incluir mayúsculas, minúsculas, números y signos'); return;
    }
    if (password !== confirm) { setError('Las contraseñas no coinciden'); return; }
    setLoading(true);
    try {
      const res = await fetch('/api/auth/reset-password', {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ access_token: accessToken, password }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || 'Error al restablecer la contraseña');
      setStep('success');
    } catch (err: any) { setError(err.message); }
    finally { setLoading(false); }
  };

  /* ── ÉXITO ── */
  if (step === 'success') {
    return (
      <div className="min-h-screen flex items-center justify-center px-4 py-12 relative" style={{ background: '#fdf9f3' }}>
        <GoldenThreadBackground />
        <div
          className="relative z-10 max-w-md w-full text-center space-y-6 p-10 rounded-[2.5rem]"
          style={{ background: '#fdf9f3', border: '1.5px solid #e8d5a8', boxShadow: '0 20px 60px rgba(26,20,16,0.10)' }}
        >
          <div
            className="w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4"
            style={{ background: '#f5efe4', border: '2px solid #e8d5a8', color: '#8a6d3b' }}
          >
            <CheckCircle2 size={40} />
          </div>
          <h2 className="text-2xl font-black" style={{ color: '#1a1410' }}>¡Contraseña Actualizada!</h2>
          <p className="text-sm" style={{ color: 'rgba(26,20,16,0.60)' }}>
            Tu contraseña ha sido restablecida exitosamente.
          </p>
          <Link
            href="/login-cliente"
            className="flex items-center justify-center gap-3 w-full py-4 rounded-2xl font-black text-xs uppercase tracking-widest transition-all"
            style={{ background: '#1a1410', color: '#fdf9f3', border: '1.5px solid #1a1410' }}
            onMouseEnter={e => { const el = e.currentTarget as HTMLElement; el.style.background = '#c4a35a'; el.style.borderColor = '#c4a35a'; el.style.color = '#1a1410'; }}
            onMouseLeave={e => { const el = e.currentTarget as HTMLElement; el.style.background = '#1a1410'; el.style.borderColor = '#1a1410'; el.style.color = '#fdf9f3'; }}
          >
            Iniciar Sesión <ArrowRight size={16} />
          </Link>
        </div>
      </div>
    );
  }

  /* ── MAIN ── */
  return (
    <div className="relative min-h-screen flex items-center justify-center px-4 py-12" style={{ background: '#fdf9f3' }}>
      <GoldenThreadBackground />

      <div
        className="relative z-10 max-w-4xl w-full rounded-[3rem] overflow-hidden grid grid-cols-1 md:grid-cols-5"
        style={{ border: '1.5px solid #e8d5a8', boxShadow: '0 20px 60px rgba(26,20,16,0.10)' }}
      >

        {/* ── PANEL IZQUIERDO ── */}
        <div className="hidden md:flex md:col-span-2 p-10 flex-col justify-between" style={{ background: '#1a1410' }}>
          <div>
            <div className="w-14 h-14 rounded-xl flex items-center justify-center mb-8 shadow-xl" style={{ background: '#fdf9f3' }}>
              <Image src="/logo.png" alt="Logo Guor" width={40} height={40} />
            </div>
            <h2 className="text-3xl italic" style={{ color: '#fdf9f3' }}>
              Recupera tu <br />
              <span className="font-black uppercase text-4xl not-italic" style={{ color: '#c4a35a' }}>
                Acceso
              </span>
            </h2>
            <p
              className="mt-8 text-sm leading-relaxed font-medium pl-4"
              style={{ color: 'rgba(253,249,243,0.65)', borderLeft: '2px solid #c4a35a' }}
            >
              Te enviaremos un código de verificación a tu correo para que puedas
              restablecer tu contraseña de forma segura.
            </p>

            {/* Indicador de pasos */}
            <div className="mt-10 space-y-3">
              {STEP_LABELS.map((label, i) => {
                const current = STEP_INDEX[step];
                const done = current > i;
                const active = current === i;
                return (
                  <div key={label} className="flex items-center gap-3">
                    <div
                      className="w-7 h-7 rounded-full flex items-center justify-center text-[10px] font-black flex-shrink-0 transition-all duration-300"
                      style={{
                        background: done ? '#c4a35a' : active ? '#fdf9f3' : 'rgba(253,249,243,0.12)',
                        color: done ? '#1a1410' : active ? '#1a1410' : 'rgba(253,249,243,0.35)',
                      }}
                    >
                      {done ? '✓' : i + 1}
                    </div>
                    <span
                      className="text-xs font-bold uppercase tracking-widest transition-all duration-300"
                      style={{ color: done || active ? '#fdf9f3' : 'rgba(253,249,243,0.30)' }}
                    >
                      {label}
                    </span>
                  </div>
                );
              })}
            </div>
          </div>
          <p className="text-[9px] uppercase" style={{ color: 'rgba(253,249,243,0.28)' }}>© 2026 GUOR</p>
        </div>

        {/* ── PANEL DERECHO (FORMULARIO) ── */}
        <div className="md:col-span-3 p-8 md:p-12 flex flex-col justify-center" style={{ background: '#fdf9f3', minHeight: '520px' }}>

          <AnimatePresence mode="wait">

            {/* PASO 1: CORREO */}
            {step === 'email' && (
              <motion.div key="email" variants={slideVariants} initial="enter" animate="center" exit="exit" transition={{ duration: 0.22 }}>
                <div className="mb-8">
                  <Link
                    href="/login-cliente"
                    className="inline-flex items-center gap-2 text-[10px] font-black uppercase mb-6 transition-colors"
                    style={{ color: 'rgba(26,20,16,0.35)' }}
                    onMouseEnter={e => (e.currentTarget.style.color = '#8a6d3b')}
                    onMouseLeave={e => (e.currentTarget.style.color = 'rgba(26,20,16,0.35)')}
                  >
                    <ArrowLeft size={13} /> Volver al login
                  </Link>
                  <h1 className="text-3xl font-black" style={{ color: '#1a1410' }}>Recuperar Acceso</h1>
                  <p className="text-[10px] font-bold uppercase tracking-[0.2em] mt-1" style={{ color: '#8a6d3b' }}>
                    Te enviamos un código de 6 dígitos
                  </p>
                </div>

                <form onSubmit={handleEmailSubmit} className="space-y-4">
                  {error && <ErrorBox message={error} />}

                  <div className="relative">
                    <Mail className="absolute left-4 top-1/2 -translate-y-1/2 pointer-events-none" size={18} style={{ color: 'rgba(26,20,16,0.30)' }} />
                    <input
                      type="email" value={email} onChange={e => setEmail(e.target.value)}
                      placeholder="CORREO CORPORATIVO" required className="recover-input"
                    />
                  </div>

                  <SubmitButton loading={loading} label="Enviar Código" icon={<SendHorizontal size={15} style={{ color: '#c4a35a' }} />} />
                </form>
              </motion.div>
            )}

            {/* PASO 2: OTP */}
            {step === 'otp' && (
              <motion.div key="otp" variants={slideVariants} initial="enter" animate="center" exit="exit" transition={{ duration: 0.22 }}>
                <div className="mb-8">
                  <button
                    onClick={() => { setStep('email'); setError(null); setOtp(['', '', '', '', '', '']); }}
                    className="inline-flex items-center gap-2 text-[10px] font-black uppercase mb-6 transition-colors"
                    style={{ color: 'rgba(26,20,16,0.35)' }}
                    onMouseEnter={e => (e.currentTarget.style.color = '#8a6d3b')}
                    onMouseLeave={e => (e.currentTarget.style.color = 'rgba(26,20,16,0.35)')}
                  >
                    <ArrowLeft size={13} /> Volver
                  </button>
                  <h1 className="text-3xl font-black" style={{ color: '#1a1410' }}>Verificar Código</h1>
                  <p className="text-[10px] font-bold uppercase tracking-[0.2em] mt-1" style={{ color: '#8a6d3b' }}>
                    Enviado a{' '}
                    <span style={{ color: '#1a1410' }}>{email}</span>
                  </p>
                </div>

                <form onSubmit={handleOtpSubmit} className="space-y-6">
                  {error && <ErrorBox message={error} />}

                  <div className="flex gap-3 justify-center" onPaste={handleOtpPaste}>
                    {otp.map((digit, i) => (
                      <input
                        key={i}
                        ref={el => { otpRefs.current[i] = el; }}
                        type="text" inputMode="numeric" maxLength={1} value={digit}
                        onChange={e => handleOtpInput(i, e.target.value)}
                        onKeyDown={e => handleOtpKeyDown(i, e)}
                        className="otp-input"
                        autoFocus={i === 0}
                      />
                    ))}
                  </div>

                  <SubmitButton
                    loading={loading}
                    disabled={otp.join('').length !== 6}
                    label="Verificar Código"
                    icon={<KeyRound size={15} style={{ color: '#c4a35a' }} />}
                  />

                  <p className="text-center text-[10px] uppercase font-bold" style={{ color: 'rgba(26,20,16,0.40)' }}>
                    ¿No recibiste el código?{' '}
                    <button
                      type="button"
                      className="font-black transition-colors"
                      style={{ color: '#8a6d3b' }}
                      onMouseEnter={e => (e.currentTarget.style.color = '#1a1410')}
                      onMouseLeave={e => (e.currentTarget.style.color = '#8a6d3b')}
                      onClick={() => {
                        setError(null);
                        fetch('/api/auth/send-otp', {
                          method: 'POST', headers: { 'Content-Type': 'application/json' },
                          body: JSON.stringify({ email }),
                        });
                      }}
                    >
                      Reenviar
                    </button>
                  </p>
                </form>
              </motion.div>
            )}

            {/* PASO 3: NUEVA CONTRASEÑA */}
            {step === 'password' && (
              <motion.div key="password" variants={slideVariants} initial="enter" animate="center" exit="exit" transition={{ duration: 0.22 }}>
                <div className="mb-8">
                  <h1 className="text-3xl font-black" style={{ color: '#1a1410' }}>Nueva Contraseña</h1>
                  <p className="text-[10px] font-bold uppercase tracking-[0.2em] mt-1" style={{ color: '#8a6d3b' }}>
                    Crea una contraseña segura
                  </p>
                </div>

                <form onSubmit={handlePasswordSubmit} className="space-y-4">
                  {error && <ErrorBox message={error} />}

                  <div className="relative">
                    <Lock className="absolute left-4 top-1/2 -translate-y-1/2 pointer-events-none" size={18} style={{ color: 'rgba(26,20,16,0.30)' }} />
                    <input
                      name="password" type={showPassword ? 'text' : 'password'}
                      required placeholder="NUEVA CONTRASEÑA (A-a, 0-9, #$*)" className="recover-input pr-12"
                    />
                    <button type="button" onClick={() => setShowPassword(v => !v)}
                      className="absolute right-4 top-1/2 -translate-y-1/2"
                      style={{ color: 'rgba(26,20,16,0.30)' }}
                    >
                      {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
                    </button>
                  </div>

                  <div className="relative">
                    <Lock className="absolute left-4 top-1/2 -translate-y-1/2 pointer-events-none" size={18} style={{ color: 'rgba(26,20,16,0.30)' }} />
                    <input
                      name="confirm" type={showConfirm ? 'text' : 'password'}
                      required placeholder="CONFIRMAR CONTRASEÑA" className="recover-input pr-12"
                    />
                    <button type="button" onClick={() => setShowConfirm(v => !v)}
                      className="absolute right-4 top-1/2 -translate-y-1/2"
                      style={{ color: 'rgba(26,20,16,0.30)' }}
                    >
                      {showConfirm ? <EyeOff size={16} /> : <Eye size={16} />}
                    </button>
                  </div>

                  <SubmitButton loading={loading} label="Restablecer Contraseña" />
                </form>
              </motion.div>
            )}

          </AnimatePresence>

          {/* Footer link */}
          <div className="mt-8 pt-6 text-center" style={{ borderTop: '1px solid #e8d5a8' }}>
            <p className="text-[10px] uppercase" style={{ color: 'rgba(26,20,16,0.45)' }}>
              ¿Recordaste tu contraseña?{' '}
              <Link href="/login-cliente" className="font-bold" style={{ color: '#8a6d3b' }}>
                Iniciar Sesión
              </Link>
            </p>
          </div>
        </div>
      </div>

      <style jsx global>{`
        .recover-input {
          width: 100%;
          padding: 1rem 1rem 1rem 3.5rem;
          background-color: #fdf9f3;
          border: 1.5px solid #e8d5a8;
          border-radius: 1.25rem;
          font-size: 0.75rem;
          font-weight: 700;
          color: #1a1410;
          outline: none;
          transition: all 0.25s ease;
        }
        .recover-input:focus {
          border-color: #c4a35a;
          box-shadow: 0 4px 16px rgba(196,163,90,0.14);
        }
        .recover-input::placeholder {
          color: rgba(26,20,16,0.32);
        }
        .otp-input {
          width: 52px;
          height: 60px;
          text-align: center;
          font-size: 1.4rem;
          font-weight: 900;
          color: #1a1410;
          background: #fdf9f3;
          border: 1.5px solid #e8d5a8;
          border-radius: 1.1rem;
          outline: none;
          transition: all 0.2s ease;
          caret-color: #c4a35a;
        }
        .otp-input:focus {
          border-color: #c4a35a;
          box-shadow: 0 4px 16px rgba(196,163,90,0.18);
          transform: scale(1.06);
        }
      `}</style>
    </div>
  );
}

/* ── Subcomponentes ── */

function ErrorBox({ message }: { message: string }) {
  return (
    <div
      className="p-4 text-[10px] font-black rounded-xl flex items-center gap-3"
      style={{ background: '#fdf9f3', border: '1px solid #8a6d3b', color: '#8a6d3b' }}
    >
      {message.toUpperCase()}
    </div>
  );
}

function SubmitButton({
  loading, label, icon, disabled,
}: {
  loading: boolean; label: string; icon?: React.ReactNode; disabled?: boolean;
}) {
  return (
    <button
      type="submit"
      disabled={loading || disabled}
      className="w-full py-4 rounded-2xl font-black text-[10px] uppercase tracking-[0.2em] transition-all duration-300 flex items-center justify-center gap-2"
      style={{ background: '#1a1410', color: '#fdf9f3', border: '1.5px solid #1a1410', opacity: disabled ? 0.45 : 1 }}
      onMouseEnter={e => {
        if (loading || disabled) return;
        const el = e.currentTarget as HTMLElement;
        el.style.background = '#c4a35a'; el.style.borderColor = '#c4a35a'; el.style.color = '#1a1410';
      }}
      onMouseLeave={e => {
        const el = e.currentTarget as HTMLElement;
        el.style.background = '#1a1410'; el.style.borderColor = '#1a1410'; el.style.color = '#fdf9f3';
      }}
    >
      {loading
        ? <Loader2 className="animate-spin" size={16} />
        : <>{label}{icon}</>
      }
    </button>
  );
}

"use client";

import { useState, useRef, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import GoldenThreadBackground from "@/components/auth/GoldenThreadBackground";
import Link from 'next/link';
import Image from 'next/image';
import {
  Building2, Mail, Lock, User,
  ArrowRight, Loader2, CheckCircle2, AlertCircle,
  Phone, MapPin, Eye, EyeOff, Briefcase, Tag, ChevronDown
} from 'lucide-react';
import router from 'next/router';

// Banderas usando flagcdn.com — imágenes reales, funcionan en todos los navegadores/SO
const SOUTH_AMERICA_PREFIXES = [
  { code: 'AR', name: 'Argentina', prefix: '+54', minLen: 10, maxLen: 11 },
  { code: 'BO', name: 'Bolivia', prefix: '+591', minLen: 8, maxLen: 8 },
  { code: 'BR', name: 'Brasil', prefix: '+55', minLen: 10, maxLen: 11 },
  { code: 'CL', name: 'Chile', prefix: '+56', minLen: 9, maxLen: 9 },
  { code: 'CO', name: 'Colombia', prefix: '+57', minLen: 10, maxLen: 10 },
  { code: 'EC', name: 'Ecuador', prefix: '+593', minLen: 9, maxLen: 9 },
  { code: 'GY', name: 'Guyana', prefix: '+592', minLen: 7, maxLen: 7 },
  { code: 'PY', name: 'Paraguay', prefix: '+595', minLen: 9, maxLen: 9 },
  { code: 'PE', name: 'Perú', prefix: '+51', minLen: 9, maxLen: 9 },
  { code: 'SR', name: 'Surinam', prefix: '+597', minLen: 6, maxLen: 7 },
  { code: 'UY', name: 'Uruguay', prefix: '+598', minLen: 8, maxLen: 9 },
  { code: 'VE', name: 'Venezuela', prefix: '+58', minLen: 10, maxLen: 10 },
]

// URL de bandera por código de país (flagcdn = CDN gratuito, sin API key)
const flagUrl = (code: string) =>
  `https://flagcdn.com/24x18/${code.toLowerCase()}.png`;

function Flag({ code, size = 24 }: { code: string; size?: number }) {
  return (
    <img
      src={flagUrl(code)}
      alt={code}
      width={size}
      height={Math.round(size * 0.75)}
      style={{ borderRadius: '2px', objectFit: 'cover', flexShrink: 0 }}
    />
  );
}

export default function RegisterPage() {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [selectedPrefix, setSelectedPrefix] = useState(SOUTH_AMERICA_PREFIXES[8]); // Perú
  const [showPrefixDropdown, setShowPrefixDropdown] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handler = (e: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
        setShowPrefixDropdown(false);
      }
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    const formData = new FormData(e.currentTarget);
    const ruc = formData.get('ruc') as string;
    const telefonoNum = formData.get('telefono') as string;
    const { minLen, maxLen } = selectedPrefix;

    if (ruc.length !== 11) {
      setError('El RUC debe tener exactamente 11 dígitos');
      setLoading(false);
      return;
    }

    if (telefonoNum.length < minLen || telefonoNum.length > maxLen) {
      setError(
        `El número para ${selectedPrefix.name} debe tener ${minLen === maxLen ? `${minLen}` : `${minLen}–${maxLen}`
        } dígitos`
      );
      setLoading(false);
      return;
    }

    const password = formData.get('password') as string;
    const hasUpper = /[A-Z]/.test(password);
    const hasLower = /[a-z]/.test(password);
    const hasNumber = /[0-9]/.test(password);
    const hasSpecial = /[!@#$%^&*(),.?":{}|<>]/.test(password);

    if (!hasUpper || !hasLower || !hasNumber || !hasSpecial) {
      setError('La contraseña debe incluir mayúsculas, minúsculas, números y signos');
      setLoading(false);
      return;
    }

    const payload = {
      email: formData.get('email') as string,
      password,
      ruc,
      razon_social: formData.get('razonSocial') as string,
      nombre_comercial: formData.get('nombreComercial') as string,
      telefono: `${selectedPrefix.prefix}${telefonoNum}`,
      direccion: formData.get('direccion') as string,
      tipo_cliente: formData.get('tipoCliente') as string,
    };

    try {
      const res = await fetch('/api/auth/signup', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || 'Error al procesar el registro');
      setSuccess(true);
      router.push('/login-cliente');
    } catch (err: any) {
      setError(err.message || 'Error al procesar el registro');
    } finally {
      setLoading(false);
    }
  };

  /* ─── SUCCESS ─── */
  if (success) {
    return (
      <div className="min-h-screen flex items-center justify-center px-4 py-12 relative" style={{ background: '#fdf9f3' }}>
        <GoldenThreadBackground />
        <div
          className="max-w-md w-full text-center space-y-6 p-10 rounded-[2.5rem]"
          style={{ background: '#fdf9f3', border: '1.5px solid #e8d5a8', boxShadow: '0 20px 60px rgba(26,20,16,0.10)' }}
        >
          <div
            className="w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4"
            style={{ background: '#f5efe4', border: '2px solid #e8d5a8', color: '#8a6d3b' }}
          >
            <CheckCircle2 size={40} />
          </div>
          <h2 className="text-2xl font-black" style={{ color: '#1a1410' }}>¡Registro Exitoso!</h2>
          <p className="text-sm" style={{ color: 'rgba(26,20,16,0.60)' }}>
            Su cuenta ha sido creada. Ya puede iniciar sesión.
          </p>
          <Link
            href="/login-cliente"
            className="flex items-center justify-center gap-3 w-full py-4 rounded-2xl font-black text-xs uppercase tracking-widest transition-all"
            style={{ background: '#1a1410', color: '#fdf9f3', border: '1.5px solid #1a1410' }}
            onMouseEnter={e => { const el = e.currentTarget as HTMLElement; el.style.background = '#c4a35a'; el.style.borderColor = '#c4a35a'; el.style.color = '#1a1410'; }}
            onMouseLeave={e => { const el = e.currentTarget as HTMLElement; el.style.background = '#1a1410'; el.style.borderColor = '#1a1410'; el.style.color = '#fdf9f3'; }}
          >
            Iniciar Sesión <ArrowRight size={16} />
          </Link>
        </div>
      </div>
    );
  }

  /* ─── MAIN FORM ─── */
  return (
    <div className="md:col-span-3 p-8 md:p-12 flex flex-col justify-center" style={{ background: '#fdf9f3' }}>
      <GoldenThreadBackground />

      <div
        className="relative z-10 w-full grid grid-cols-5 rounded-[2.5rem] overflow-hidden"
        style={{ maxWidth: '900px', border: '1.5px solid #e8d5a8', boxShadow: '0 20px 60px rgba(26,20,16,0.10)' }}
      >

        {/* ── LADO IZQUIERDO ── */}
        <div className="md:flex md:col-span-2 p-10 flex-col justify-between hidden" style={{ background: '#1a1410' }}>
          <div>
            <div className="w-14 h-14 rounded-xl flex items-center justify-center mb-8 shadow-xl" style={{ background: '#fdf9f3' }}>
              <Image src="/logo.png" alt="Logo Guor" width={40} height={40} />
            </div>
            <h2 className="text-3xl italic" style={{ color: '#fdf9f3' }}>
              Excelencia en <br />
              <span className="font-black uppercase text-4xl not-italic" style={{ color: '#c4a35a' }}>
                Textiles B2B
              </span>
            </h2>
            <p
              className="mt-8 text-sm leading-relaxed font-medium pl-4"
              style={{ color: 'rgba(253,249,243,0.65)', borderLeft: '2px solid #c4a35a' }}
            >
              Únete a nuestra red mayorista para gestionar pedidos con soporte
              inteligente y optimizar tus procesos comerciales dentro del
              ecosistema GUOR.
            </p>
          </div>
          <p className="text-[9px] uppercase" style={{ color: 'rgba(253,249,243,0.28)' }}>© 2026 GUOR</p>
        </div>

        {/* ── FORMULARIO ── */}
        <div className="md:col-span-3 p-8 md:p-12 flex flex-col justify-center" style={{ background: '#fdf9f3' }}>
          <div className="mb-8">
            <h1 className="text-3xl font-black" style={{ color: '#1a1410' }}>Registro de Socio</h1>
            <p className="text-[10px] font-bold uppercase tracking-[0.2em] mt-1" style={{ color: '#8a6d3b' }}>
              Acceso inmediato al sistema
            </p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-4">

            {error && (
              <div
                className="p-4 text-[10px] font-black rounded-xl flex items-center gap-3"
                style={{ background: '#fdf9f3', border: '1px solid #8a6d3b', color: '#8a6d3b' }}
              >
                <AlertCircle size={16} /> {error.toUpperCase()}
              </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">

              <div className="md:col-span-2 relative">
                <Building2 className="absolute left-4 top-1/2 -translate-y-1/2 pointer-events-none" size={18} style={{ color: 'rgba(26,20,16,0.30)' }} />
                <input name="razonSocial" required placeholder="RAZÓN SOCIAL / EMPRESA" className="register-input" />
              </div>

              <div className="md:col-span-2 relative">
                <Briefcase className="absolute left-4 top-1/2 -translate-y-1/2 pointer-events-none" size={18} style={{ color: 'rgba(26,20,16,0.30)' }} />
                <input name="nombreComercial" placeholder="NOMBRE COMERCIAL (OPCIONAL)" className="register-input" />
              </div>

              <div className="relative">
                <User className="absolute left-4 top-1/2 -translate-y-1/2 pointer-events-none" size={18} style={{ color: 'rgba(26,20,16,0.30)' }} />
                <input
                  name="ruc" required placeholder="RUC (11 DÍGITOS)" className="register-input"
                  maxLength={11}
                  onInput={e => { e.currentTarget.value = e.currentTarget.value.replace(/\D/g, ''); }}
                />
              </div>

              <div className="relative">
                <Tag className="absolute left-4 top-1/2 -translate-y-1/2 pointer-events-none" size={18} style={{ color: 'rgba(26,20,16,0.30)' }} />
                <select name="tipoCliente" required className="register-input appearance-none">
                  <option value="">TIPO DE CLIENTE</option>
                  <option value="corporativo">CORPORATIVO</option>
                  <option value="minorista">MINORISTA</option>
                  <option value="distribuidor">DISTRIBUIDOR</option>
                </select>
              </div>

              {/* ── TELÉFONO CON PREFIJO + BANDERA ── */}
              <div className="md:col-span-2" ref={dropdownRef} style={{ position: 'relative' }}>
                <div
                  className="flex rounded-[1.25rem]"
                  style={{ border: '1.5px solid #e8d5a8', background: '#fdf9f3', overflow: 'visible' }}
                >
                  {/* Botón selector */}
                  <div style={{ position: 'relative', flexShrink: 0 }}>
                    <button
                      type="button"
                      onClick={() => setShowPrefixDropdown(v => !v)}
                      className="flex items-center gap-2 px-4 py-4 font-bold text-xs h-full rounded-l-[1.2rem] transition-colors"
                      style={{
                        background: showPrefixDropdown ? '#f5efe4' : 'transparent',
                        color: '#1a1410',
                        borderRight: '1.5px solid #e8d5a8',
                        minWidth: '110px',
                      }}
                    >
                      {/* Imagen real de bandera */}
                      <Flag code={selectedPrefix.code} size={22} />
                      <span style={{ color: '#8a6d3b', fontWeight: 900, fontSize: '0.75rem' }}>
                        {selectedPrefix.prefix}
                      </span>
                      <ChevronDown
                        size={13}
                        style={{
                          color: 'rgba(26,20,16,0.40)',
                          transform: showPrefixDropdown ? 'rotate(180deg)' : 'rotate(0deg)',
                          transition: '0.2s',
                        }}
                      />
                    </button>

                    {/* ── DROPDOWN ── */}
                    {showPrefixDropdown && (
                      <div
                        style={{
                          position: 'absolute',
                          top: 'calc(100% + 6px)',
                          left: 0,
                          zIndex: 9999,
                          background: '#fdf9f3',
                          border: '1.5px solid #e8d5a8',
                          borderRadius: '1rem',
                          boxShadow: '0 8px 32px rgba(26,20,16,0.13)',
                          minWidth: '220px',
