              {/* Preview de datos extraídos */}
              {datosExtraidos && (
                <div className="space-y-4 border-t border-slate-100 pt-4">
                  <p className="text-xs font-black text-slate-400 uppercase tracking-widest">
                    Datos extraídos — revisa antes de guardar
                  </p>

                  <div className="grid grid-cols-2 gap-3">
                    {datosExtraidos.sam_total && (
                      <div className="bg-orange-50 border border-orange-100 rounded-xl p-3">
                        <p className="text-[10px] text-orange-400 font-black uppercase tracking-widest">SAM total</p>
                        <p className="text-sm font-black text-orange-700">{datosExtraidos.sam_total} min</p>
                      </div>
                    )}
                    {datosExtraidos.costo_estimado && (
                      <div className="bg-emerald-50 border border-emerald-100 rounded-xl p-3">
                        <p className="text-[10px] text-emerald-400 font-black uppercase tracking-widest">Costo estimado</p>
                        <p className="text-sm font-black text-emerald-700">S/ {datosExtraidos.costo_estimado}</p>
                      </div>
                    )}
                  </div>

                  {/* Tallas del producto */}
                  {datosExtraidos.tallas_disponibles?.length > 0 && (
                    <div className="bg-white border border-slate-100 rounded-xl p-3">
                      <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mb-2">
                        Tallas (desde producto)
                      </p>
                      <div className="flex flex-wrap gap-2">
                        {datosExtraidos.tallas_disponibles.map((t) => (
                          <span key={t} className="px-3 py-1 bg-slate-100 rounded-lg text-xs font-bold text-slate-700">{t}</span>
                        ))}
                      </div>
                    </div>
                  )}

                  {/* Colores del producto */}
                  {datosExtraidos.colores_disponibles?.length > 0 && (
                    <div className="bg-white border border-slate-100 rounded-xl p-3">
                      <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mb-2">
                        Colores (desde producto)
                      </p>
                      <div className="flex flex-wrap gap-2">
                        {datosExtraidos.colores_disponibles.map((c) => (
                          <span key={c} className="px-3 py-1 bg-pink-50 border border-pink-100 rounded-lg text-xs font-bold text-pink-700">{c}</span>
                        ))}
                      </div>
                    </div>
                  )}

                  {/* Medidas extraídas */}
                  {datosExtraidos.medidas?.length > 0 && (
                    <div className="bg-white border border-slate-100 rounded-xl overflow-hidden">
                      <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest p-3 border-b border-slate-100">
                        Medidas extraídas ({datosExtraidos.medidas.length})
                      </p>
                      <div className="overflow-x-auto">
                        <table className="w-full text-xs">
                          <thead className="bg-slate-50">
                            <tr>
                              <th className="text-left p-2 font-black text-slate-400 uppercase tracking-wider">Punto</th>
                              <th className="text-left p-2 font-black text-slate-400 uppercase tracking-wider">Talla</th>
                              <th className="text-left p-2 font-black text-slate-400 uppercase tracking-wider">Valor cm</th>
                              <th className="text-left p-2 font-black text-slate-400 uppercase tracking-wider">Tolerancia</th>
                            </tr>
                          </thead>
                          <tbody>
                            {datosExtraidos.medidas.map((m, i) => (
                              <tr key={i} className="border-t border-slate-50">
                                <td className="p-2 font-semibold text-slate-700">{m.punto_medida}</td>
                                <td className="p-2 text-slate-500">{m.talla}</td>
                                <td className="p-2 text-slate-700 font-bold">{m.valor_cm} cm</td>
                                <td className="p-2 text-slate-400">{m.tolerancia ? `±${m.tolerancia}` : "—"}</td>
                              </tr>
                            ))}
                          </tbody>
                        </table>
                      </div>
                    </div>
                  )}

                  {/* Botón guardar */}
                  <Button
                    onClick={handleGuardarDatosExtraidos}
                    disabled={guardandoDatos}
                    className="w-full bg-pink-600 hover:bg-pink-700 text-white font-black gap-2 h-12"
                  >
                    {guardandoDatos ? (
                      <><div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />Guardando...</>
                    ) : (
                      "Guardar datos en la ficha"
                    )}
                  </Button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* ── Sheet: Medidas Cortador ─────────────────────────────── */}
      {medidasUploadOpen && (
        <MedidasUploadSheet
          fichaId={id}
          onClose={() => setMedidasUploadOpen(false)}
          onSuccess={() => {
            qc.invalidateQueries({ queryKey: [FICHA_DETALLE_KEY, id] });
            setMedidasUploadOpen(false);
          }}
        />
      )}
    </div>
  );
}

// ─── MiniStat ─────────────────────────────────────────────────
const MINI_COLORS: Record<string, { bg: string; icon: string; value: string }> = {
  blue:    { bg: "bg-blue-50    border-blue-100",    icon: "text-blue-500",    value: "text-blue-700"    },
  purple:  { bg: "bg-purple-50  border-purple-100",  icon: "text-purple-500",  value: "text-purple-700"  },
  orange:  { bg: "bg-orange-50  border-orange-100",  icon: "text-orange-500",  value: "text-orange-700"  },
  emerald: { bg: "bg-emerald-50 border-emerald-100", icon: "text-emerald-500", value: "text-emerald-700" },
};

function MiniStat({ icon, label, value, color }: {
  icon: React.ReactNode; label: string; value: string; color: string;
}) {
  const c = MINI_COLORS[color] ?? MINI_COLORS.blue;
  return (
    <div className={`rounded-xl border p-4 flex items-center gap-3 ${c.bg}`}>
      <div className={`shrink-0 ${c.icon}`}>{icon}</div>
      <div className="min-w-0">
        <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">{label}</p>
        <p className={`text-sm font-black truncate ${c.value}`}>{value}</p>
      </div>
    </div>
  );
}

// ─── TabPill ──────────────────────────────────────────────────
function TabPill({ active, onClick, icon, label }: {
  active: boolean; onClick: () => void;
  icon: React.ReactNode; label: string;
}) {
  return (
    <button
      onClick={onClick}
      className={`flex items-center gap-2 px-4 py-2 rounded-lg font-bold text-sm transition-all duration-200 active:scale-95 ${
        active ? "bg-pink-600 text-white shadow-md" : "text-gray-500 hover:bg-gray-50"
      }`}
    >
      {icon}{label}
    </button>
  );
}

// ─── InfoCard ─────────────────────────────────────────────────
function InfoCard({ label, value, mono }: { label: string; value: string; mono?: boolean }) {
  return (
    <div className="bg-white rounded-xl border border-slate-100 shadow-sm p-4">
      <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mb-1">{label}</p>
      <p className={`text-sm font-bold text-slate-800 ${mono ? "font-mono" : ""}`}>{value}</p>
    </div>
  );
}

"use client";

import { useState, useMemo, useEffect } from "react";
import { useRouter } from "next/navigation";
import { usePermissions } from "@/lib/hooks/usePermissions";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  FileText, Plus, FileSpreadsheet,
  CheckCircle2, PenLine, AlertTriangle,
  Search, RefreshCw, ChevronLeft, ChevronRight,
  Layers,
} from "lucide-react";
import FichaTecnicasTable from "@/components/admin/fichas-tecnicas/FichaTecnicasTable";
import FichasTecnicasFilters from "@/components/admin/fichas-tecnicas/FichasTecnicasFilters";
import { toast } from "sonner";

interface FichaTecnica {
  id: string;
  version: string;
  estado: string;
  descripcion_detallada: string | null;
  sam_total: number | null;
  costo_estimado: number | null;
  ficha_url: string | null;
  created_at: string;
  productos: { id: string; nombre: string; sku: string; imagen_url: string | null } | null;
  ficha_medidas: { id: string }[];
}

const PAGE_SIZE = 10;

export default function FichasTecnicasPage() {
  const router = useRouter();
  const { can, isLoading: authLoading } = usePermissions();

  const [fichas, setFichas]                       = useState<FichaTecnica[]>([]);
  const [categorias, setCategorias]               = useState<{ id: string; nombre: string }[]>([]);
  const [isLoading, setIsLoading]                 = useState(true);

  // Filtros
  const [searchTerm, setSearchTerm]               = useState("");
  const [estadoFilter, setEstadoFilter]           = useState("");
  const [sortOrder, setSortOrder]                 = useState<"asc" | "desc" | "none">("none");
  const [selectedCategoria, setSelectedCategoria] = useState("all");
  const [statusFilter, setStatusFilter]           = useState<string | null>(null);

  // Paginación
  const [currentPage, setCurrentPage] = useState(0);

  // ── Fetch ──────────────────────────────────────────────────
  const fetchFichas = async () => {
    setIsLoading(true);
    try {
      const query = new URLSearchParams();
      if (estadoFilter) query.append("estado", estadoFilter);
      if (searchTerm)   query.append("busqueda", searchTerm);
      if (selectedCategoria !== "all") query.append("categoria", selectedCategoria);

      const res  = await fetch(`/api/admin/fichas-tecnicas?${query.toString()}`);
      const json = await res.json();

      if (res.ok) {
        setFichas(json.data || []);
        if (json.categorias) setCategorias(json.categorias);
      } else {
        toast.error(json.error || "Error al cargar fichas técnicas");
      }
    } catch (err) {
      console.error(err);
      toast.error("Error de conexión");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    const t = setTimeout(() => fetchFichas(), 300);
    return () => clearTimeout(t);
  }, [searchTerm, estadoFilter, selectedCategoria]);

  useEffect(() => { fetchFichas(); }, []);

  // ── Procesamiento ──────────────────────────────────────────
  const fichasProcesadas = useMemo(() => {
    let result = [...fichas];

    // Filtro desde StatCards
    if (statusFilter === "activo")   result = result.filter((f) => f.estado === "activo");
    if (statusFilter === "borrador") result = result.filter((f) => f.estado === "borrador");
    if (statusFilter === "revision") result = result.filter((f) => f.estado === "revisión");

    // Ordenar por costo estimado
    if (sortOrder === "asc")
      result.sort((a, b) => (a.costo_estimado ?? 0) - (b.costo_estimado ?? 0));
    else if (sortOrder === "desc")
      result.sort((a, b) => (b.costo_estimado ?? 0) - (a.costo_estimado ?? 0));

    return result;
  }, [fichas, statusFilter, sortOrder]);

  const stats = useMemo(() => ({
    total:      fichas.length,
    activas:    fichas.filter((f) => f.estado === "activo").length,
    borradores: fichas.filter((f) => f.estado === "borrador").length,
    revision:   fichas.filter((f) => f.estado === "revisión").length,
  }), [fichas]);

  const totalPages    = Math.ceil(fichasProcesadas.length / PAGE_SIZE);
  const paginatedData = fichasProcesadas.slice(
    currentPage * PAGE_SIZE,
    (currentPage + 1) * PAGE_SIZE
  );

  useEffect(() => {
    setCurrentPage(0);
  }, [searchTerm, estadoFilter, selectedCategoria, sortOrder, statusFilter]);

  // ── Handlers ───────────────────────────────────────────────
  const handleEditFicha = (ficha: FichaTecnica) =>
    router.push(`/admin/Panel-Administrativo/fichas-tecnicas/${ficha.id}`);

  // ── Guards ─────────────────────────────────────────────────
  if (authLoading) return (
    <div className="h-screen flex flex-col items-center justify-center bg-gray-50">
      <div className="w-10 h-10 border-4 border-pink-500 border-t-transparent rounded-full animate-spin mb-4" />
      <p className="text-gray-400 text-sm font-bold uppercase tracking-widest">Verificando permisos...</p>
    </div>
  );

  if (!can("view", "fichas_tecnicas")) return (
    <div className="p-6 text-red-600">No tienes permisos para ver fichas técnicas</div>
  );

  return (
    <div className="p-4 md:p-8 space-y-6 bg-gray-50 min-h-screen">
      <div className="max-w-7xl mx-auto space-y-6">

        {/* ── HEADER ────────────────────────────────────────── */}
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
          <div>
            <h1 className="text-3xl font-bold text-gray-900">Fichas Técnicas</h1>
            <p className="text-gray-500 text-sm">
              Control de fichas técnicas y especificaciones de Modas GUOR
            </p>
          </div>

          <div className="flex items-center gap-3">
            <Button
              variant="outline"
              className="bg-white border-red-200 text-red-700 hover:bg-red-50 font-bold gap-2 h-11 transition-all active:scale-95"
              onClick={() => toast.info("Exportar PDF próximamente")}
            >
              <FileText className="w-5 h-5" />
              <span className="hidden sm:inline">Reporte PDF</span>
            </Button>

            <Button
              variant="outline"
              className="bg-white border-emerald-200 text-emerald-700 hover:bg-emerald-50 font-bold gap-2 h-11 transition-all active:scale-95"
              onClick={() => toast.info("Exportar Excel próximamente")}
            >
              <FileSpreadsheet className="w-5 h-5" />
              <span className="hidden sm:inline">Exportar Excel</span>
            </Button>

            {can("create", "ficha_tecnica") && (
              <Button
                onClick={() => router.push("/admin/Panel-Administrativo/fichas-tecnicas/nueva")}
                className="bg-pink-600 hover:bg-pink-700 shadow-lg font-bold gap-2 h-11 px-6 text-white transition-all active:scale-95"
              >
                <Plus className="w-5 h-5" /> Nueva Ficha
              </Button>
            )}
          </div>
        </div>

        {/* ── STATS INTERACTIVAS ────────────────────────────── */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <StatCard
            title="TOTAL FICHAS"
            value={stats.total}
            icon={<Layers className="w-6 h-6" />}
            isActive={statusFilter === null}
            color="pink"
            onClick={() => setStatusFilter(null)}
          />
          <StatCard
            title="EN LÍNEA / ACTIVAS"
            value={stats.activas}
            icon={<CheckCircle2 className="w-6 h-6" />}
            isActive={statusFilter === "activo"}
            color="emerald"
            onClick={() => setStatusFilter(statusFilter === "activo" ? null : "activo")}
          />
          <StatCard
            title="BORRADORES"
            value={stats.borradores}
            icon={<PenLine className="w-6 h-6" />}
            isActive={statusFilter === "borrador"}
            color="slate"
            onClick={() => setStatusFilter(statusFilter === "borrador" ? null : "borrador")}
          />
          <StatCard
            title="EN REVISIÓN"
            value={stats.revision}
            icon={<AlertTriangle className="w-6 h-6" />}
            isActive={statusFilter === "revision"}
            color="orange"
            onClick={() => setStatusFilter(statusFilter === "revision" ? null : "revision")}
          />
        </div>

        {/* ── BUSCADOR + REFRESH ────────────────────────────── */}
        <div className="flex flex-col md:flex-row gap-4 items-center bg-white p-4 rounded-xl border shadow-sm">
          <div className="relative flex-1 w-full">
            <Search className="absolute left-3 top-3 text-gray-400 w-4 h-4" />
            <Input
              placeholder="Buscar por nombre, SKU o versión..."
              className="pl-10 h-11 border-gray-200 focus:ring-pink-500"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <Button
            variant="outline"
            className="h-11 border-gray-200"
            onClick={fetchFichas}
          >
            <RefreshCw className={`w-4 h-4 ${isLoading ? "animate-spin" : ""}`} />
          </Button>
        </div>

        {/* ── FILTROS AVANZADOS ─────────────────────────────── */}
        <FichasTecnicasFilters
          searchTerm=""
          setSearchTerm={() => {}}
          estadoFilter={estadoFilter}
          setEstadoFilter={setEstadoFilter}
          sortOrder={sortOrder}
          setSortOrder={setSortOrder}
          selectedCategoria={selectedCategoria}
          setSelectedCategoria={setSelectedCategoria}
          categorias={categorias}
          onRefresh={fetchFichas}
        />

        {/* ── TABLA ─────────────────────────────────────────── */}
        {isLoading ? (
          <div className="h-64 flex flex-col items-center justify-center bg-white rounded-xl border animate-pulse">
            <div className="w-10 h-10 border-4 border-pink-500 border-t-transparent rounded-full animate-spin mb-4" />
            <p className="text-gray-400 text-sm font-bold uppercase tracking-widest">
              Sincronizando fichas...
            </p>
          </div>
        ) : (
          <div className="space-y-4">
            <FichaTecnicasTable
              data={paginatedData}
              loading={isLoading}
              onEdit={can("edit", "ficha_tecnica") ? handleEditFicha : undefined}
            />

            {/* ── PAGINACIÓN ──────────────────────────────── */}
            <div className="flex items-center justify-between bg-white p-4 rounded-xl border shadow-sm">
              <p className="text-xs text-gray-500">
                Mostrando{" "}
                <span className="font-bold text-gray-900">{paginatedData.length}</span>
                {" "}de{" "}
                <span className="font-bold text-gray-900">{fichasProcesadas.length}</span>
              </p>
              <div className="flex gap-2">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => setCurrentPage((p) => p - 1)}
                  disabled={currentPage === 0}
                >
                  <ChevronLeft className="w-4 h-4" />
                </Button>
                <div className="px-4 py-1.5 text-xs font-bold bg-gray-50 border rounded-lg flex items-center">
                  Página {currentPage + 1} de {totalPages || 1}
                </div>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => setCurrentPage((p) => p + 1)}
                  disabled={currentPage + 1 >= totalPages}
                >
                  <ChevronRight className="w-4 h-4" />
                </Button>
              </div>
            </div>
          </div>
        )}
      </div>

    </div>
  );
}

// ─── StatCard ─────────────────────────────────────────────────
const STAT_STYLES: Record<string, { active: string; iconActive: string; textActive: string }> = {
  pink:    { active: "border-pink-500    ring-pink-50    bg-white", iconActive: "bg-pink-600    text-white", textActive: "text-pink-600"    },
  emerald: { active: "border-emerald-500 ring-emerald-50 bg-white", iconActive: "bg-emerald-600 text-white", textActive: "text-emerald-600" },
  slate:   { active: "border-slate-500   ring-slate-50   bg-white", iconActive: "bg-slate-600   text-white", textActive: "text-slate-600"   },
  orange:  { active: "border-orange-500  ring-orange-50  bg-white", iconActive: "bg-orange-600  text-white", textActive: "text-orange-600"  },
};

function StatCard({ title, value, icon, isActive, color, onClick }: {
  title: string; value: number; icon: React.ReactNode;
  isActive: boolean; color: string; onClick: () => void;
}) {
  const s = STAT_STYLES[color] ?? STAT_STYLES.pink;
  return (
    <button
      onClick={onClick}
      className={`group p-4 rounded-xl border transition-all duration-300 flex items-center gap-4 cursor-pointer ${
        isActive
          ? `ring-4 shadow-xl scale-[1.02] z-10 ${s.active}`
          : "bg-white border-gray-100 shadow-sm hover:shadow-lg hover:-translate-y-1 active:scale-95"
      }`}
    >
      <div className={`p-3 rounded-lg transition-all duration-300 ${
        isActive ? `${s.iconActive} rotate-3` : "bg-gray-100 text-gray-600 group-hover:rotate-3"
      }`}>
        {icon}
      </div>
      <div className="text-left">
        <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">{title}</p>
        <p className={`text-2xl font-black tracking-tight ${isActive ? s.textActive : "text-gray-800"}`}>
          {value}
        </p>
      </div>
    </button>
  );
}

