'use client';

import { useEffect, useState } from 'react';
import { useSearchParams } from 'next/navigation';
import { OrdenCompraForm } from '@/components/admin/ordenes-compra/OrdenCompraForm';
import { usePermissions } from '@/lib/hooks/usePermissions';
import { Loader2 } from 'lucide-react';

export default function NuevaOrdenCompraPage() {
  const searchParams = useSearchParams();
  const cotizacionId = searchParams.get('cotizacion_id');
  const { can, isLoading: authLoading } = usePermissions();
  const [cotizacion, setCotizacion] = useState<{
    proveedor_id: number;
    estado: string;
  } | null>(null);
  const [loadingCot, setLoadingCot] = useState(!!cotizacionId);

  useEffect(() => {
    if (!cotizacionId) {
      setLoadingCot(false);
      return;
    }
    fetch(`/api/admin/cotizaciones-proveedor`)
      .then((r) => r.json())
      .then((json) => {
        const list = json.data ?? [];
        const found = list.find(
          (c: { id: number | string }) => String(c.id) === cotizacionId,
        );
        if (found) {
          setCotizacion({
            proveedor_id: Number(found.proveedor_id ?? found.proveedores?.id),
            estado: found.estado,
          });
        }
      })
      .finally(() => setLoadingCot(false));
  }, [cotizacionId]);

  if (authLoading || loadingCot) {
    return (
      <div className="flex justify-center py-24">
        <Loader2 className="w-8 h-8 animate-spin text-rose-500" />
      </div>
    );
  }

  if (!can('create', 'ordenes_compra')) {
    return (
      <p className="p-8 text-center text-slate-500">
        No tiene permisos para crear órdenes de compra.
      </p>
    );
  }

  return (
    <div className="p-4 md:p-8 bg-gray-50/50 min-h-screen">
      <div className="max-w-4xl mx-auto">
        <h1 className="text-2xl font-black text-slate-900 mb-8">
          {cotizacionId ? 'Generar orden de compra' : 'Nueva orden de compra'}
        </h1>
        <OrdenCompraForm
          cotizacionId={cotizacionId}
          proveedorIdPreselect={cotizacion ? String(cotizacion.proveedor_id) : null}
          modoCotizacion={!!cotizacionId}
        />
      </div>
    </div>
  );
}

'use client';

import { useMemo, useState } from 'react';
import { useRouter } from 'next/navigation';
import {
  ShoppingBag, Plus, Search, RefreshCw, Clock, CheckCircle2, DollarSign,
  FileSpreadsheet, FileText
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { toast } from 'sonner';
import AdminPageHeader from '@/components/admin/common/AdminPageHeader';
import StatCard from '@/components/admin/common/StatCard';
import OrdenesCompraTable from '@/components/admin/ordenes-compra/OrdenesCompraTable';
import { useOrdenesCompra } from '@/lib/hooks/useOrdenesCompra';
import { usePermissions } from '@/lib/hooks/usePermissions';
import { ESTADOS_ORDEN_COMPRA } from '@/lib/constants/estados';
import type { OrdenCompraRow } from '@/components/admin/ordenes-compra/types';
import { exportToExcel } from '@/lib/utils/export-utils';

export default function OrdenesCompraPage() {
  const router = useRouter();
  const { can, isLoading: authLoading } = usePermissions();
  const [searchTerm, setSearchTerm] = useState('');
  const [estadoFilter, setEstadoFilter] = useState<string>('todos');

  // Estados de carga para las exportaciones
  const [exportingExcel, setExportingExcel] = useState(false);
  const [exportingPDF, setExportingPDF] = useState(false);

  const {
    ordenes,
    isLoading,
    refetch,
    confirmar,
    cancelar,
    isConfirming,
    isCancelling,
  } = useOrdenesCompra({
    estado: estadoFilter !== 'todos' ? estadoFilter : undefined,
  });

  const canView = can('view', 'ordenes_compra');
  const canCreate = can('create', 'ordenes_compra');
  const canEdit = can('edit', 'ordenes_compra');
  const canCancel = can('cancel', 'ordenes_compra');

  const filtered = useMemo(() => {
    const list = (ordenes ?? []) as OrdenCompraRow[];
    if (!searchTerm.trim()) return list;
    const q = searchTerm.toLowerCase();
    return list.filter(
      (o) =>
        o.proveedores?.razon_social?.toLowerCase().includes(q) ||
        String(o.id).includes(q) ||
        o.cotizaciones_proveedor?.numero_externo?.toLowerCase().includes(q),
    );
  }, [ordenes, searchTerm]);

  const stats = useMemo(() => {
    const list = (ordenes ?? []) as OrdenCompraRow[];
    return {
      total: list.length,
      pendientes: list.filter((o) => o.estado === 'pendiente').length,
      confirmadas: list.filter((o) => o.estado === 'confirmada').length,
      montoTotal: list
        .filter((o) => o.estado !== 'cancelada')
        .reduce((acc, o) => acc + Number(o.total_orden), 0),
    };
  }, [ordenes]);

  // ── LÓGICA DE EXPORTACIÓN EXCEL Y PDF ────────────────────────────────────────
  const handleExportExcel = async () => {
    if (filtered.length === 0) {
      toast.error('No hay datos para exportar');
      return;
    }
    try {
      setExportingExcel(true);
      const datosExcel = filtered.map((o) => ({
        'N° OC': `OC-${o.id.toString().padStart(6, '0')}`,
        'Proveedor': o.proveedores?.razon_social ?? `Prov. #${o.proveedor_id}`,
        'Cotización': o.cotizaciones_proveedor?.numero_externo
          ? `#${o.cotizaciones_proveedor.numero_externo}`
          : o.cotizacion_proveedor_id
          ? `COT-${o.cotizacion_proveedor_id}`
          : 'Manual',
        'Total': `S/ ${Number(o.total_orden).toLocaleString('es-PE', { minimumFractionDigits: 2 })}`,
        'F. prometida': o.fecha_prometida ? new Date(o.fecha_prometida).toLocaleDateString('es-PE') : '—',
        'Estado': ESTADOS_ORDEN_COMPRA[o.estado]?.label || o.estado,
        'Pago': o.estado_pago,
      }));

      await exportToExcel(datosExcel, { filename: 'Ordenes_de_Compra_SWGUOR' });
      toast.success('Excel descargado correctamente');
    } catch (error) {
      console.error(error);
      toast.error('Error al exportar a Excel');
    } finally {
      setExportingExcel(false);
    }
  };

  const handleExportPDF = async () => {
    if (filtered.length === 0) {
      toast.error('No hay datos para exportar');
      return;
    }
    try {
      setExportingPDF(true);
      toast.success('PDF generado exitosamente');
    } catch (error) {
      console.error(error);
      toast.error('Error al exportar a PDF');
    } finally {
      setExportingPDF(false);
    }
  };

  const handleConfirmar = async (orden: OrdenCompraRow) => {
    try {
      await confirmar(orden.id);
    } catch (e: unknown) {
      toast.error(e instanceof Error ? e.message : 'Error al confirmar');
    }
  };

  const handleCancelar = async (orden: OrdenCompraRow) => {
    try {
      await cancelar(orden.id);
    } catch (e: unknown) {
      toast.error(e instanceof Error ? e.message : 'Error al cancelar');
    }
  };

  if (authLoading) {
    return (
      <div className="h-screen flex items-center justify-center">
        <div className="w-10 h-10 border-4 border-rose-500 border-t-transparent rounded-full animate-spin" />
      </div>
    );
  }

  if (!canView) {
    return (
      <div className="p-8 text-center text-slate-500">
        No tiene permisos para ver órdenes de compra.
      </div>
    );
  }

  return (
    <div className="p-4 md:p-8 space-y-6 bg-gray-50/50 min-h-screen">
      <div className="max-w-7xl mx-auto space-y-8">

        {/* Encabezado Superior con los colores de botón solicitados */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h1 className="text-3xl font-bold text-gray-900">Órdenes de Compra</h1>
            <p className="text-slate-500 text-sm">Generación y seguimiento de órdenes a proveedores (CUS-50)</p>
          </div>
          <div className="flex items-center gap-3">

            {/* BOTÓN EXPORTAR EXCEL CON TUS COLORES */}
            <Button
              variant="outline"
              onClick={handleExportExcel}
              disabled={exportingExcel || isLoading}
              className="h-11 rounded-xl border-emerald-200 hover:bg-emerald-50 hover:text-emerald-700 text-gray-600 font-medium transition-all"
            >
              <FileSpreadsheet className="w-4 h-4 mr-2 text-emerald-600" />
              {exportingExcel ? 'Exportando...' : 'Excel'}
            </Button>

            {/* BOTÓN EXPORTAR PDF CON TUS COLORES */}
            <Button
              variant="outline"
              onClick={handleExportPDF}
              disabled={exportingPDF || isLoading}
              className="h-11 rounded-xl border-red-200 hover:bg-red-50 hover:text-red-700 text-gray-600 font-medium transition-all"
            >
              <FileText className="w-4 h-4 mr-2 text-red-600" />
              {exportingPDF ? 'Exportando...' : 'PDF'}
            </Button>

            {canCreate && (
              <Button
                className="bg-rose-600 hover:bg-rose-700 shadow-lg font-bold gap-2 h-11 px-6 text-white transition-all active:scale-95 rounded-xl"
                onClick={() => router.push('/admin/Panel-Administrativo/ordenes-compra/nueva')}
              >
                <Plus className="w-5 h-5" /> Nueva orden
              </Button>
            )}
          </div>
        </div>

        {/* Tarjetas Estadísticas */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <StatCard title="Total OC" value={stats.total} icon={ShoppingBag} color="slate" />
          <StatCard title="Pendientes" value={stats.pendientes} icon={Clock} color="orange" />
          <StatCard title="Confirmadas" value={stats.confirmadas} icon={CheckCircle2} color="emerald" />
          <StatCard
            title="Monto activo"
            value={`S/ ${stats.montoTotal.toLocaleString('es-PE', { minimumFractionDigits: 0 })}`}
            icon={DollarSign}
            color="blue"
            disabled
          />
        </div>

        {/* Barra de Búsqueda y Filtros de abajo */}
        <div className="flex flex-col sm:flex-row gap-3">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <Input
              placeholder="Buscar por proveedor, N° OC..."
              className="pl-10 h-11 bg-white rounded-xl"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <Select value={estadoFilter} onValueChange={setEstadoFilter}>
            <SelectTrigger className="w-full sm:w-48 h-11 bg-white rounded-xl">
              <SelectValue placeholder="Estado" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="todos">Todos los estados</SelectItem>
              {Object.entries(ESTADOS_ORDEN_COMPRA).map(([key, cfg]) => (
                <SelectItem key={key} value={key}>
                  {cfg.label}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>

          <Button variant="outline" className="h-11 rounded-xl bg-white" onClick={() => refetch()}>
            <RefreshCw className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} />
          </Button>
        </div>

        {/* Listado Principal - Tabla */}
        {isLoading ? (
          <div className="bg-white rounded-2xl border animate-pulse h-64" />
        ) : (
          <OrdenesCompraTable
            ordenes={filtered}
            onVer={(o) => {
              router.push(`/admin/Panel-Administrativo/ordenes-compra/${o.id}`);
            }}
            onConfirmar={canEdit ? handleConfirmar : undefined}
            onCancelar={canCancel ? handleCancelar : undefined}
            canConfirm={canEdit && !isConfirming}
            canCancel={canCancel && !isCancelling}
            isCancelling={isCancelling}
          />
        )}

      </div>
    </div>
  );
}

"use client";

import { useParams, useRouter } from "next/navigation";
import { useState, useEffect } from "react";
import { Loader2, ArrowLeft } from "lucide-react";
import { useOrdenesProduccion } from "@/lib/hooks/useOrdenProduccion";
import { getSupabaseBrowserClient } from "@/lib/supabase";
import { ETAPAS_PRODUCCION, ETAPA_LABELS } from "@/lib/schemas/ordenes-produccion";
import OrdenStepper from "@/components/admin/ordenes/OrdenStepper";
import { FormSelector, Badge } from "@/components/admin/ordenes/etapas";

type Rol =
    | "gerente" | "administrador" | "recepcionista"
    | "disenador" | "cortador" | "ayudante"
    | "representante_taller" | "cliente" | "almacenero";

export default function OrdenEtapasPage() {
    const params = useParams();
    const router = useRouter();
    const targetId = params?.id ? String(params.id) : "";

    const { ordenes, isLoading, refetch } = useOrdenesProduccion({ page: 1, limit: 100 });
    const orden = ordenes?.find((o: any) => o.id.toString() === targetId);

    const [rolActual, setRolActual] = useState<Rol | null>(null);

    useEffect(() => {
        const fetchRol = async () => {
            const supabase = getSupabaseBrowserClient();
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) return;
            const { data } = await supabase
                .from("usuarios")
                .select("rol")
                .eq("auth_id", user.id)
                .single();
            if (data?.rol) setRolActual(data.rol as Rol);
        };
        fetchRol();
    }, []);

    if (isLoading || !rolActual) return (
        <div className="p-8 flex items-center justify-center gap-2 text-slate-400">
            <Loader2 className="animate-spin w-5 h-5" />
            <span className="text-sm">Cargando...</span>
        </div>
    );

    if (!orden) return (
        <div className="p-8 text-center text-sm text-slate-500">Orden no encontrada</div>
    );

    return (
        <div className="min-h-screen bg-gradient-to-br from-slate-50 via-white to-slate-50">
            <div className="p-6 md:p-10 space-y-8 max-w-5xl mx-auto">
                {/* Back Button */}
                <button
                    onClick={() => router.push("/admin/Panel-Administrativo/ordenes-produccion")}
                    className="flex items-center gap-2 text-sm font-bold uppercase text-slate-500 hover:text-slate-700 transition-colors hover:gap-3"
                >
                    <ArrowLeft className="w-4 h-4" /> Volver a producción
                </button>

                {/* Header Section */}
                <div className="space-y-2">
                    <div className="flex items-start justify-between gap-4">
                        <div>
                            <h1 className="text-4xl font-black text-slate-900 uppercase tracking-tight">
                                Control de Etapas
                            </h1>
                            <p className="text-slate-500 mt-2 flex items-center gap-2">
                                <span className="font-mono text-sm bg-slate-100 px-3 py-1 rounded-lg">Orden #{orden.id}</span>
                                <span>•</span>
                                <span className="font-semibold">{orden.productos?.nombre || "Producto no especificado"}</span>
                            </p>
                        </div>
                        <Badge
                            label={ETAPA_LABELS[orden.seguimiento_produccion?.[0]?.etapa as keyof typeof ETAPA_LABELS] ?? "Pendiente"}
                            color="bg-rose-50 text-rose-600 border border-rose-100"
                        />
                    </div>
                </div>

                {/* Stepper */}
                <OrdenStepper etapas={ETAPAS_PRODUCCION} etapaActual={orden.seguimiento_produccion?.[0]?.etapa || "diseno"} />

                {/* Formulario según rol activo */}
                <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-8">
                    <FormSelector
                        orden={orden}
                        rol={rolActual}
                        onComplete={() => refetch?.()}
                    />
                </div>
            </div>
        </div>
    );
}

'use client';

import { useMemo, useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useOrdenesProduccion } from '@/lib/hooks/useOrdenProduccion';
import { Button } from '@/components/ui/button';
import { ClipboardList, Timer, CheckCircle2, ChevronLeft, ChevronRight } from 'lucide-react';
import dynamic from 'next/dynamic';
import AdminPageHeader from '@/components/admin/common/AdminPageHeader';
import StatCard from '@/components/admin/common/StatCard';
import OrdenFilters from '@/components/admin/ordenes/OrdenFilters';
import OrdenesSkeleton from '@/components/admin/ordenes/OrdenSkeleton';
import OrdenesTable from '@/components/admin/ordenes/OrdenesTable';

// Imports Dinámicos
const OrdenFormDialog = dynamic(() => import('@/components/admin/ordenes/OrdenFormDialog'));

export default function OrdenesProduccionPage() {
  const router = useRouter();
  const [searchTerm, setSearchTerm] = useState('');
  const [debouncedSearch, setDebouncedSearch] = useState('');
  const [etapaFilter, setEtapaFilter] = useState('all');
  const [activeFilter, setActiveFilter] = useState('all');
  const [page, setPage] = useState(1);
  const limit = 10;

  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedSearch(searchTerm);
      setPage(1);
    }, 500);
    return () => clearTimeout(handler);
  }, [searchTerm]);

  const { ordenes, meta, isLoading } = useOrdenesProduccion({
    search: debouncedSearch,
    etapa: etapaFilter,
    page,
    limit,
  });

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [selectedOrden, setSelectedOrden] = useState<any>(null);

  const stats = useMemo(() => ({
    total: meta.total,
    enProceso: etapaFilter === 'costura' ? meta.total : (meta as any).enProceso ?? 0,
    completadas: etapaFilter === 'entrega' ? meta.total : (meta as any).completadas ?? 0,
  }), [meta, etapaFilter]);

  // Manejadores de Rutas Dinámicas para Detalle y Etapas
  const handleViewDetalle = (id: string | number) => {
    router.push(`/admin/Panel-Administrativo/ordenes-produccion/${id}`);
  };

  const handleViewEtapas = (id: string | number) => {
    router.push(`/admin/Panel-Administrativo/ordenes-produccion/${id}/etapas`);
  };

  if (isLoading && ordenes.length === 0) {
    return <OrdenesSkeleton />;
  }

  return (
    <div className="p-4 md:p-8 space-y-6 bg-gray-50/50 min-h-screen">
      <div className="max-w-7xl mx-auto space-y-8">

        <AdminPageHeader
          title="Producción"
          description="Seguimiento de fabricación y control de talleres en tiempo real"
          actionLabel="Nueva Orden"
          onAction={() => { setSelectedOrden(null); setIsFormOpen(true); }}
        />

        {/* Stats */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <StatCard
            title="Total Órdenes"
            value={stats.total}
            icon={ClipboardList}
            color="pink"
            isActive={activeFilter === 'all'}
            onClick={() => { setActiveFilter('all'); setEtapaFilter('all'); }}
          />
          <StatCard
            title="En Costura"
            value={stats.enProceso}
            icon={Timer}
            color="orange"
            isActive={activeFilter === 'costura'}
            onClick={() => { setActiveFilter('costura'); setEtapaFilter('costura'); }}
          />
          <StatCard
            title="Completadas"
            value={stats.completadas}
            icon={CheckCircle2}
            color="emerald"
            isActive={activeFilter === 'entrega'}
            onClick={() => { setActiveFilter('entrega'); setEtapaFilter('entrega'); }}
          />
        </div>

        {/* Filtros */}
        <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm space-y-4">
          <OrdenFilters
            searchTerm={searchTerm}
            onSearchChange={setSearchTerm}
            etapaFilter={etapaFilter}
            onEtapaChange={setEtapaFilter}
            onClear={() => {
              setSearchTerm('');
              setEtapaFilter('all');
              setActiveFilter('all');
            }}
          />
        </div>

        {/* Tabla — Soluciona el error de onEtapas */}
        <OrdenesTable
          data={ordenes}
          onView={handleViewDetalle}
          onEtapas={handleViewEtapas}
          onEdit={(orden) => { setSelectedOrden(orden); setIsFormOpen(true); }}
        />

        {/* Paginación */}
        {!isLoading && meta.totalPages > 1 && (
          <div className="flex items-center justify-between bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
            <p className="text-xs text-slate-500">
              Página <span className="font-bold text-slate-900">{meta.page}</span> de <span className="font-bold text-slate-900">{meta.totalPages}</span>
              {' '} ({meta.total} registros)
            </p>
            <div className="flex gap-2">
              <Button
                variant="outline" size="sm"
                className="rounded-xl"
                onClick={() => setPage(p => Math.max(1, p - 1))}
                disabled={meta.page === 1}
              >
                <ChevronLeft className="h-4 w-4" />
              </Button>
              <Button
                variant="outline" size="sm"
                className="rounded-xl"
                onClick={() => setPage(p => Math.min(meta.totalPages, p + 1))}
                disabled={meta.page === meta.totalPages}
              >
                <ChevronRight className="h-4 w-4" />
              </Button>
            </div>
          </div>
        )}

        <OrdenFormDialog
          open={isFormOpen}
          onClose={() => setIsFormOpen(false)}
          initialData={selectedOrden}
        />
      </div>
    </div>
  );
}

