"use client";

import { useCallback, useEffect, useMemo, useState } from "react";
import { Button } from "@/components/ui/button";
import { Users, UserPlus, Download } from "lucide-react";
import { toast } from "sonner";
import { usePermissions } from "@/lib/hooks/usePermissions";
import type { EstadoPersonal } from "@prisma/client";

import PersonalTable from "@/components/admin/personal/PersonalTable";
import type { PersonalRow } from "@/lib/services/personal-interno.service";
import PersonalFilters, {
  PersonalFiltrosState,
  EMPTY_PERSONAL_FILTERS,
} from "@/components/admin/personal/FiltersPersonal";
import StatsPersonal from "@/components/admin/personal/StatsPersonal";
import PersonalFormModal from "@/components/admin/personal/PersonalFormModal";
import { PersonalSuspendModal, PersonalDetailModal } from "@/components/admin/personal/PersonalModals";
import { exportPersonalToExcel } from "@/lib/utils/export-utils";

export default function PersonalPage() {
  const { can } = usePermissions();

  const [personal, setPersonal] = useState<PersonalRow[]>([]);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState<PersonalFiltrosState>(EMPTY_PERSONAL_FILTERS);

  const [statusFilter, setStatusFilter] = useState<EstadoPersonal | null>(null);

  // Modal states
  const [formTarget, setFormTarget] = useState<PersonalRow | null | undefined>(undefined);
  const [suspenderTarget, setSuspenderTarget] = useState<PersonalRow | null>(null);
  const [detalleTarget, setDetalleTarget] = useState<PersonalRow | null>(null);
  const [isSuspending, setIsSuspending] = useState(false);
  const selectedPersonal = suspenderTarget;
  // ── Fetch ─────────────────────────────────────────────────────
  const fetchPersonal = useCallback(async () => {
    setLoading(true);
    try {
      const res = await fetch("/api/admin/personal");
      const body = await res.json();
      if (!res.ok) throw new Error(body?.error ?? "Error al cargar personal");
      setPersonal(body.data ?? []);
    } catch (e: any) {
      toast.error(e.message ?? "Error inesperado");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchPersonal(); }, [fetchPersonal]);

  const handleExportExcel = async () => {
    try {
      await exportPersonalToExcel(filtered, {
        filename: `Personal_GUOR_${new Date().toISOString().split('T')[0]}`,
      });
    } catch (e: any) {
      toast.error(e.message ?? "Error al exportar");
    }
  };

  // ── Manejo de suspensión ─────────────────────────────────────
  const handleSuspend = async (isSuspendido: boolean) => {
    if (!selectedPersonal) return;

    setIsSuspending(true);
    try {
      const res = await fetch(`/api/admin/personal/${selectedPersonal.id}/estado`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ estado: isSuspendido ? 'suspendido' : 'activo' }),
      });

      if (!res.ok) {
        const body = await res.json();
        throw new Error(body?.error ?? 'Error al cambiar estado');
      }

      toast.success(
        isSuspendido ? 'Colaborador suspendido' : 'Colaborador activado',
      );
      setSuspenderTarget(null);
      fetchPersonal(); // recargar lista
    } catch (error: any) {
      toast.error(error.message ?? 'Error al actualizar estado');
    } finally {
      setIsSuspending(false);
    }
  };

  // ── Filtrado local ────────────────────────────────────────────
  const filtered = useMemo(() => {
    return personal.filter((p) => {

      // Filtro por card de stats (statusFilter)
      if (statusFilter && p.estado !== statusFilter) return false;

      // Filtro por selector de estado en FiltersPersonal
      if (filters.estado && p.estado !== filters.estado) return false;

      // Filtro por cargo
      if (filters.cargo && p.cargo !== filters.cargo) return false;

      // Filtro por búsqueda de texto
      const q = filters.q.toLowerCase().trim();
      if (q) {
        const hayMatch =
          p.nombre_completo?.toLowerCase().includes(q) ||
          p.usuarios?.email?.toLowerCase().includes(q) ||
          p.dni?.toLowerCase().includes(q);
        if (!hayMatch) return false;
      }

      return true;
    });
  }, [personal, filters, statusFilter]);

  // ── Render ────────────────────────────────────────────────────
  return (
    <div className="p-6 space-y-5">

      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="p-2.5 bg-teal-50 rounded-xl border border-teal-100">
            <Users className="w-5 h-5 text-teal-600" />
          </div>
          <div>
            <h1 className="text-xl font-black text-slate-800 tracking-tight">Personal Interno</h1>
            <p className="text-xs text-slate-400 mt-0.5">
              {loading
                ? "Cargando…"
                : `${filtered.length} colaborador${filtered.length !== 1 ? "es" : ""}`}
            </p>
          </div>
        </div>

        <div className="flex items-center gap-2">
          {can("export", "personal") && (
            <Button
              variant="outline"
              size="sm"
              className="gap-2 text-slate-600 border-slate-200 hover:bg-slate-50"
              onClick={handleExportExcel}
              disabled={loading || filtered.length === 0}
            >
              <Download className="w-4 h-4" /> Exportar
            </Button>
          )}
          {can("create", "personal") && (
            <Button
              size="sm"
              onClick={() => setFormTarget(null)}
              className="gap-2 bg-teal-600 hover:bg-teal-700 text-white shadow-sm shadow-teal-100"
            >
              <UserPlus className="w-4 h-4" /> Nuevo Personal
            </Button>
          )}
        </div>
      </div>

      {/* Stats */}
      <StatsPersonal
        personal={personal}
        loading={loading}
        statusFilter={statusFilter}
        onFilterChange={(estado) => setStatusFilter(prev => prev === estado ? null : estado)}
      />

      {/* Filtros */}
      <PersonalFilters
        filters={filters}
        onChange={setFilters}
        totalCount={filtered.length}
      />

      {/* Tabla */}
      <div className="bg-white border border-slate-100 rounded-2xl shadow-sm overflow-hidden">
        <PersonalTable
          data={filtered}
          loading={loading}
          onEdit={can("edit", "personal") ? setFormTarget : undefined}
          onDetalle={setDetalleTarget}
          onSuspender={can("archive", "personal") ? setSuspenderTarget : undefined}
        />
      </div>

      {/* Modales */}
      {formTarget !== undefined && (
        <PersonalFormModal
          personal={formTarget}
          onClose={() => setFormTarget(undefined)}
          onSuccess={fetchPersonal}
        />
      )}

      {suspenderTarget && (
        <PersonalSuspendModal
          personal={suspenderTarget}
          isSuspending={isSuspending}
          onClose={() => setSuspenderTarget(null)}
          onConfirm={() => handleSuspend(suspenderTarget.estado === 'suspendido')}
        />
      )}

      {detalleTarget && (
        <PersonalDetailModal
          personal={detalleTarget}
          onClose={() => setDetalleTarget(null)}
        />
      )}

    </div>
  );
}

"use client";

import { useState, useMemo, useEffect } from "react";
import { usePermissions } from "@/lib/hooks/usePermissions";
import { useProductos } from "@/lib/hooks/useProductos";
import { Button } from "@/components/ui/button";
import {
  ShieldAlert, RefreshCw, Plus, ChevronLeft, ChevronRight,
  FileSpreadsheet, FileText
} from "lucide-react";
import Link from "next/link";
import dynamic from "next/dynamic";
import ProductFilters from "@/components/admin/productos/ProductsFilters";
import ProductosTable from "@/components/admin/productos/ProductsTable";
import { toast } from "sonner";
import { useProductoStockResumen } from "@/lib/hooks/useStockResumen";
import { cn } from "@/lib/utils";
import AdminPageHeader from "@/components/admin/common/AdminPageHeader";
import ProductosStats from "@/components/admin/productos/ProductosStats";
import {
  exportProductosToExcel,
  exportInventarioToPDF
} from "@/lib/utils/export-utils";

const DescontinuarProductoDialog = dynamic(() =>
  import("@/components/admin/productos/DescontinuarProductDialog")
);

export default function ProductosPage() {
  const { can, role, isLoading: authLoading } = usePermissions();
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedCategoria, setSelectedCategoria] = useState("all");
  const [colorFilter, setColorFilter] = useState("");
  const [sizeFilter, setSizeFilter] = useState("");
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc' | 'none'>("none");
  const [currentPage, setCurrentPage] = useState(0);
  const [selectedProducto, setSelectedProducto] = useState<any>(null);
  const [isDeleteOpen, setIsDeleteOpen] = useState(false);
  const [statusFilter, setStatusFilter] = useState<string | null>(null);

  const pageSize = 10;
  const { data: stockResumen } = useProductoStockResumen();

  // Estados de carga para las exportaciones (Sincronizado con órdenes de compra)
  const [exportingExcel, setExportingExcel] = useState(false);
  const [exportingPDF, setExportingPDF] = useState(false);

  const { productos, categorias, isLoading, refetch, toggleEstado, remove } = useProductos({
    categoriaId: selectedCategoria !== "all" ? selectedCategoria : undefined,
    busqueda: searchTerm || undefined,
    color: colorFilter || undefined,
    talla: sizeFilter || undefined,
    sortOrder
  });

  const productosProcesados = useMemo(() => {
    let result = [...productos];

    if (statusFilter === "activo") {
      result = result.filter((p: any) => p.estado === "activo");
    } else if (statusFilter === "bajoStock") {
      result = result.filter((p: any) => p.stock > 0 && p.stock <= 5);
    }

    return result.sort((a: any, b: any) =>
      a.nombre.localeCompare(b.nombre, 'es', { sensitivity: 'base' })
    );
  }, [productos, statusFilter]);

  const stats = useMemo(() => ({
    total: productos.length,
    activos: productos.filter((p: any) => p.estado === "activo").length,
    bajoStock: productos.filter((p: any) => p.stock > 0 && p.stock <= 5).length
  }), [productos]);

  const totalPages = Math.ceil(productosProcesados.length / pageSize);

  const paginatedData = productosProcesados
    .slice(currentPage * pageSize, (currentPage + 1) * pageSize)
    .map((p: any) => ({
      ...p,
      stock: stockResumen?.find((s) => s.producto_id === Number(p.id))?.stock_total_adicional ?? p.stock ?? 0
    }));

  useEffect(() => {
    setCurrentPage(0);
  }, [searchTerm, selectedCategoria, colorFilter, sizeFilter, sortOrder, statusFilter]);

  // ── LÓGICA DE EXPORTACIÓN EXCEL Y PDF ────────────────────────────────────────

  const handleExportExcel = async () => {
    if (productosProcesados.length === 0) {
      toast.error("No hay datos para exportar");
      return;
    }
    const toastId = toast.loading("Generando Excel...");
    try {
      setExportingExcel(true);
      await exportProductosToExcel(
        productosProcesados,
        stockResumen ?? [],
        "Inventario"
      );
      toast.success("Excel descargado correctamente", { id: toastId });
    } catch (e: any) {
      console.error("[Excel export]", e);
      toast.error(e?.message ?? "Error al generar Excel", { id: toastId });
    } finally {
      setExportingExcel(false);
    }
  };

  const handleExportPDF = async () => {
    if (productosProcesados.length === 0) {
      toast.error("No hay datos para exportar");
      return;
    }
    const toastId = toast.loading("Generando PDF...");
    try {
      setExportingPDF(true);
      await exportInventarioToPDF(productosProcesados, categorias, {
        filename: "Inventario",
        title: "REPORTE DE INVENTARIO",
      });
      toast.success("PDF descargado correctamente", { id: toastId });
    } catch (e: any) {
      console.error("[PDF export]", e);
      toast.error(e?.message ?? "Error al generar PDF", { id: toastId });
    } finally {
      setExportingPDF(false);
    }
  };

  if (authLoading) return <LoadingScreen />;
  if (!can("view", "productos")) return <AccessDenied />;

  return (
    <div className="p-4 md:p-8 space-y-6 bg-gray-50/50 min-h-screen">
      <div className="max-w-7xl mx-auto space-y-8">

        <AdminPageHeader
          title="Gestión de Inventario"
          description="Control centralizado de productos, SKU y existencias"
          actionLabel="Nuevo Producto"
          showAction={can("create", "productos")}
          onAction={() => {
            window.location.href = "/admin/Panel-Administrativo/productos/nuevo";
          }}
        >
          <div className="flex items-center gap-3">
            {/* BOTÓN EXPORTAR EXCEL CON TU DISEÑO UNIFICADO */}
            <Button
              variant="outline"
              onClick={handleExportExcel}
              disabled={exportingExcel || isLoading}
              className="h-11 rounded-xl border-emerald-200 hover:bg-emerald-50 hover:text-emerald-700 text-gray-600 font-medium transition-all"
            >
              <FileSpreadsheet className="w-4 h-4 mr-2 text-emerald-600" />
              {exportingExcel ? 'Exportando...' : 'Exportar Excel'}
            </Button>

            {/* BOTÓN EXPORTAR PDF CON TU DISEÑO UNIFICADO */}
            <Button
              variant="outline"
              onClick={handleExportPDF}
              disabled={exportingPDF || isLoading}
              className="h-11 rounded-xl border-red-200 hover:bg-red-50 hover:text-red-700 text-gray-600 font-medium transition-all"
            >
              <FileText className="w-4 h-4 mr-2 text-red-600" />
              {exportingPDF ? 'Exportando...' : 'Exportar PDF'}
            </Button>
          </div>
        </AdminPageHeader>

        <ProductosStats
          stats={stats}
          statusFilter={statusFilter}
          setStatusFilter={setStatusFilter}
          onPageReset={() => setCurrentPage(0)}
        />

        <div className="space-y-4">
          <div className="flex items-center gap-3 bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
            <div className="flex-1">
              <ProductFilters
                searchTerm={searchTerm}
                setSearchTerm={setSearchTerm}
                selectedCategoria={selectedCategoria}
                setSelectedCategoria={setSelectedCategoria}
                colorFilter={colorFilter}
                setColorFilter={setColorFilter}
                sizeFilter={sizeFilter}
                setSizeFilter={setSizeFilter}
                sortOrder={sortOrder}
                setSortOrder={setSortOrder}
                categorias={categorias}
                colors={[]}
              />
            </div>
            <Button variant="outline" className="h-11 w-11 p-0 border-gray-200 rounded-xl hover:bg-gray-50 transition-all active:scale-95" onClick={() => refetch()}>
              <RefreshCw className={cn("w-4 h-4 text-gray-500", isLoading && "animate-spin")} />
            </Button>
          </div>
        </div>

        {isLoading ? (
          <div className="h-64 flex flex-col items-center justify-center bg-white rounded-2xl border border-gray-100 shadow-sm animate-pulse">
            <div className="w-10 h-10 border-4 border-pink-500 border-t-transparent rounded-full animate-spin mb-4" />
            <p className="text-gray-400 text-sm font-bold uppercase tracking-widest">Sincronizando productos...</p>
          </div>
        ) : (
          <div className="space-y-4">
            <ProductosTable
              data={paginatedData}
              categorias={categorias}
              loading={isLoading}
              onEdit={(p) => { setSelectedProducto(p); }}
              onArchive={(p) => { setSelectedProducto(p); setIsDeleteOpen(true); }}
              onStatusChange={(p) => toggleEstado(p.id.toString(), p.estado === 'activo' ? 'inactivo' : 'activo')}
            />

            <div className="flex items-center justify-between bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
              <p className="text-xs text-gray-500">
                Mostrando <span className="font-bold text-gray-900">{paginatedData.length}</span> de <span className="font-bold text-gray-900">{productosProcesados.length}</span>
              </p>
              <div className="flex gap-2">
                <Button variant="outline" size="sm" onClick={() => setCurrentPage(p => p - 1)} disabled={currentPage === 0} className="rounded-xl">
                  <ChevronLeft className="w-4 h-4" />
                </Button>
                <div className="px-4 py-1.5 text-xs font-bold bg-gray-50 border border-gray-100 rounded-xl flex items-center">
                  Página {currentPage + 1} de {totalPages || 1}
                </div>
                <Button variant="outline" size="sm" onClick={() => setCurrentPage(p => p + 1)} disabled={currentPage + 1 >= totalPages} className="rounded-xl">
                  <ChevronRight className="w-4 h-4" />
                </Button>
              </div>
            </div>
          </div>
        )}
      </div>

      {role && (
        <DescontinuarProductoDialog
          isOpen={isDeleteOpen}
          producto={selectedProducto}
          onClose={() => setIsDeleteOpen(false)}
          onSuccess={() => remove(selectedProducto?.id?.toString())}
          rolUsuario={role}
        />
      )}
    </div>
  );
}

function LoadingScreen() {
  return (
    <div className="h-screen flex flex-col items-center justify-center gap-4 bg-gray-50">
      <div className="w-10 h-10 border-4 border-pink-500 border-t-transparent rounded-full animate-spin" />
      <p className="text-sm font-bold text-gray-400 uppercase tracking-widest animate-pulse">Cargando inventario...</p>
    </div>
  );
}

function AccessDenied() {
  return (
    <div className="h-[80vh] flex flex-col items-center justify-center text-center p-6">
      <ShieldAlert className="w-16 h-16 text-red-500 mb-4 opacity-20" />
      <h2 className="text-2xl font-black text-gray-900 uppercase tracking-tight">Acceso Restringido</h2>
      <p className="text-gray-500 max-w-sm mt-2 font-medium">No cuentas con los privilegios necesarios para visualizar el catálogo de productos.</p>
    </div>
  );
}

