"use client";

import { useCallback, useEffect, useMemo, useState } from "react";
import { Button } from "@/components/ui/button";
import { ShieldCheck, UserPlus, Download } from "lucide-react";
import { toast } from "sonner";
import { usePermissions } from "@/lib/hooks/usePermissions";
import type { usuarios } from "@prisma/client";

import UsuariosTable from "@/components/admin/usuarios/UsuarioTable";
import UsuarioFilters, {
  UsuarioFiltrosState,
  EMPTY_FILTERS,
} from "@/components/admin/usuarios/UsuarioFilter";
import StatsUsuarios from "@/components/admin/usuarios/StatsUsuarios";
import UsuarioFormModal from "@/components/admin/usuarios/UsuarioFormModal";
import { UsuarioSuspendModal } from "@/components/admin/usuarios/UsuarioModals";

export default function UsuariosPage() {
  const { can } = usePermissions();

  const [usuarios, setUsuarios] = useState<usuarios[]>([]);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState<UsuarioFiltrosState>(EMPTY_FILTERS);
  const [statusFilter, setStatusFilter] = useState<"activo" | "inactivo" | null>(null);

  // Modal states
  const [formTarget, setFormTarget] = useState<usuarios | null | undefined>(undefined);
  const [suspenderTarget, setSuspenderTarget] = useState<usuarios | null>(null);

  const fetchUsuarios = useCallback(async () => {
    setLoading(true);
    try {
      const res = await fetch("/api/admin/usuarios");
      const body = await res.json();
      if (!res.ok) throw new Error(body?.error ?? "Error al cargar usuarios");
      setUsuarios(body.data ?? []);
    } catch (e: any) {
      toast.error(e.message ?? "Error inesperado");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchUsuarios();
  }, [fetchUsuarios]);

  const filtered = useMemo(() => {
    return usuarios.filter((u) => {
      // 1. Filtro por chips de stats
      if (statusFilter && u.estado !== statusFilter) return false;

      // 2. Filtro por barra de búsqueda y selectores
      if (filters.estado && u.estado !== filters.estado) return false;
      if (filters.rol && u.rol !== filters.rol) return false;

      const q = filters.q.toLowerCase().trim();
      if (q && !u.email?.toLowerCase().includes(q)) return false;

      return true;
    });
  }, [usuarios, filters, statusFilter]);

  return (
    <div className="p-4 md:p-8 space-y-6 bg-gray-50/50 min-h-screen">
      <div className="max-w-7xl mx-auto space-y-8">

        {/* Header */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-indigo-600 rounded-2xl shadow-lg shadow-indigo-200">
              <ShieldCheck className="w-6 h-6 text-white" />
            </div>
            <div>
              <h1 className="text-2xl font-black text-slate-900 tracking-tight">Gestión de Accesos</h1>
              <p className="text-sm text-slate-500 font-medium mt-1">Control de cuentas de usuario y permisos del sistema</p>
            </div>
          </div>

          <div className="flex items-center gap-2 w-full md:w-auto">
            {can("export", "usuarios") && (
              <Button variant="outline" className="h-11 gap-2 border-slate-200 rounded-xl hover:bg-white font-bold text-slate-600 transition-all active:scale-95">
                <Download size={18} /> Exportar
              </Button>
            )}
            {can("create", "usuarios") && (
              <Button 
                onClick={() => setFormTarget(null)}
                className="h-11 gap-2 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-xl shadow-lg shadow-indigo-100 transition-all active:scale-95"
              >
                <UserPlus size={18} /> Nuevo Usuario
              </Button>
            )}
          </div>
        </div>

        {/* Stats */}
        <StatsUsuarios 
          usuarios={usuarios} 
          loading={loading} 
          statusFilter={statusFilter}
          onFilterChange={setStatusFilter}
        />

        {/* Filtros */}
        <UsuarioFilters 
          filters={filters} 
          onChange={setFilters} 
          totalCount={filtered.length}
          onRefresh={fetchUsuarios}
          isRefreshing={loading}
        />

        {/* Tabla */}
        <div className="bg-white border border-slate-100 rounded-[2rem] shadow-sm overflow-hidden">
          <UsuariosTable 
            usuarios={filtered} 
            loading={loading}
            onEdit={can("edit", "usuarios") ? setFormTarget : undefined}
            onSuspender={can("archive", "usuarios") ? setSuspenderTarget : undefined}
          />
        </div>

        {/* Modales */}
        {formTarget !== undefined && (
          <UsuarioFormModal
            usuario={formTarget}
            onClose={() => setFormTarget(undefined)}
            onSuccess={fetchUsuarios}
          />
        )}

        {suspenderTarget && (
          <UsuarioSuspendModal
            usuario={suspenderTarget}
            onClose={() => setSuspenderTarget(null)}
            onSuccess={fetchUsuarios}
          />
        )}

      </div>
    </div>
  );
}

import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';
import { actualizarAlmacenSchema as almacenUpdateSchema } from '@/lib/schemas/almacenes';
import { ZodError } from 'zod';

// Función helper para serializar de forma segura registros con BigInt
function formatearRespuesta(data: any) {
  return JSON.parse(
    JSON.stringify(data, (_, value) =>
      typeof value === 'bigint' ? value.toString() : value
    )
  );
}

export async function GET(request: NextRequest, { params }: { params: Promise<{ id: string }> }) {
  try {
    const { id } = await params;

    const almacen = await prisma.almacenes.findUnique({
      where: { id: BigInt(id) },
    });

    if (!almacen) {
      return NextResponse.json({ error: 'Almacén no encontrado' }, { status: 404 });
    }

    return NextResponse.json(formatearRespuesta(almacen));
  } catch (error) {
    console.error('Error fetching almacen:', error);
    return NextResponse.json({ error: 'Error interno del servidor' }, { status: 500 });
  }
}

export async function PUT(request: NextRequest, { params }: { params: Promise<{ id: string }> }) {
  try {
    const { id } = await params;
    const body = await request.json();
    const validated = almacenUpdateSchema.parse(body);

    const almacen = await prisma.almacenes.update({
      where: { id: BigInt(id) },
      data: {
        nombre: validated.nombre,
        direccion: validated.direccion,
        telefono: validated.telefono,
        email: validated.email,
        descripcion: validated.descripcion,
        unidad_capacidad: validated.unidad_capacidad,
        capacidad_total: validated.capacidad_total,
        estado: String(validated.estado).toLowerCase() === 'true',
        responsable_id: validated.responsable_id ? BigInt(validated.responsable_id) : null,
      },
    });

    return NextResponse.json(formatearRespuesta(almacen));
  } catch (error) {
    if (error instanceof ZodError) {
      return NextResponse.json({ error: 'Datos inválidos', details: error.issues }, { status: 400 });
    }
    console.error('Error updating almacen:', error);
    return NextResponse.json({ error: 'Error interno del servidor' }, { status: 500 });
  }
}

export async function DELETE(request: NextRequest, { params }: { params: Promise<{ id: string }> }) {
  try {
    const { id } = await params;

    await prisma.almacenes.update({
      where: { id: BigInt(id) },
      data: {
        estado: false
      },
    });

    return NextResponse.json({ message: 'Almacén desactivado correctamente' });
  } catch (error) {
    console.error('Error deactivating almacen:', error);
    return NextResponse.json({ error: 'Error interno del servidor' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';
import { crearAlmacenSchema as almacenSchema } from '@/lib/schemas/almacenes';
import { ZodError } from 'zod';
import { requireServerRole } from '@/lib/auth/server';
import { auditoriaService } from '@/lib/services/auditoria.service';
import { RolUsuario } from '@/lib/constants/roles';

const ALMACEN_ROLES: RolUsuario[] = ['administrador', 'gerente', 'almacenero', 'representante_taller'];

export async function GET(request: NextRequest) {
  const auth = await requireServerRole(ALMACEN_ROLES);
  if (!auth.success) return NextResponse.json({ error: auth.error }, { status: auth.status });

  try {
    const almacenes = await prisma.almacenes.findMany({
      orderBy: { nombre: 'asc' },
    });

    return NextResponse.json(
      JSON.parse(
        JSON.stringify(almacenes, (_, value) =>
          typeof value === 'bigint' ? value.toString() : value
        )
      )
    );
  } catch (error) {
    console.error('Error fetching almacenes:', error);
    return NextResponse.json({ error: 'Error interno del servidor' }, { status: 500 });
  }
}

export async function POST(request: NextRequest) {
  const auth = await requireServerRole(ALMACEN_ROLES);
  if (!auth.success) return NextResponse.json({ error: auth.error }, { status: auth.status });

  try {
    const body = await request.json();
    const validated = almacenSchema.parse(body);
    const almacen = await prisma.almacenes.create({
      data: {
        nombre: validated.nombre,
        direccion: validated.direccion,
        telefono: validated.telefono,
        email: validated.email,
        descripcion: validated.descripcion,
        unidad_capacidad: validated.unidad_capacidad || 'unidades',
        capacidad_total: validated.capacidad_total,
        estado: String(validated.estado).toLowerCase() === 'true',
        responsable_id: validated.responsable_id ? BigInt(validated.responsable_id) : null,
      },
    });

    await auditoriaService.registrar({
      usuario_id: BigInt(auth.user.id),
      accion: 'CREAR',
      tabla: 'almacenes',
      registro_id: BigInt(almacen.id),
      datos_despues: almacen,
    });

    return NextResponse.json(
      JSON.parse(
        JSON.stringify(almacen, (_, value) =>
          typeof value === 'bigint' ? value.toString() : value
        )
      ),
      { status: 201 }
    );
  } catch (error) {
    if (error instanceof ZodError) {
      return NextResponse.json({ error: 'Datos inválidos', details: error.issues }, { status: 400 });
    }
    console.error('Error creating almacen:', error);
    return NextResponse.json({ error: 'Error interno del servidor' }, { status: 500 });
  }
}

export const runtime = 'nodejs';

import { NextRequest, NextResponse } from 'next/server';
import { asientoContableBaseSchema as asientosContablesUpdateSchema } from '@/lib/schemas/asientos-contables';
import { asientosContablesService } from '@/lib/services';
import { requireServerRole } from '@/lib/auth/server';
import type { RolUsuario } from '@/lib/constants/roles';
import { ZodError } from 'zod';

import { auditoriaService } from '@/lib/services/auditoria.service';

const ASIENTOS_CONTABLES_ROLES: RolUsuario[] = ['administrador', 'gerente'];

export async function GET(request: NextRequest, { params }: { params: Promise<{ id: string }> }) {
  const auth = await requireServerRole(ASIENTOS_CONTABLES_ROLES);
  if (!auth.success) {
    return NextResponse.json({ error: auth.error }, { status: auth.status });
  }

  try {
    const { id } = await params;
    const data = await asientosContablesService.obtenerPorId(Number(id));
    if (!data) {
      return NextResponse.json({ error: 'Registro no encontrado' }, { status: 404 });
    }
    return NextResponse.json({ success: true, data });
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

export async function PUT(request: NextRequest, { params }: { params: Promise<{ id: string }> }) {
  const auth = await requireServerRole(ASIENTOS_CONTABLES_ROLES);
  if (!auth.success) {
    return NextResponse.json({ error: auth.error }, { status: auth.status });
  }

  try {
    const { id } = await params;
    const body = await request.json();
    const validated = asientosContablesUpdateSchema.parse(body);
    const data = await asientosContablesService.actualizar(Number(id), {
      ...validated,
      pago_id: validated.pago_id != null ? String(validated.pago_id) : null,
    });

    await auditoriaService.registrar({
      usuario_id: BigInt(auth.user.id),
      accion: 'ACTUALIZAR',
      tabla: 'asientos_contables',
      registro_id: BigInt(id),
      datos_despues: data,
    });

    return NextResponse.json({ success: true, data });
  } catch (error) {
    if (error instanceof ZodError) {
      return NextResponse.json({ error: 'Datos inválidos', details: error.issues }, { status: 400 });
    }
    return NextResponse.json({ error: 'Error interno del servidor' }, { status: 500 });
  }
}

export async function DELETE(request: NextRequest, { params }: { params: Promise<{ id: string }> }) {
  const auth = await requireServerRole(ASIENTOS_CONTABLES_ROLES);
  if (!auth.success) {
