export const runtime = 'nodejs';
import { createClient} from '@/lib/supabase/server';
import { NextRequest, NextResponse } from 'next/server';

/**
 * POST /api/admin/migrations/reorganize-categories
 * Reorganiza los productos en las categorías correctas
 * - Fusiona "Blusas y Camisas" con "Blusas"
 * - Fusiona "Pantalones y Jeans" con "Pantalones"
 * - Elimina productos de categorías no deseadas (Accesorios, etc)
 */
export async function POST(request: NextRequest) {
  try {
    const supabase = await createClient();

    // Mapeo de categorías antiguas a nuevas
    const categoryMap = new Map([
      ['Blusas y Camisas', 'Blusas'],      // Fusionar
      ['Pantalones y Jeans', 'Pantalones'], // Fusionar
      ['Accesorios', null],                 // Eliminar productos
      ['Prendas Deportivas', null],         // Eliminar productos
      ['Suéteres', null],                   // Eliminar productos
      ['Conjuntos', null],                  // Eliminar productos
    ]);

    // Obtener todas las categorías
    const { data: categorias } = await supabase
      .from('categorias')
      .select('*')
      .eq('estado', 'activo');

    const categoriasMap = new Map(
      (categorias || []).map((c: any) => [c.nombre, c.id])
    );

    let productosActualizados = 0;
    let productosEliminados = 0;

    // Procesar cada mapeo
    for (const [oldCategory, newCategory] of categoryMap.entries()) {
      const oldCategoryId = categoriasMap.get(oldCategory);
      if (!oldCategoryId) continue;

      if (newCategory) {
        // Fusionar categorías
        const newCategoryId = categoriasMap.get(newCategory);
        if (!newCategoryId) continue;

        console.log(`Fusionando ${oldCategory} (${oldCategoryId}) a ${newCategory} (${newCategoryId})`);

        const { error: updateError } = await supabase
          .from('productos')
          .update({ categoria_id: newCategoryId })
          .eq('categoria_id', oldCategoryId);

        if (updateError) {
          console.error(`Error actualizando ${oldCategory}:`, updateError);
        } else {
          const { count } = await supabase
            .from('productos')
            .select('id', { count: 'exact', head: true })
            .eq('categoria_id', newCategoryId);
          const actualCount = count || 0;
          productosActualizados += actualCount;
          console.log(`✓ ${actualCount} productos en ${newCategory}`);
        }
      } else {
        // Eliminar productos de categorías no deseadas
        console.log(`Eliminando productos de ${oldCategory} (${oldCategoryId})`);

        const { data: productosAEliminar, count } = await supabase
          .from('productos')
          .select('id', { count: 'exact' })
          .eq('categoria_id', oldCategoryId);

        if (count && count > 0) {
          const ids = (productosAEliminar || []).map((p: any) => p.id);
          console.log(`Eliminando ${ids.length} productos...`);

          const { error: deleteError } = await supabase
            .from('productos')
            .delete()
            .in('id', ids);

          if (deleteError) {
            console.error(`Error eliminando productos de ${oldCategory}:`, deleteError);
          } else {
            productosEliminados += ids.length;
            console.log(`✓ ${ids.length} productos eliminados de ${oldCategory}`);
          }
        }
      }
    }

    // Eliminar categorías vacías/inactivas
    const { data: toDelete } = await supabase
      .from('categorias')
      .select('id, nombre')
      .in('id', Array.from(categoriasMap.values()).filter((id: any) => {
        for (const [name] of categoryMap) {
          if (categoriasMap.get(name) === id) return true;
        }
        return false;
      }));

    if (toDelete) {
      for (const cat of toDelete) {
        await supabase
          .from('categorias')
          .update({ estado: 'inactivo' })
          .eq('id', cat.id);
      }
    }

    return NextResponse.json({
      success: true,
      message: 'Reorganización completada',
      productosActualizados,
      productosEliminados,
    });
  } catch (error) {
    console.error('[MIGRATION] Error:', error);
    return NextResponse.json(
      {
        success: false,
        error: 'Error en la migración',
      },
      { status: 500 }
    );
  }
}

export const runtime = 'nodejs';
import { createClient} from '@/lib/supabase/server';
import { NextRequest, NextResponse } from 'next/server';

/**
 * POST /api/admin/migrations/reorganize-products-by-image
 * Reorganiza los 80 productos según su imagen y asigna a la categoría correcta
 * Elimina Buzos y distribuye todo correctamente
 */
export async function POST(request: NextRequest) {
  try {
    const supabase = await createClient();

    // Obtener todas las categorías
    const { data: categorias } = await supabase
      .from('categorias')
      .select('*')
      .eq('estado', 'activo');

    const categoriasMap = new Map(
      (categorias || []).map((c: any) => [c.nombre.toLowerCase(), c.id])
    );

    // Función para mapear imagen a categoría
    const obtenerCategoriaDeImagen = (imagen: string | null): string => {
      if (!imagen) return 'blusas'; // default

      const nombreLower = imagen.toLowerCase();

      // Mapeos específicos basados en nombres de archivo
      if (nombreLower.includes('camiseta') || nombreLower.includes('jersey')) {
        return 'blusas';
      }
      if (nombreLower.includes('casaca') || nombreLower.includes('jacket')) {
        return 'casacas y chaquetas';
      }
      if (nombreLower.includes('falda')) {
        return 'faldas';
      }
      if (
        nombreLower.includes('pantalon') ||
        nombreLower.includes('jean') ||
        nombreLower.includes('jeans') ||
        nombreLower.includes('cargo')
      ) {
        return 'pantalones';
      }
      if (nombreLower.includes('polera') || nombreLower.includes('polo')) {
        return 'polos y poleras';
      }
      if (
        nombreLower.includes('sweater') ||
        nombreLower.includes('sueter') ||
        nombreLower.includes('prenda')
      ) {
        // Los suéteres/buzos van a Blusas ahora que Buzos se elimina
        return 'blusas';
      }
      if (nombreLower.includes('vestido') || nombreLower.includes('vestigo')) {
        return 'vestidos';
      }

      return 'blusas'; // default
    };

    // Obtener todos los productos
    const { data: productos } = await supabase
      .from('productos')
      .select('*');

    if (!productos || productos.length === 0) {
      return NextResponse.json({
        success: true,
        message: 'No hay productos para reorganizar',
      });
    }

    let productosActualizados = 0;
    const errores: any[] = [];

    // Reorganizar cada producto
    for (const producto of productos) {
      const categoriaNombre = obtenerCategoriaDeImagen(producto.imagen);
      const categoriaId = categoriasMap.get(categoriaNombre);

      if (categoriaId) {
        const { error } = await supabase
          .from('productos')
          .update({ categoria_id: categoriaId })
          .eq('id', producto.id);

        if (error) {
          errores.push({ id: producto.id, error: error.message });
        } else {
          productosActualizados++;
        }
      } else {
        errores.push({
          id: producto.id,
          error: `Categoría no encontrada: ${categoriaNombre}`,
        });
      }
    }

    // Marcar Buzos como inactivo
    const { data: buzosCateg } = await supabase
      .from('categorias')
      .select('id')
      .ilike('nombre', '%buzos%');

    if (buzosCateg && buzosCateg.length > 0) {
      for (const buzo of buzosCateg) {
        await supabase
          .from('categorias')
          .update({ estado: 'inactivo' })
          .eq('id', buzo.id);
      }
    }

    // Eliminar productos huérfanos
    const { data: categoriasActivas } = await supabase
      .from('categorias')
      .select('id')
      .eq('estado', 'activo');

    const idsActivos = (categoriasActivas || []).map((c: any) => c.id);

    if (idsActivos.length > 0) {
      const { data: huerfanos } = await supabase
        .from('productos')
        .select('id')
        .not('categoria_id', 'in', `(${idsActivos.join(',')})`);

      if (huerfanos && huerfanos.length > 0) {
        const idsAEliminar = huerfanos.map((p: any) => p.id);
        await supabase
          .from('productos')
          .delete()
          .in('id', idsAEliminar);
      }
    }

    // Obtener estadísticas finales
    const { data: distributionData } = await supabase
      .from('productos')
      .select('categoria_id, id');

    const distribution = new Map();
    (distributionData || []).forEach((p: any) => {
      const count = distribution.get(p.categoria_id) || 0;
      distribution.set(p.categoria_id, count + 1);
    });

    return NextResponse.json({
      success: true,
      message: 'Reorganización completada',
      productosActualizados,
      errores: errores.length > 0 ? errores.slice(0, 5) : [],
      distribution: Object.fromEntries(distribution),
    });
  } catch (error) {
    console.error('[MIGRATION] Error:', error);
    return NextResponse.json(
      {
        success: false,
        error: 'Error en la reorganización',
      },
      { status: 500 }
    );
  }
}

