    await prisma.pagos_taller.delete({ where: { id: BigInt(id) } });
    return NextResponse.json({ success: true });
  } catch (error: any) {
    console.error('[DELETE /pagos-taller/:id]', error);
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

