import { NextResponse } from 'next/server';
import { writeFile, unlink } from 'fs/promises';
import { tmpdir } from 'os';
import { join, extname } from 'path';
import { extraerFichaTecnica } from '@/lib/helpers/ai-extraction';
import { createClient } from '@/lib/supabase/server';

export async function POST(req: Request) {
  let tempFilePath: string | null = null;

  try {
    const formData = await req.formData();
    const file = formData.get('file') as File;

    if (!file) {
      return NextResponse.json({ error: 'No se proporcionó archivo' }, { status: 400 });
    }

    const isImage = file.type.startsWith('image/');
    const isPdf = file.type === 'application/pdf';

    if (!isImage && !isPdf) {
      return NextResponse.json({ error: 'El archivo debe ser una imagen (PNG, JPG, WEBP) o un PDF' }, { status: 400 });
    }

    // 1. Guardar archivo temporalmente para procesamiento local de Gemini
    const buffer = await file.arrayBuffer();
    const fileExt = extname(file.name) || (isPdf ? '.pdf' : '.png');
    tempFilePath = join(tmpdir(), `geometral-${Date.now()}${fileExt}`);
    await writeFile(tempFilePath, Buffer.from(buffer));

    // 2. Extraer información con Gemini
    const extractedData = await extraerFichaTecnica(tempFilePath);

    // 3. Opcional: Subir a Supabase Storage para tener una URL persistente
    const supabase = await createClient();
    const storagePath = `geometrales/${Date.now()}_${file.name.replace(/\s+/g, '_')}`;

    const { data: uploadData, error: uploadError } = await supabase.storage
      .from('documentos')
      .upload(storagePath, Buffer.from(buffer), {
        contentType: file.type,
        upsert: true
      });

    let publicUrl = null;
    if (!uploadError) {
      const { data: { publicUrl: url } } = supabase.storage
        .from('documentos')
        .getPublicUrl(storagePath);
      publicUrl = url;
    }

    return NextResponse.json({
      success: true,
      data: extractedData,
      imagen_geometral_url: publicUrl
    });

  } catch (error: any) {
    console.error('[POST /api/ai/extract-ficha-tecnica]', error);
    return NextResponse.json(
      { error: error.message || 'Error al procesar el archivo' },
      { status: 500 }
    );
  } finally {
    if (tempFilePath) {
      try {
        await unlink(tempFilePath);
      } catch {}
    }
  }
}

import { createClient } from '@supabase/supabase-js';
import { NextResponse } from 'next/server';

const supabaseAdmin = createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.SUPABASE_SERVICE_ROLE_KEY!,
    { auth: { autoRefreshToken: false, persistSession: false } }
);

export async function POST(request: Request) {
    try {
        const { access_token, password } = await request.json();

        if (!access_token || !password) {
            return NextResponse.json(
                { error: 'Token de sesión y nueva contraseña son requeridos' },
                { status: 400 }
            );
        }

        // Validar fortaleza de contraseña (mismas reglas que el frontend)
        const hasUpper = /[A-Z]/.test(password);
        const hasLower = /[a-z]/.test(password);
        const hasNumber = /[0-9]/.test(password);
        const hasSpecial = /[!@#$%^&*(),.?":{}|<>]/.test(password);

        if (!hasUpper || !hasLower || !hasNumber || !hasSpecial || password.length < 8) {
            return NextResponse.json(
                { error: 'La contraseña no cumple los requisitos de seguridad' },
                { status: 400 }
            );
        }

        // Obtener el usuario desde el access_token que generó verifyOtp
        const supabasePublic = createClient(
            process.env.NEXT_PUBLIC_SUPABASE_URL!,
            process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
        );

        const { data: { user }, error: userError } = await supabasePublic.auth.getUser(access_token);

        if (userError || !user) {
            return NextResponse.json(
                { error: 'Sesión de recuperación inválida. Inicia el proceso nuevamente.' },
                { status: 401 }
            );
        }

        // Actualizar contraseña usando el service role (no requiere sesión activa)
        const { error: updateError } = await supabaseAdmin.auth.admin.updateUserById(
            user.id,
            { password }
        );

        if (updateError) {
            throw new Error(`Auth update error: ${updateError.message}`);
        }

        return NextResponse.json(
            { success: true, message: 'Contraseña actualizada correctamente' },
            { status: 200 }
        );

    } catch (error: any) {
        console.error('Error en reset-password:', error);
        return NextResponse.json(
            { error: 'Error al restablecer la contraseña. Intente nuevamente.' },
            { status: 500 }
        );
    }
}

