// ─────────────────────────────────────────────────────────────
// GET: Historial de cotizaciones
// ─────────────────────────────────────────────────────────────
export async function GET(req: Request) {
  try {
    const sesion = await obtenerClienteSesion();
    if ('error' in sesion) {
      return NextResponse.json(
        { success: false, error: sesion.error },
        { status: sesion.status },
