// PATCH: Actualizar datos del perfil del cliente
export async function PATCH(req: Request) {
  try {
    const sesion = await obtenerClienteSesion();
    if ('error' in sesion) {
      return NextResponse.json(
        { success: false, error: sesion.error },
        { status: sesion.error ? 401 : 404 }
      );
    }

    const body = await req.json();

    const CAMPOS_PERMITIDOS = ['nombre_comercial', 'direccion_fiscal'];

    const dataCliente: Record<string, unknown> = {};
    for (const campo of CAMPOS_PERMITIDOS) {
      if (body[campo] !== undefined) dataCliente[campo] = body[campo];
    }

    if (typeof dataCliente.nombre_comercial === 'string') {
      dataCliente.nombre_comercial = dataCliente.nombre_comercial.trim();
    }

    if (typeof dataCliente.direccion_fiscal === 'string') {
      dataCliente.direccion_fiscal = dataCliente.direccion_fiscal.trim();
    }

    if (Object.keys(dataCliente).length === 0) {
      return NextResponse.json(
        { success: false, error: 'No se enviaron campos editables' },
        { status: 400 }
      );
    }

    const clienteActualizado = await prisma.clientes.update({
      where: { id: sesion.cliente_id },
      data:  dataCliente,
    });

    return NextResponse.json({ success: true, data: serializeBigInt(clienteActualizado) });
  } catch (error: any) {
    console.error('[Portal] Error en PATCH perfil:', error);
    if (error.code === 'P2025') {
      return NextResponse.json({ success: false, error: 'Cliente no encontrado' }, { status: 404 });
    }
    return NextResponse.json({ success: false, error: error.message }, { status: 500 });
  }
}

export const runtime = 'nodejs';
import { prisma } from '@/lib/prisma';
import { serializeBigInt } from '@/lib/utils/serialize';
import { NextResponse } from 'next/server';

// Orden canónico de tallas
const ORDEN_TALLAS = ['XS', 'S', 'M', 'L', 'XL', 'XXL', '28', '30', '32', '34'];
const ordenarTallas = (tallas: string[]) =>
  [...tallas].sort((a, b) => {
    const ia = ORDEN_TALLAS.indexOf(a);
    const ib = ORDEN_TALLAS.indexOf(b);
    return (ia === -1 ? 99 : ia) - (ib === -1 ? 99 : ib);
  });

// Normalizar imagen de Supabase Storage
const normalizarImagen = (img: string | null | undefined, bucket = 'productos'): string | null => {
  if (!img) return null;
  if (img.startsWith('http')) return img;
  const cleanPath = img.includes('/') ? img : `${bucket}/${img}`;
  return `${process.env.NEXT_PUBLIC_SUPABASE_URL}/storage/v1/object/public/${cleanPath}`;
};

/**
 * GET /api/portal/productos/[id]
 * Detalle profundo de un producto con variantes activas,
 * mapas de tallas_por_color y colores_por_talla con stock.
 */
export async function GET(
  _req: Request,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const resolvedParams = await params;
    const productoId = BigInt(resolvedParams.id);

    // ── 1. Producto con categoría y variantes activas ──
    const producto = await prisma.productos.findUnique({
      where: { id: productoId },
      include: {
        categorias: { select: { id: true, nombre: true, imagen: true } },
        variantes_producto: {
          where: { estado: 'activo' },
          select: {
            id: true,
            color: true,
            talla: true,
            estado: true,
            stock: true,
            precio_adicional: true,
            sku: true,
            imagen_url: true,
            created_at: true,
          },
          orderBy: [{ talla: 'asc' }, { color: 'asc' }],
        },
      },
    });

    if (!producto) {
      return NextResponse.json(
        { success: false, error: 'Producto no encontrado' },
        { status: 404 }
      );
    }

    if (producto.estado !== 'activo') {
      return NextResponse.json(
        { success: false, error: 'Producto no disponible' },
        { status: 403 }
      );
    }

    // ── 2. Variantes con stock > 0 (para selectores del frontend) ──
    const variantesConStock = producto.variantes_producto.filter(
      (v) => v.stock > 0
    );

    const coloresDisponibles = [
      ...new Set(variantesConStock.map((v) => v.color)),
    ] as string[];

    const tallasDisponibles = ordenarTallas([
      ...new Set(variantesConStock.map((v) => v.talla)),
    ] as string[]);

    // ── 3. Mapa: color → tallas disponibles ──
    const tallasPorColor: Record<string, string[]> = {};
    for (const v of variantesConStock) {
      if (!tallasPorColor[v.color]) tallasPorColor[v.color] = [];
      if (!tallasPorColor[v.color].includes(v.talla)) {
        tallasPorColor[v.color].push(v.talla);
      }
    }
    for (const color in tallasPorColor) {
      tallasPorColor[color] = ordenarTallas(tallasPorColor[color]);
    }

    // ── 4. Mapa: talla → colores disponibles ──
    const coloresPorTalla: Record<string, string[]> = {};
    for (const v of variantesConStock) {
      if (!coloresPorTalla[v.talla]) coloresPorTalla[v.talla] = [];
      if (!coloresPorTalla[v.talla].includes(v.color)) {
        coloresPorTalla[v.talla].push(v.color);
      }
    }

    // ── 5. Stock total disponible ──
    const stockTotal = variantesConStock.reduce(
      (sum, v) => sum + v.stock,
      0
    );

    // ── 6. Construir respuesta ──
    const imagenPrincipal = normalizarImagen(producto.imagen);

    const data = {
      ...serializeBigInt(producto),
      precio: Number(producto.precio),
      imagen: imagenPrincipal,
      stock_disponible: stockTotal,
      categoria: producto.categorias
        ? {
            id: producto.categorias.id,
            nombre: producto.categorias.nombre,
            imagen: normalizarImagen(producto.categorias.imagen, 'categorias'),
          }
        : { id: null, nombre: 'Sin categoría', imagen: null },
      colores_disponibles: coloresDisponibles,
      tallas_disponibles: tallasDisponibles,
      tallas_por_color: tallasPorColor,
      colores_por_talla: coloresPorTalla,
      variantes: producto.variantes_producto.map((v) => ({
        id: v.id,
        color: v.color,
        talla: v.talla,
        estado: v.estado,
        stock: v.stock,
        precio_adicional: Number(v.precio_adicional),
        precio_final: Number(producto.precio) + Number(v.precio_adicional),
        sku: v.sku,
        imagen_url: normalizarImagen(v.imagen_url) || imagenPrincipal,
      })),
    };

    return NextResponse.json({ success: true, data }, {
      headers: {
        'Cache-Control': 'public, s-maxage=60, stale-while-revalidate=300',
      },
    });
  } catch (error: any) {
    console.error('[Portal] Error en GET producto detalle:', error);
    return NextResponse.json(
      { success: false, error: error.message },
      { status: 500 }
    );
  }
}

export const runtime = 'nodejs';
import { prisma } from '@/lib/prisma';
import { serializeBigInt } from '@/lib/utils/serialize';
import { NextResponse } from 'next/server';

/**
 * GET /api/portal/productos
 * Catálogo público del portal B2B — solo productos activos con variantes.
 *
 * Query params:
 *  - categoria_id  → filtro por categoría
 *  - busqueda      → búsqueda por nombre, descripción o SKU
 *  - color         → filtro por ColorPrenda
 *  - talla         → filtro por TallaProductos
 *  - limite        → max resultados (default 50)
 *  - nuevo         → "true" para productos de los últimos N días
 *  - dias          → días atrás para "nuevo" (default 30)
 */
export async function GET(req: Request) {
  try {
    const url = new URL(req.url);
    const categoriaId = url.searchParams.get('categoria_id');
    const busqueda = url.searchParams.get('busqueda');
    const colorFiltro = url.searchParams.get('color');
    const tallaFiltro = url.searchParams.get('talla');
    const limite = Math.min(parseInt(url.searchParams.get('limite') || '50'), 200);
    const soloNuevos = url.searchParams.get('nuevo') === 'true';
    const dias = parseInt(url.searchParams.get('dias') || '30');

    // ── 1. Si hay filtro de color/talla, obtener producto_ids válidos ──
    let productoIdsFiltrados: bigint[] | null = null;

    if (colorFiltro || tallaFiltro) {
      const whereVariantes: Record<string, unknown> = {
        estado: 'activo'
      };
      if (colorFiltro) whereVariantes.color = colorFiltro;
      if (tallaFiltro) whereVariantes.talla = tallaFiltro;

      const variantes = await prisma.variantes_producto.findMany({
        where: whereVariantes,
        select: { producto_id: true },
      });

      productoIdsFiltrados = [
        ...new Set(variantes.map((v) => v.producto_id)),
      ];

      if (productoIdsFiltrados.length === 0) {
        return NextResponse.json({ success: true, data: [], count: 0 });
      }
    }

    // ── 2. Query principal ──
    const whereProductos: Record<string, unknown> = {
      estado: 'activo',
    };

    if (categoriaId) whereProductos.categoria_id = BigInt(categoriaId);
    if (productoIdsFiltrados)
      whereProductos.id = { in: productoIdsFiltrados };

    if (soloNuevos) {
      const fechaLimite = new Date();
      fechaLimite.setDate(fechaLimite.getDate() - dias);
      whereProductos.created_at = { gte: fechaLimite };
    }

    // Búsqueda por texto (nombre, descripción, SKU)
    if (busqueda) {
      whereProductos.OR = [
        { nombre: { contains: busqueda, mode: 'insensitive' } },
        { descripcion: { contains: busqueda, mode: 'insensitive' } },
        { sku: { contains: busqueda, mode: 'insensitive' } },
      ];
    }

    const productos = await prisma.productos.findMany({
      where: whereProductos,
      include: {
        categorias: { select: { id: true, nombre: true, imagen: true } },
        variantes_producto: {
          where: { estado: 'activo', stock: { gt: 0 } },
          select: {
            id: true,
            color: true,
            talla: true,
            estado: true,
            stock: true,
            precio_adicional: true,
            sku: true,
            imagen_url: true,
          },
          orderBy: [{ talla: 'asc' }, { color: 'asc' }],
        },
      },
      orderBy: { created_at: 'desc' },
      take: limite,
    });

    // ── 3. Transformar con lógica de variantes ──
    const normalizarImagen = (
      img: string | null | undefined
    ): string | null => {
      if (!img) return null;
      if (img.startsWith('http')) return img;
      return `${process.env.NEXT_PUBLIC_SUPABASE_URL}/storage/v1/object/public/productos/${img}`;
    };

    const ORDEN_TALLAS = ['XS', 'S', 'M', 'L', 'XL', 'XXL', '28', '30', '32', '34'];
    const ordenarTallas = (tallas: string[]) =>
      [...tallas].sort(
        (a, b) => ORDEN_TALLAS.indexOf(a) - ORDEN_TALLAS.indexOf(b)
      );

    const ahora = new Date();
    const limiteNuevo = new Date();
    limiteNuevo.setDate(limiteNuevo.getDate() - 30);

    const data = productos.map((producto) => {
      const variantes = producto.variantes_producto;

      const coloresDisponibles = [
        ...new Set(variantes.map((v) => v.color)),
      ] as string[];

      const tallasDisponibles = ordenarTallas([
        ...new Set(variantes.map((v) => v.talla)),
      ] as string[]);

      // Tallas por color
      const tallasPorColor: Record<string, string[]> = {};
      for (const v of variantes) {
        if (!tallasPorColor[v.color]) tallasPorColor[v.color] = [];
        if (!tallasPorColor[v.color].includes(v.talla)) {
          tallasPorColor[v.color].push(v.talla);
        }
      }
      for (const color in tallasPorColor) {
        tallasPorColor[color] = ordenarTallas(tallasPorColor[color]);
      }

      // Colores por talla
      const coloresPorTalla: Record<string, string[]> = {};
      for (const v of variantes) {
        if (!coloresPorTalla[v.talla]) coloresPorTalla[v.talla] = [];
        if (!coloresPorTalla[v.talla].includes(v.color)) {
          coloresPorTalla[v.talla].push(v.color);
        }
      }

      const esNuevo = producto.created_at >= limiteNuevo;

      return {
        ...serializeBigInt(producto),
        precio: Number(producto.precio),
        imagen: normalizarImagen(producto.imagen),
        categoria: producto.categorias
          ? {
              id: producto.categorias.id,
              nombre: producto.categorias.nombre,
              imagen: normalizarImagen(producto.categorias.imagen),
            }
          : { id: null, nombre: 'Sin categoría', imagen: null },
        es_nuevo: esNuevo,
        colores_disponibles: coloresDisponibles,
        tallas_disponibles: tallasDisponibles,
        tallas_por_color: tallasPorColor,
        colores_por_talla: coloresPorTalla,
        variantes: variantes.map((v) => ({
          id: v.id,
          color: v.color,
          talla: v.talla,
          stock: v.stock,
          precio_adicional: Number(v.precio_adicional),
          sku: v.sku,
          imagen_url: v.imagen_url ? normalizarImagen(v.imagen_url) : null,
        })),
      };
    });

    return NextResponse.json({
      success: true,
      data,
      count: data.length,
      filtros_aplicados: {
        categoria_id: categoriaId ? parseInt(categoriaId) : null,
        color: colorFiltro,
        talla: tallaFiltro,
        busqueda: busqueda || null,
        nuevo: soloNuevos,
        dias: soloNuevos ? dias : null,
      },
    });
  } catch (error: any) {
    console.error('[Portal] Error en GET productos:', error);
    return NextResponse.json(
      { success: false, error: error.message, data: [] },
      { status: 500 }
    );
  }
}

import { NextResponse } from 'next/server';
import { prisma, prismaAvailable } from '@/lib/prisma';
import { serializeBigInt } from '@/lib/utils/serialize';

export async function GET() {
  // Check DATABASE_URL first
  if (!process.env.DATABASE_URL) {
    console.error('[testimonials] DATABASE_URL is not set');
    return NextResponse.json(
      { error: 'Database not configured' },
      { status: 503 }
    );
  }

  if (!prismaAvailable) {
    console.error('[testimonials] Prisma client unavailable');
    return NextResponse.json(
      { error: 'Database client not initialized' },
      { status: 503 }
    );
  }

  try {
    const testimonials = await prisma.feedback_cliente.findMany({
      where: {
        estado: 'revisado',
        puntuacion: { gte: 4 },
        comentarios: { not: null },
      },
      include: {
        clientes: {
          select: {
            nombre_comercial: true,
          },
        },
      },
      orderBy: {
        created_at: 'desc',
      },
      take: 20,
    });

    return NextResponse.json(serializeBigInt(testimonials), {
      headers: {
        'Cache-Control': 'public, s-maxage=3600, stale-while-revalidate=86400',
      },
    });
  } catch (error: any) {
    console.error('[testimonials] Query error:', {
      message: error?.message,
      code: error?.code,
      clientVersion: error?.clientVersion,
    });
    console.error('[testimonials] Full error:', error);
    return NextResponse.json(
      { error: 'Failed to fetch testimonials', details: error?.message },
      { status: 500 }
    );
  }
}

