        {/* Fields */}
        <div className="p-6 space-y-3">
          {fields.map(f => (
            <div key={f.label} className="flex justify-between items-center py-2 border-b last:border-0">
              <span className="text-xs font-semibold text-gray-500 uppercase tracking-wider">{f.label}</span>
              <span className="text-sm font-medium text-gray-900">{f.value || '—'}</span>
            </div>
          ))}
          {typeof almacen._count?.insumos === 'number' && (
            <div className="flex justify-between items-center py-2 border-b last:border-0">
              <span className="text-xs font-semibold text-gray-500 uppercase tracking-wider flex items-center gap-1">
                <Package className="w-3 h-3" /> Insumos
              </span>
              <span className="text-sm font-medium text-gray-900">{almacen._count.insumos}</span>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

'use client';

import { format } from 'date-fns';
import { es } from 'date-fns/locale';
import { Eye, User, Database } from 'lucide-react';
import { 
  Table, TableBody, TableCell, TableHead, TableHeader, TableRow 
} from "@/components/ui/table";
import { Button } from '@/components/ui/button';
import { Badge } from "@/components/ui/badge";
import { AuditLog, PaginationData } from './types';

interface AuditTableProps {
  logs: AuditLog[];
  loading: boolean;
  pagination: { page: number; totalPages: number };
  onViewDetail: (log: AuditLog) => void;
  onPageChange: (page: number) => void;
}

export function AuditTable({
  logs,
  loading,
  pagination,
  onViewDetail,
  onPageChange
}: AuditTableProps) {
  const getActionBadge = (action: string) => {
    switch (action) {
      case 'CREAR':      return <Badge className="bg-emerald-100 text-emerald-700 border-emerald-200">CREAR</Badge>;
      case 'ACTUALIZAR': return <Badge className="bg-blue-100 text-blue-700 border-blue-200">ACTUALIZAR</Badge>;
      case 'ELIMINAR':   return <Badge className="bg-rose-100 text-rose-700 border-rose-200">ELIMINAR</Badge>;
      default:           return <Badge variant="outline" className="text-slate-500">{action}</Badge>;
    }
  };

  return (
    <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
      <Table>
        <TableHeader className="bg-slate-50/50">
          <TableRow>
            <TableHead className="w-[180px]">Fecha y Hora</TableHead>
            <TableHead>Usuario</TableHead>
            <TableHead>Acción</TableHead>
            <TableHead>Módulo / Tabla</TableHead>
            <TableHead>ID Registro</TableHead>
            <TableHead className="text-right">Detalle</TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          {loading ? (
            <TableRow>
              <TableCell colSpan={6} className="h-40 text-center text-slate-400">
                Cargando registros...
              </TableCell>
            </TableRow>
          ) : logs.length === 0 ? (
            <TableRow>
              <TableCell colSpan={6} className="h-40 text-center text-slate-400">
                No se encontraron registros de auditoría.
              </TableCell>
            </TableRow>
          ) : (
            logs.map((log) => (
              <TableRow key={log.id} className="hover:bg-slate-50/50 transition-colors">
                <TableCell className="font-medium text-slate-600">
                  <div className="flex flex-col">
                    <span className="text-xs font-bold text-slate-900">
                      {format(new Date(log.created_at), 'dd MMM, yyyy', { locale: es })}
                    </span>
                    <span className="text-[10px] text-slate-400">
                      {format(new Date(log.created_at), 'HH:mm:ss')}
                    </span>
                  </div>
                </TableCell>
                <TableCell>
                  <div className="flex items-center gap-2">
                    <div className="w-8 h-8 rounded-lg bg-rose-50 flex items-center justify-center">
                      <User className="w-4 h-4 text-rose-500" />
                    </div>
                    <div className="flex flex-col">
                      <span className="text-xs font-bold text-slate-900">
                        {log.usuarios?.personal_interno?.[0]?.nombre_completo ?? 'Sistema'}
                      </span>
                      <span className="text-[10px] text-slate-400 truncate max-w-[150px]">
                        {log.usuarios?.email ?? 'N/A'}
                      </span>
                    </div>
                  </div>
                </TableCell>
                <TableCell>{getActionBadge(log.accion)}</TableCell>
                <TableCell>
                  <div className="flex items-center gap-1.5">
                    <Database className="w-3 h-3 text-slate-400" />
                    <span className="text-xs font-semibold text-slate-600 uppercase tracking-tight">
                      {log.tabla}
                    </span>
                  </div>
                </TableCell>
                <TableCell>
                  <code className="text-[10px] bg-slate-100 px-1.5 py-0.5 rounded text-slate-500 font-mono">
                    #{log.registro_id}
                  </code>
                </TableCell>
                <TableCell className="text-right">
                  <Button 
                    variant="ghost" 
                    size="sm" 
                    className="h-8 w-8 p-0 rounded-lg"
                    onClick={() => onViewDetail(log)}
                  >
                    <Eye className="w-4 h-4 text-slate-400" />
                  </Button>
                </TableCell>
              </TableRow>
            ))
          )}
        </TableBody>
      </Table>

      <div className="p-4 border-t border-slate-100 flex items-center justify-between bg-slate-50/30">
        <span className="text-xs text-slate-400 font-medium">
          Página {pagination.page} de {pagination.totalPages}
        </span>
        <div className="flex gap-2">
          <Button 
            variant="outline" 
            size="sm" 
            disabled={pagination.page <= 1}
            onClick={() => onPageChange(pagination.page - 1)}
            className="h-8 rounded-lg"
          >
            Anterior
          </Button>
          <Button 
            variant="outline" 
            size="sm" 
            disabled={pagination.page >= pagination.totalPages}
            onClick={() => onPageChange(pagination.page + 1)}
            className="h-8 rounded-lg"
          >
            Siguiente
          </Button>
        </div>
      </div>
    </div>
  );
}

export interface AuditLog {
  id: string;
  usuario_id: string | null;
  accion: 'CREAR' | 'ACTUALIZAR' | 'ELIMINAR' | 'LOGIN' | 'LOGOUT' | 'EXPORTAR' | 'IMPORTAR';
  tabla: string;
  registro_id: string;
  datos_antes: any;
  datos_despues: any;
  ip_address: string | null;
  user_agent: string | null;
  created_at: string;
  usuarios: {
    email: string;
    personal_interno?: { nombre_completo: string }[];
  } | null;
}

export interface PaginationData {
  page: number;
  totalPages: number;
  total: number;
  limit: number;
}

'use client';

// GUOR PRO Modal Design — Categorías
import { useState, useEffect } from 'react';
import { X, Loader2 } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import type { Categoria } from '@/lib/services/categorias.service';

interface CategoriaForm {
  nombre: string;
  descripcion: string;
  activo: boolean;
}

interface Props {
  categoria: Categoria | null;
  isSaving: boolean;
  onClose: () => void;
  onSave: (data: CategoriaForm) => void;
}

const EMPTY: CategoriaForm = { nombre: '', descripcion: '', activo: true };

export default function CategoriaFormModal({ categoria, isSaving, onClose, onSave }: Props) {
  const [form, setForm] = useState<CategoriaForm>(EMPTY);
  const [errors, setErrors] = useState<Record<string, string>>({});

  useEffect(() => {
    if (categoria) {
      setForm({
        nombre: categoria.nombre ?? '',
        descripcion: categoria.descripcion ?? '',
        activo: categoria.activo ?? true,
      });
    } else {
      setForm(EMPTY);
    }
    setErrors({});
  }, [categoria]);

  const handleChange = (field: keyof CategoriaForm, value: string | boolean) => {
    setForm(prev => ({ ...prev, [field]: value }));
    setErrors(prev => { const c = { ...prev }; delete c[field]; return c; });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.nombre.trim()) {
      setErrors({ nombre: 'El nombre de la categoría es requerido' });
      return;
    }
    onSave(form);
  };

  return (
    <div
      className="fixed inset-0 bg-black/40 backdrop-blur-sm z-50 flex items-center justify-center p-4"
      onClick={onClose}
    >
      <div
        className="bg-white rounded-2xl shadow-2xl w-full max-w-lg max-h-[90vh] overflow-y-auto"
        onClick={e => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex items-center justify-between p-6 border-b">
          <div>
            <h2 className="text-xl font-bold text-gray-900">
              {categoria ? 'Editar Categoría' : 'Nueva Categoría'}
            </h2>
            <p className="text-sm text-gray-500 mt-0.5">
              {categoria ? 'Ajusta los detalles de la línea de productos' : 'Define una nueva línea para tu catálogo'}
            </p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-xl transition-colors">
            <X className="w-5 h-5 text-gray-400" />
          </button>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <div>
            <label className="block text-xs font-semibold text-gray-600 mb-1.5">Nombre de la Línea *</label>
            <Input
              value={form.nombre}
              onChange={e => handleChange('nombre', e.target.value)}
              placeholder="Ej. Vestidos de Gala"
              className={errors.nombre ? 'border-red-400 focus:ring-red-400' : ''}
            />
            {errors.nombre && <p className="text-xs text-red-500 mt-1">{errors.nombre}</p>}
          </div>

          <div>
            <label className="block text-xs font-semibold text-gray-600 mb-1.5">Descripción</label>
            <Textarea
              value={form.descripcion}
              onChange={e => handleChange('descripcion', e.target.value)}
              placeholder="¿Qué tipo de prendas incluye esta categoría?"
              className="resize-none"
              rows={3}
            />
          </div>

          <div className="flex items-center justify-between p-4 bg-gray-50 rounded-xl border border-gray-100">
            <div>
              <p className="text-xs font-semibold text-gray-600 uppercase tracking-wider">Estado Actual</p>
              <p className="text-sm font-bold text-gray-900 mt-0.5">
                {form.activo ? 'Visible en Catálogo' : 'Oculta al Público'}
              </p>
            </div>
            <button
              type="button"
              onClick={() => handleChange('activo', !form.activo)}
              className={`relative w-12 h-6 rounded-full transition-colors ${form.activo ? 'bg-rose-600' : 'bg-gray-300'
                }`}
            >
              <span
                className={`absolute top-0.5 left-0.5 w-5 h-5 bg-white rounded-full shadow transition-transform ${form.activo ? 'translate-x-6' : 'translate-x-0'
                  }`}
              />
            </button>
          </div>

          <div className="flex gap-3 pt-4 border-t">
            <Button type="button" variant="outline" onClick={onClose} className="flex-1 h-11" disabled={isSaving}>
              Cancelar
            </Button>
            <Button type="submit" className="flex-1 h-11 bg-rose-600 hover:bg-rose-700 text-white" disabled={isSaving}>
              {isSaving
                ? <><Loader2 className="w-4 h-4 animate-spin mr-2" />Guardando...</>
                : categoria ? 'Actualizar' : 'Crear Categoría'
              }
            </Button>
          </div>
        </form>
      </div>
    </div>
  );
}

