                  sig === "cancelado"
                    ? "bg-red-50 text-red-600 border-red-200 hover:bg-red-100"
                    : "bg-pink-50 text-pink-600 border-pink-200 hover:bg-pink-100"
                }`}
              >
                {isLoading
                  ? <Loader2 size={12} className="animate-spin" />
                  : <ChevronRight size={12} />
                }
