'use client';

import { useState } from 'react';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Star, MessageSquare, Edit } from 'lucide-react';

interface Feedback {
  id: number;
  cliente_id: number;
  pedido_id?: number;
  puntuacion: number;
  comentario?: string;
  tipo_feedback: 'positivo' | 'negativo' | 'sugerencia';
  created_at: string;
  clientes: { nombre: string; email: string };
  pedidos?: { estado: string };
}

interface FeedbackClienteTableProps {
  data: Feedback[];
  onEdit?: (feedback: Feedback) => void;
}

export default function FeedbackClienteTable({ data, onEdit }: FeedbackClienteTableProps) {
  const [search, setSearch] = useState('');
  const [tipoFilter, setTipoFilter] = useState<string>('');

  const filteredData = data.filter(item => {
    const matchesSearch = item.clientes.nombre.toLowerCase().includes(search.toLowerCase()) ||
                         item.comentario?.toLowerCase().includes(search.toLowerCase());
    const matchesTipo = !tipoFilter || item.tipo_feedback === tipoFilter;
    return matchesSearch && matchesTipo;
  });

  const renderStars = (rating: number) => {
    return Array.from({ length: 5 }, (_, i) => (
      <Star
        key={i}
        className={`w-4 h-4 ${i < rating ? 'fill-yellow-400 text-yellow-400' : 'text-gray-300'}`}
      />
    ));
  };

  const getTipoBadge = (tipo: string) => {
    const variants = {
      positivo: 'bg-green-100 text-green-800',
      negativo: 'bg-red-100 text-red-800',
      sugerencia: 'bg-blue-100 text-blue-800',
    };
    return <Badge className={variants[tipo as keyof typeof variants] || 'bg-gray-100'}>{tipo}</Badge>;
  };

  return (
    <div className="space-y-4">
      <div className="flex gap-4">
        <Input
          placeholder="Buscar por cliente o comentario..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="max-w-sm"
        />
        <Select value={tipoFilter} onValueChange={setTipoFilter}>
          <SelectTrigger className="w-48">
            <SelectValue placeholder="Filtrar por tipo" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="">Todos</SelectItem>
            <SelectItem value="positivo">Positivo</SelectItem>
            <SelectItem value="negativo">Negativo</SelectItem>
            <SelectItem value="sugerencia">Sugerencia</SelectItem>
          </SelectContent>
        </Select>
      </div>

      <div className="border rounded-lg">
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>Cliente</TableHead>
              <TableHead>Pedido</TableHead>
              <TableHead>Calificación</TableHead>
              <TableHead>Tipo</TableHead>
              <TableHead>Comentario</TableHead>
              <TableHead>Fecha</TableHead>
              <TableHead>Acciones</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {filteredData.map((feedback) => (
              <TableRow key={feedback.id}>
                <TableCell>
                  <div>
                    <div className="font-medium">{feedback.clientes.nombre}</div>
                    <div className="text-sm text-muted-foreground">{feedback.clientes.email}</div>
                  </div>
                </TableCell>
                <TableCell>
                  {feedback.pedido_id ? (
                    <div>
                      <div>#{feedback.pedido_id}</div>
                      <Badge variant="outline">{feedback.pedidos?.estado}</Badge>
                    </div>
                  ) : (
                    <span className="text-muted-foreground">Sin pedido</span>
                  )}
                </TableCell>
                <TableCell>
                  <div className="flex items-center gap-1">
                    {renderStars(feedback.puntuacion)}
                    <span className="ml-2 text-sm">({feedback.puntuacion}/5)</span>
                  </div>
                </TableCell>
                <TableCell>{getTipoBadge(feedback.tipo_feedback)}</TableCell>
                <TableCell>
                  {feedback.comentario ? (
                    <div className="max-w-xs truncate" title={feedback.comentario}>
                      {feedback.comentario}
                    </div>
                  ) : (
                    <span className="text-muted-foreground">Sin comentario</span>
                  )}
                </TableCell>
                <TableCell>
                  {new Date(feedback.created_at).toLocaleDateString()}
                </TableCell>
                <TableCell>
                  {onEdit && (
                    <Button variant="ghost" size="sm" onClick={() => onEdit(feedback)}>
                      <Edit className="w-4 h-4" />
                    </Button>
                  )}
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </div>

      {filteredData.length === 0 && (
        <div className="text-center py-8 text-muted-foreground">
          No se encontraron feedbacks
        </div>
      )}
    </div>
  );
}

"use client";

import { useFichaDetalle } from "@/lib/hooks/useFichaDetalle";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { Package2, Trash2, Layers } from "lucide-react";
import { Badge } from "@/components/ui/badge";

interface Props {
  fichaId: string;
  canEdit: boolean;
}

export default function DetallesMateriales({ fichaId, canEdit }: Props) {
  const { detalles, isLoading, remove, isDeleting } = useFichaDetalle(fichaId);

  if (isLoading) return (
    <div className="space-y-3">
      {Array.from({ length: 4 }).map((_, i) => (
        <Skeleton key={i} className="h-16 w-full rounded-xl" />
      ))}
    </div>
  );

  // Calcular costo total
  const costoTotal = (detalles as any[]).reduce((total, d) => {
    const precio    = Number(d.material?.precio_unitario ?? d.insumo?.precio_unitario ?? 0);
    const cantidad  = Number(d.cantidad_consumo);
    const desperdicio = Number(d.porcentaje_desperdicio ?? 0) / 100;
    return total + precio * cantidad * (1 + desperdicio);
  }, 0);

  return (
    <div className="space-y-4">

      {/* Header con costo total */}
      <div className="flex items-center justify-between">
        <p className="text-sm text-slate-500 font-semibold">
          {detalles.length} {detalles.length === 1 ? "item" : "items"} registrados
        </p>
        {detalles.length > 0 && (
          <div className="flex items-center gap-2 bg-emerald-50 border border-emerald-100 rounded-lg px-3 py-1.5">
            <span className="text-[10px] font-black uppercase tracking-widest text-emerald-600">Costo total estimado</span>
            <span className="text-sm font-black text-emerald-700">S/ {costoTotal.toFixed(2)}</span>
          </div>
        )}
      </div>

      {/* Sin datos */}
      {detalles.length === 0 && (
        <div className="bg-white rounded-xl border border-slate-100 shadow-sm py-16 flex flex-col items-center gap-2">
          <Layers className="w-10 h-10 text-slate-200" />
          <p className="text-xs text-slate-400 font-semibold uppercase tracking-widest">
            No hay materiales ni insumos registrados
          </p>
        </div>
      )}

      {/* Tabla */}
      {detalles.length > 0 && (
        <div className="bg-white rounded-xl border border-slate-100 shadow-sm overflow-hidden">
          <table className="w-full text-sm">
            <thead>
              <tr className="border-b border-slate-100 bg-slate-50">
                {["Ítem", "Tipo", "Cantidad", "% Desperdicio", "Precio unit.", "Subtotal", canEdit ? "" : null]
                  .filter(Boolean)
                  .map((h, i) => (
                    <th key={i} className="px-4 py-3 text-left text-[10px] font-black uppercase tracking-widest text-slate-400">
                      {h}
                    </th>
                  ))}
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {(detalles as any[]).map((d, idx) => {
                const esM       = !!d.material;
                const item      = d.material ?? d.insumo;
                const precio    = Number(item?.precio_unitario ?? 0);
                const cantidad  = Number(d.cantidad_consumo);
                const desp      = Number(d.porcentaje_desperdicio ?? 0) / 100;
                const subtotal  = precio * cantidad * (1 + desp);

                return (
                  <tr key={d.id} className={idx % 2 === 0 ? "bg-white" : "bg-slate-50/30"}>
                    {/* Ítem */}
                    <td className="px-4 py-3">
                      <div className="flex items-center gap-2">
                        <div className={`h-8 w-8 rounded-lg flex items-center justify-center shrink-0 ${
                          esM ? "bg-blue-50 text-blue-600" : "bg-purple-50 text-purple-600"
                        }`}>
                          <Package2 size={14} />
                        </div>
                        <div className="min-w-0">
                          <p className="font-bold text-slate-800 truncate">{item?.nombre ?? "—"}</p>
                          {item?.composicion && (
                            <p className="text-[10px] text-slate-400 truncate">{item.composicion}</p>
                          )}
                        </div>
                      </div>
                    </td>

                    {/* Tipo */}
                    <td className="px-4 py-3">
                      <Badge variant="outline" className={`rounded-full text-[10px] font-bold uppercase border ${
                        esM
                          ? "bg-blue-50 text-blue-700 border-blue-200"
                          : "bg-purple-50 text-purple-700 border-purple-200"
                      }`}>
                        {esM ? "Material" : "Insumo"}
                      </Badge>
                    </td>

                    {/* Cantidad */}
                    <td className="px-4 py-3 text-slate-600 tabular-nums">
                      {cantidad} <span className="text-slate-400 text-xs">{item?.unidad_medida ?? ""}</span>
                    </td>

                    {/* Desperdicio */}
                    <td className="px-4 py-3 text-slate-600 tabular-nums">
                      {d.porcentaje_desperdicio ?? 0}%
                    </td>

                    {/* Precio unit. */}
                    <td className="px-4 py-3 text-slate-600 tabular-nums">
                      S/ {precio.toFixed(2)}
                    </td>

                    {/* Subtotal */}
                    <td className="px-4 py-3 font-bold text-slate-800 tabular-nums">
                      S/ {subtotal.toFixed(2)}
                    </td>

                    {/* Acción */}
                    {canEdit && (
                      <td className="px-4 py-3">
                        <Button variant="ghost" size="icon" disabled={isDeleting}
                          onClick={() => remove(String(d.id))}
                          className="h-8 w-8 text-red-400 hover:text-red-600 hover:bg-red-50">
                          <Trash2 size={14} />
                        </Button>
                      </td>
                    )}
                  </tr>
                );
              })}
            </tbody>

            {/* Footer con total */}
            <tfoot>
              <tr className="border-t border-slate-200 bg-slate-50">
                <td colSpan={canEdit ? 5 : 4} className="px-4 py-3 text-right text-xs font-black uppercase tracking-widest text-slate-400">
                  Total estimado
                </td>
                <td className="px-4 py-3 font-black text-emerald-700 tabular-nums">
                  S/ {costoTotal.toFixed(2)}
                </td>
                {canEdit && <td />}
              </tr>
            </tfoot>
          </table>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import {
  Dialog, DialogContent, DialogTitle, DialogDescription,
} from "@/components/ui/dialog";
import { Button }   from "@/components/ui/button";
import { Input }    from "@/components/ui/input";
import { Label }    from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import {
  Select, SelectContent, SelectItem,
  SelectTrigger, SelectValue,
} from "@/components/ui/select";
import { toast }   from "sonner";
import { 
  FilePen, X, Sparkles, Layers, DollarSign, 
  Clock, AlignLeft, Link as LinkIcon, Image as ImageIcon,
  Loader2, Save, Scissors
} from "lucide-react";
import { cn } from "@/lib/utils";

interface Props {
  isOpen:    boolean;
  ficha:     any;
  onClose:   () => void;
  onSuccess: () => void;
}

const ESTADOS = [
  { value: "borrador", label: "Borrador",  dot: "bg-slate-400",   glow: "shadow-slate-200" },
  { value: "activo",   label: "Activo",    dot: "bg-emerald-500", glow: "shadow-emerald-200" },
  { value: "revision", label: "Revisión",  dot: "bg-amber-400",   glow: "shadow-amber-200" },
  { value: "obsoleto", label: "Obsoleto",  dot: "bg-red-500",     glow: "shadow-red-200" },
];

export default function EditFichaDialog({ isOpen, ficha, onClose, onSuccess }: Props) {
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({
    version:               "",
    estado:                "borrador",
    sam_total:             "",
    costo_estimado:        "",
    descripcion_detallada: "",
    ficha_url:             "",
    imagen_geometral:      "",
  });

  useEffect(() => {
    if (ficha) setForm({
      version:               ficha.version               ?? "",
      estado:                ficha.estado                ?? "borrador",
      sam_total:             ficha.sam_total      != null ? String(ficha.sam_total)      : "",
      costo_estimado:        ficha.costo_estimado != null ? String(ficha.costo_estimado) : "",
      descripcion_detallada: ficha.descripcion_detallada ?? "",
      ficha_url:             ficha.ficha_url             ?? "",
      imagen_geometral:      ficha.imagen_geometral      ?? "",
    });
  }, [ficha]);

  const set = (key: string, value: string) => setForm((f) => ({ ...f, [key]: value }));

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      const res = await fetch(`/api/admin/fichas-tecnicas/${ficha.id}`, {
        method:  "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          version:               form.version               || undefined,
          estado:                form.estado,
          sam_total:             form.sam_total      ? Number(form.sam_total)      : undefined,
          costo_estimado:        form.costo_estimado ? Number(form.costo_estimado) : undefined,
          descripcion_detallada: form.descripcion_detallada || undefined,
          ficha_url:             form.ficha_url             || undefined,
          imagen_geometral:      form.imagen_geometral      || undefined,
        }),
      });
      const body = await res.json().catch(() => ({}));
      if (!res.ok) throw new Error(body?.error ?? "Error al guardar");
      toast.success("Ingeniería de prenda actualizada");
      onSuccess();
      onClose();
    } catch (err: any) {
      toast.error(err.message ?? "Error inesperado");
    } finally {
      setLoading(false);
    }
  };

  const estadoActual = ESTADOS.find((e) => e.value === form.estado);

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-3xl bg-white/95 backdrop-blur-3xl border-none shadow-[0_32px_128px_-16px_rgba(0,0,0,0.15)] p-0 overflow-hidden rounded-[48px] max-h-[92vh] flex flex-col animate-in zoom-in-95 duration-500">
        
        {/* HEADER: Estética de Atelier Premium */}
        <div className="bg-gradient-to-br from-fuchsia-900 to-pink-950 px-10 py-10 text-white relative shrink-0">
          <div className="absolute top-0 right-0 w-64 h-64 bg-fuchsia-500/10 rounded-full -mr-32 -mt-32 blur-3xl animate-pulse" />
          <div className="absolute bottom-0 left-0 w-32 h-32 bg-pink-500/10 rounded-full -ml-16 -mb-16 blur-2xl" />
          
          <div className="flex justify-between items-start relative z-10">
            <div className="flex items-center gap-6">
              <div className="p-4 bg-white/5 backdrop-blur-2xl border border-white/10 rounded-3xl shadow-2xl rotate-3 transition-transform hover:rotate-0">
                <Scissors className="w-8 h-8 text-fuchsia-400" />
              </div>
              <div>
                <div className="flex items-center gap-3">
                  <DialogTitle className="text-3xl font-black tracking-tighter uppercase">
                    Editor de Ficha
                  </DialogTitle>
                  <div className="px-3 py-1 bg-fuchsia-500/20 text-fuchsia-300 rounded-full text-[10px] font-black uppercase tracking-[0.2em] border border-fuchsia-500/30">
                    Pro Studio
                  </div>
                </div>
                <DialogDescription className="text-slate-400 font-bold text-sm mt-1">
                  {ficha?.productos?.nombre 
                    ? `Perfeccionando la ingeniería de: ${ficha.productos.nombre}`
                    : "Actualiza los parámetros técnicos y de diseño."}
                </DialogDescription>
              </div>
            </div>
            <button onClick={onClose} className="p-3 bg-white/5 hover:bg-white/10 rounded-2xl transition-all">
              <X className="w-5 h-5 text-slate-400" />
            </button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-10 space-y-12 custom-scrollbar bg-white/50">
          
          {/* FORMULARIO ORGANIZADO EN BLOQUES */}
          <form id="edit-ficha-form" onSubmit={handleSubmit} className="space-y-12">
            
            {/* BLOQUE 1: CONTROL DE VERSIÓN Y ESTADO */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="col-span-full">
                <SectionHeader icon={<Layers className="w-4 h-4" />} label="Control de Versión" />
              </div>
              
              <Field label="Versión de Ingeniería" icon={<Sparkles className="w-4 h-4" />}>
                <Input
                  value={form.version}
                  onChange={(e) => set("version", e.target.value)}
                  placeholder="Ej. 2.4.1"
                  className={inputCls}
                />
              </Field>

              <Field label="Estado Operativo" icon={<Clock className="w-4 h-4" />}>
                <Select value={form.estado} onValueChange={(v) => set("estado", v)}>
                  <SelectTrigger className={cn(inputCls, "bg-white")}>
                    <div className="flex items-center gap-3">
                      <span className={cn("w-2.5 h-2.5 rounded-full shadow-lg transition-all", estadoActual?.dot, estadoActual?.glow)} />
                      <SelectValue />
                    </div>
                  </SelectTrigger>
                  <SelectContent className="rounded-3xl border-none shadow-2xl p-2 bg-white/95 backdrop-blur-xl">
                    {ESTADOS.map((e) => (
                      <SelectItem key={e.value} value={e.value} className="rounded-2xl py-3 px-4 font-bold focus:bg-fuchsia-50 transition-colors">
                        <div className="flex items-center gap-3">
                          <span className={cn("w-2 h-2 rounded-full", e.dot)} />
                          {e.label}
                        </div>
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </Field>
            </div>

            {/* BLOQUE 2: PRODUCTIVIDAD Y COSTOS */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="col-span-full">
                <SectionHeader icon={<DollarSign className="w-4 h-4" />} label="Eficiencia y Costeo" />
              </div>

              <Field label="SAM Total (Minutos)" icon={<Clock className="w-4 h-4" />}>
                <div className="relative group">
                  <Input
                    type="number"
                    value={form.sam_total}
                    onChange={(e) => set("sam_total", e.target.value)}
                    placeholder="0.00"
                    className={cn(inputCls, "pr-12")}
                  />
                  <span className="absolute right-6 top-1/2 -translate-y-1/2 text-[10px] font-black text-slate-300 uppercase">min</span>
                </div>
              </Field>

              <Field label="Costo de Fabricación (Estimado)" icon={<DollarSign className="w-4 h-4" />}>
                <div className="relative group">
                  <span className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-400 font-bold">S/</span>
                  <Input
                    type="number"
                    value={form.costo_estimado}
                    onChange={(e) => set("costo_estimado", e.target.value)}
                    placeholder="0.00"
                    className={cn(inputCls, "pl-12")}
                  />
                </div>
              </Field>
            </div>

            {/* BLOQUE 3: DOCUMENTACIÓN Y MULTIMEDIA */}
            <div className="space-y-8">
              <SectionHeader icon={<AlignLeft className="w-4 h-4" />} label="Detalles y Recursos" />
              
              <Field label="Notas de Ingeniería / Descripción" icon={<AlignLeft className="w-4 h-4" />}>
                <Textarea
                  value={form.descripcion_detallada}
                  onChange={(e) => set("descripcion_detallada", e.target.value)}
                  placeholder="Especificaciones sobre costuras, avíos, o acabados especiales..."
                  rows={4}
                  className={cn(inputCls, "h-auto py-5 resize-none")}
                />
              </Field>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <Field label="Enlace Ficha Técnica (PDF)" icon={<LinkIcon className="w-4 h-4" />}>
                  <div className="relative">
                    <Input
                      value={form.ficha_url}
                      onChange={(e) => set("ficha_url", e.target.value)}
                      placeholder="https://cloud.storage/ficha.pdf"
                      className={cn(inputCls, "pl-12")}
                    />
                    <LinkIcon className="absolute left-6 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300" />
                  </div>
                </Field>
                <Field label="Imagen Geometral (Vector)" icon={<ImageIcon className="w-4 h-4" />}>
                  <div className="relative">
                    <Input
                      value={form.imagen_geometral}
                      onChange={(e) => set("imagen_geometral", e.target.value)}
                      placeholder="https://cloud.storage/geometral.png"
                      className={cn(inputCls, "pl-12")}
                    />
                    <ImageIcon className="absolute left-6 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300" />
                  </div>
                </Field>
              </div>
            </div>
          </form>
        </div>

        {/* FOOTER: Acción y Cierre */}
        <div className="px-10 py-8 bg-slate-50/80 backdrop-blur-md border-t border-slate-100/50 shrink-0 flex items-center justify-between gap-6">
          <Button
            type="button"
            variant="ghost"
            onClick={onClose}
            disabled={loading}
            className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em] hover:text-slate-600 rounded-2xl h-14 px-8"
          >
            Descartar Cambios
          </Button>
          <Button
            type="submit"
            form="edit-ficha-form"
            disabled={loading}
            className="bg-slate-900 hover:bg-slate-800 text-white shadow-2xl shadow-slate-200 rounded-[24px] h-14 px-10 font-black uppercase text-xs tracking-widest group"
          >
            {loading ? (
              <div className="flex items-center gap-3">
                <Loader2 className="w-4 h-4 animate-spin" />
                Guardando Ingeniería...
              </div>
            ) : (
              <div className="flex items-center gap-3">
                Guardar Ficha
                <Save className="w-4 h-4 group-hover:scale-110 transition-transform" />
              </div>
            )}
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
}

// ─── Helpers Premium ──────────────────────────────────────────────────
const inputCls = "bg-slate-50 border-slate-100 rounded-[20px] focus:bg-white focus:border-fuchsia-200 focus:shadow-xl focus:shadow-fuchsia-50/50 focus-visible:ring-0 transition-all h-14 px-6 text-sm font-bold text-slate-700 placeholder:text-slate-300";

function SectionHeader({ icon, label }: { icon: React.ReactNode; label: string }) {
  return (
    <div className="flex items-center gap-4">
      <div className="p-2.5 bg-fuchsia-50 text-fuchsia-600 rounded-xl">
        {icon}
      </div>
      <span className="text-[12px] font-black uppercase tracking-[0.3em] text-slate-900">{label}</span>
      <div className="h-px flex-1 bg-slate-100" />
    </div>
  );
}

function Field({ label, icon, children }: { label: string; icon: React.ReactNode; children: React.ReactNode }) {
  return (
    <div className="space-y-3">
      <Label className="text-[11px] uppercase font-black text-slate-400 flex items-center gap-2 tracking-[0.1em] ml-1">
        {icon}
        {label}
      </Label>
      {children}
    </div>
  );
}

'use client';

import { useState, useId } from 'react';
import { useRouter } from 'next/navigation';
import { useForm, useFieldArray, Controller } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { Loader2, Save, ArrowLeft, Plus, Trash2, FileText, ShieldAlert } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Form } from '@/components/ui/form';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { toast } from 'sonner';
import {
  FormField, FormControl, FormItem, FormLabel, FormMessage,
} from '@/components/ui/form';
import ImagenGeometralExtractor from '@/components/admin/common/ImagenGeometralExtractor';
import { usePermissions } from '@/lib/hooks/usePermissions';

// ─── Schemas ────────────────────────────────────────────────────────────────

const medidaSchema = z.object({
  punto_medida: z.string().min(1, 'Punto de medida requerido'),
  talla:        z.string().min(1, 'Talla requerida'),
  valor_cm:     z.number().nonnegative().optional(),
  tolerancia:   z.number().nonnegative().optional(),
});

const fichaTecnicaSchema = z.object({
  producto_id:           z.string(),
  version:               z.string().optional(),
  descripcion_detallada: z.string().optional(),
  sam_total:             z.number().nonnegative().optional(),
  costo_estimado:        z.number().nonnegative().optional(),
  imagen_geometral:      z.string().optional(),
  medidas:               z.array(medidaSchema),
});

type FichaTecnicaInput = z.infer<typeof fichaTecnicaSchema>;

// ─── Componente ─────────────────────────────────────────────────────────────

export function FichaTecnicaForm({ productos }: { productos?: any[] }) {
  const router = useRouter();
  const formId = useId();
  const { can, isLoading: authLoading } = usePermissions();

  const [isSubmitting,        setIsSubmitting]        = useState(false);
  const [tallasProducto,      setTallasProducto]      = useState<string[]>([]);
  const [coloresProducto,     setColoresProducto]     = useState<string[]>([]);

  const puedeCrearFicha = can('create', 'ficha_tecnica');
  const puedeMedidas    = can('edit',   'ficha_tecnica');

  const form = useForm<FichaTecnicaInput>({
    resolver: zodResolver(fichaTecnicaSchema),
    defaultValues: {
      producto_id:           '',
      version:               '1.0',
      descripcion_detallada: '',
      sam_total:             undefined,
      costo_estimado:        undefined,
      imagen_geometral:      undefined,
      medidas: [{ punto_medida: '', talla: '', valor_cm: undefined, tolerancia: undefined }],
    },
  });

  const { fields, append, remove, replace } = useFieldArray({
    control: form.control,
    name: 'medidas',
  });

  // ── Callback del extractor de imagen geometral ─────────────
  const handleGeometralExtracted = (data: any, imagenUrl?: string) => {
    // Guardar URL de la imagen geometral
    if (imagenUrl) form.setValue('imagen_geometral', imagenUrl);

    // Poblar campos básicos extraídos por la IA
    if (data?.descripcion)    form.setValue('descripcion_detallada', data.descripcion);
    if (data?.sam_total)      form.setValue('sam_total',      Number(data.sam_total));
    if (data?.costo_estimado) form.setValue('costo_estimado', Number(data.costo_estimado));

    // Tallas y colores vienen del producto (ya consultados en el backend)
    if (data?.tallas_disponibles?.length)  setTallasProducto(data.tallas_disponibles);
    if (data?.colores_disponibles?.length) setColoresProducto(data.colores_disponibles);

    // Reemplazar medidas con las extraídas
    if (data?.medidas?.length > 0) {
      replace(
        data.medidas.map((m: any) => ({
          punto_medida: m.punto_medida || '',
          talla:        m.talla        || '',
          valor_cm:     m.valor_cm     ? Number(m.valor_cm)   : undefined,
          tolerancia:   m.tolerancia   ? Number(m.tolerancia) : undefined,
        }))
      );
      toast.success(`Se extrajeron ${data.medidas.length} puntos de medida`);
    }
  };

  // ── Submit ─────────────────────────────────────────────────
  const onSubmit = async (data: FichaTecnicaInput) => {
    try {
      setIsSubmitting(true);

      if (!puedeCrearFicha) {
        toast.error('No tienes permisos para crear fichas técnicas');
        return;
      }
      if (!data.producto_id) {
        toast.error('Debes seleccionar un producto');
        return;
      }

      // 1. Crear ficha técnica
      const res = await fetch('/api/admin/fichas-tecnicas', {
        method:  'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          producto_id:           Number(data.producto_id),
          version:               data.version,
          descripcion_detallada: data.descripcion_detallada || null,
          sam_total:             data.sam_total      || null,
          costo_estimado:        data.costo_estimado || null,
          imagen_geometral:      data.imagen_geometral || null,
        }),
      });

      const result = await res.json();
      if (!res.ok) throw new Error(result.error || 'Error al crear ficha técnica');

      const fichaId = result.data?.id;

      // 2. Guardar medidas en bulk
      if (puedeMedidas && data.medidas?.length > 0 && fichaId) {
        const medidasRes = await fetch('/api/admin/fichas-tecnicas/medidas', {
          method:  'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ 
            ficha_id: fichaId, 
            medidas: data.medidas 
          }),
        });
        if (!medidasRes.ok) toast.warning('Ficha creada pero hubo un error al guardar medidas');
      }

      toast.success('Ficha técnica registrada correctamente');
      router.push('/admin/Panel-Administrativo/fichas-tecnicas');

    } catch (error: any) {
      toast.error(error.message || 'Error al guardar');
    } finally {
      setIsSubmitting(false);
    }
  };

  const tallasUnicas = new Set(
    (form.watch('medidas') || []).map(m => m.talla).filter(Boolean)
  );

  const productoSeleccionadoId = form.watch('producto_id');

  // ── Guards ─────────────────────────────────────────────────
  if (authLoading) return (
    <div className="h-64 flex flex-col items-center justify-center">
      <div className="w-8 h-8 border-4 border-slate-900 border-t-transparent rounded-full animate-spin mb-3" />
      <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Verificando permisos...</p>
    </div>
  );

  if (!puedeCrearFicha) return (
    <div className="bg-white rounded-3xl border border-red-100 p-10 flex flex-col items-center gap-3 text-center">
      <ShieldAlert className="w-10 h-10 text-red-400" />
      <p className="font-black text-slate-800 text-lg">Sin permisos</p>
      <p className="text-sm text-slate-500">Solo diseñadores y administradores pueden crear fichas técnicas.</p>
      <Button variant="outline" onClick={() => router.back()} className="mt-2">Volver</Button>
    </div>
  );

  // ── Render ─────────────────────────────────────────────────
  return (
    <Form {...form}>
      <form
        id={`${formId}-ficha-tecnica`}
        onSubmit={form.handleSubmit(onSubmit)}
        className="space-y-8"
      >

        {/* ── SECCIÓN 1: Información General ── */}
        <div className="bg-white rounded-3xl shadow-xl border border-slate-100 p-8 space-y-6">
          <div className="flex items-center gap-3">
            <div className="w-1 h-8 bg-slate-900 rounded-full" />
            <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tight">
              Información General
            </h2>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {/* Selector de producto */}
            <FormField
              control={form.control}
              name="producto_id"
              render={({ field }) => (
                <FormItem>
                  <FormLabel className="text-[10px] font-black uppercase tracking-widest text-slate-400">
                    Producto *
                  </FormLabel>
                  <FormControl>
                    <select
                      {...field}
                      className="w-full h-10 border border-slate-200 rounded-xl text-sm px-3 bg-white focus:ring-2 focus:ring-blue-400 focus:border-transparent"
                    >
                      <option value="">Seleccionar producto...</option>
                      {productos?.map(p => (
                        <option key={p.id} value={p.id.toString()}>
                          {p.nombre} ({p.sku})
                        </option>
                      ))}
                    </select>
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            {/* Versión */}
            <FormField
              control={form.control}
              name="version"
              render={({ field }) => (
                <FormItem>
                  <FormLabel className="text-[10px] font-black uppercase tracking-widest text-slate-400">
                    Versión
                  </FormLabel>
                  <FormControl>
                    <Input {...field} placeholder="1.0" className="h-10 border-slate-200 rounded-xl text-sm" />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            {/* SAM + Costo */}
            <div className="grid grid-cols-2 gap-3">
              <FormField
                control={form.control}
                name="sam_total"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="text-[10px] font-black uppercase tracking-widest text-slate-400">
                      SAM Total (min)
                    </FormLabel>
                    <FormControl>
                      <Input
                        {...field}
                        type="number" min="0"
                        onChange={e => field.onChange(e.target.value ? Number(e.target.value) : undefined)}
                        placeholder="0"
                        className="h-10 border-slate-200 rounded-xl text-sm"
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
              <FormField
                control={form.control}
                name="costo_estimado"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="text-[10px] font-black uppercase tracking-widest text-slate-400">
                      Costo Est. (S/)
                    </FormLabel>
                    <FormControl>
                      <Input
                        {...field}
                        type="number" min="0" step="0.01"
                        onChange={e => field.onChange(e.target.value ? Number(e.target.value) : undefined)}
                        placeholder="0.00"
                        className="h-10 border-slate-200 rounded-xl text-sm"
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </div>
          </div>

          {/* Descripción */}
          <FormField
            control={form.control}
            name="descripcion_detallada"
            render={({ field }) => (
              <FormItem>
                <FormLabel className="text-[10px] font-black uppercase tracking-widest text-slate-400">
                  Descripción Detallada
                </FormLabel>
                <FormControl>
                  <Textarea
                    {...field}
                    placeholder="Descripción general del producto y su uso..."
                    rows={3}
                    className="border-slate-200 rounded-xl text-sm resize-none"
                  />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />

          {/* Tallas y colores del producto (se llenan tras extracción) */}
          {(tallasProducto.length > 0 || coloresProducto.length > 0) && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pt-2">
              {tallasProducto.length > 0 && (
                <div className="bg-slate-50 border border-slate-100 rounded-xl p-4">
                  <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mb-2">
                    Tallas disponibles (desde producto)
                  </p>
                  <div className="flex flex-wrap gap-2">
                    {tallasProducto.map(t => (
                      <span key={t} className="px-3 py-1 bg-white border border-slate-200 rounded-lg text-xs font-bold text-slate-700">
                        {t}
                      </span>
                    ))}
                  </div>
                </div>
              )}
              {coloresProducto.length > 0 && (
                <div className="bg-slate-50 border border-slate-100 rounded-xl p-4">
                  <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mb-2">
                    Colores disponibles (desde producto)
                  </p>
                  <div className="flex flex-wrap gap-2">
                    {coloresProducto.map(c => (
                      <span key={c} className="px-3 py-1 bg-pink-50 border border-pink-100 rounded-lg text-xs font-bold text-pink-700">
                        {c}
                      </span>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}
        </div>

        {/* ── SECCIÓN 2: Imagen Geometral + Extracción IA ── */}
        <div className="bg-white rounded-3xl shadow-xl border border-slate-100 p-8 space-y-6">
          <div className="flex items-center gap-3">
            <div className="w-1 h-8 bg-pink-600 rounded-full" />
            <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tight">
              Imagen Geometral
            </h2>
          </div>
          <p className="text-sm text-slate-500">
            Sube la imagen geometral de la prenda. La IA extraerá automáticamente las medidas,
            materiales, SAM y costo estimado. Las tallas y colores se obtienen del producto seleccionado.
          </p>

          <ImagenGeometralExtractor
            productoId={productoSeleccionadoId || undefined}
            onExtract={handleGeometralExtracted}
            disabled={!productoSeleccionadoId}
            label={
              productoSeleccionadoId
                ? 'Cargar imagen geometral'
                : 'Selecciona un producto primero'
            }
          />

          {!productoSeleccionadoId && (
            <p className="text-xs text-amber-600 font-semibold">
              ⚠ Selecciona un producto para que la IA pueda obtener tallas y colores automáticamente.
            </p>
          )}

          {/* Preview imagen si ya fue subida */}
          {form.watch('imagen_geometral') && (
            <div className="border border-slate-100 rounded-xl overflow-hidden">
              <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest p-3 border-b border-slate-100">
                Imagen guardada
              </p>
              <img
                src={form.watch('imagen_geometral')}
                alt="Geometral"
                className="max-h-64 object-contain mx-auto p-4"
              />
            </div>
          )}
        </div>

        {/* ── SECCIÓN 3: Tabla de Medidas ── */}
        {puedeMedidas && (
          <div className="bg-white rounded-3xl shadow-xl border border-slate-100 p-8 space-y-6">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="w-1 h-8 bg-purple-600 rounded-full" />
                <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tight">
                  Tabla de Medidas
                </h2>
                {fields.length > 0 && (
                  <span className="px-2.5 py-0.5 bg-purple-100 text-purple-700 text-xs font-black rounded-full">
                    {fields.length}
                  </span>
                )}
                {tallasUnicas.size > 0 && (
                  <span className="text-xs font-semibold text-slate-500">
                    {tallasUnicas.size} talla{tallasUnicas.size !== 1 ? 's' : ''}
                  </span>
                )}
              </div>
              <Button
                type="button"
                variant="outline"
                size="sm"
                onClick={() => append({ punto_medida: '', talla: '', valor_cm: undefined, tolerancia: undefined })}
                className="h-9 gap-1.5 text-xs font-bold uppercase rounded-xl border-purple-200 text-purple-700 hover:bg-purple-50"
              >
                <Plus size={14} /> Agregar Medida
              </Button>
            </div>

            {fields.length === 0 ? (
              <div className="text-center py-12 border-2 border-dashed border-slate-200 rounded-2xl">
                <FileText className="w-10 h-10 text-slate-300 mx-auto mb-3" />
                <p className="text-xs text-slate-400 font-black uppercase tracking-widest">
                  Sin medidas — sube la imagen geometral para extraerlas automáticamente
                </p>
              </div>
            ) : (
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="border-b border-slate-200">
                      <th className="text-left py-3 px-4 text-[10px] font-black text-slate-400 uppercase">Punto de Medida</th>
                      <th className="text-center py-3 px-4 text-[10px] font-black text-slate-400 uppercase">Talla</th>
                      <th className="text-center py-3 px-4 text-[10px] font-black text-slate-400 uppercase">Valor (cm)</th>
                      <th className="text-center py-3 px-4 text-[10px] font-black text-slate-400 uppercase">Tolerancia (cm)</th>
                      <th className="text-center py-3 px-4 text-[10px] font-black text-slate-400 uppercase"></th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {fields.map((field, idx) => (
                      <tr key={field.id} className="hover:bg-slate-50">
                        <td className="py-3 px-4">
                          <Controller
                            control={form.control}
                            name={`medidas.${idx}.punto_medida`}
                            render={({ field: f }) => (
                              <Input {...f} placeholder="Ej. Largo, Ancho..." className="h-8 border-slate-200 rounded text-xs" />
                            )}
                          />
                        </td>
                        <td className="py-3 px-4">
                          <Controller
                            control={form.control}
                            name={`medidas.${idx}.talla`}
                            render={({ field: f }) => (
                              <Input {...f} placeholder="S, M, L..." className="h-8 border-slate-200 rounded text-xs text-center" />
                            )}
                          />
                        </td>
                        <td className="py-3 px-4">
                          <Controller
                            control={form.control}
                            name={`medidas.${idx}.valor_cm`}
                            render={({ field: f }) => (
                              <Input
                                {...f}
                                type="number" min="0" step="0.1"
                                onChange={e => f.onChange(e.target.value ? Number(e.target.value) : undefined)}
                                placeholder="0"
                                className="h-8 border-slate-200 rounded text-xs text-center"
                              />
                            )}
                          />
                        </td>
                        <td className="py-3 px-4">
                          <Controller
                            control={form.control}
                            name={`medidas.${idx}.tolerancia`}
                            render={({ field: f }) => (
                              <Input
                                {...f}
                                type="number" min="0" step="0.1"
                                onChange={e => f.onChange(e.target.value ? Number(e.target.value) : undefined)}
                                placeholder="±0"
                                className="h-8 border-slate-200 rounded text-xs text-center"
                              />
                            )}
                          />
                        </td>
                        <td className="py-3 px-4 text-center">
                          <Button
                            type="button" variant="ghost" size="icon"
                            onClick={() => remove(idx)}
                            className="h-8 w-8 text-slate-400 hover:text-red-600 hover:bg-red-50"
                          >
                            <Trash2 size={14} />
                          </Button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        )}

        {/* ── ACCIONES ── */}
        <div className="flex items-center justify-end gap-4 sticky bottom-6 bg-white/80 backdrop-blur-sm p-4 rounded-2xl border border-slate-200 shadow-lg">
          <Button
            type="button" variant="outline"
            onClick={() => router.back()}
            disabled={isSubmitting}
            className="h-11 px-6 font-bold uppercase rounded-xl gap-2"
          >
            <ArrowLeft size={15} /> Cancelar
          </Button>
          <Button
            type="submit"
            form={`${formId}-ficha-tecnica`}
            disabled={isSubmitting}
            className="h-11 px-8 bg-slate-900 hover:bg-slate-800 font-bold uppercase rounded-xl gap-2 text-white"
          >
            {isSubmitting
              ? <><Loader2 size={15} className="animate-spin" /> Guardando...</>
              : <><Save size={15} /> Crear Ficha Técnica</>
            }
          </Button>
        </div>

      </form>
    </Form>
  );
}

"use client";

import { memo } from "react";
import { useRouter } from "next/navigation";
import { Eye, Edit, FileText, Package, Ruler } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import {
  Table, TableBody, TableCell,
  TableHead, TableHeader, TableRow,
} from "@/components/ui/table";

// ─── Tipos ────────────────────────────────────────────────────
export interface FichaTecnicaRow {
  id:                    string;
  version:               string;
  estado:                string;
  descripcion_detallada: string | null;
  sam_total:             number | null;
  costo_estimado:        number | null;
  ficha_url:             string | null;
  created_at:            string;
  productos:             { id: string; nombre: string; sku: string; imagen_url: string | null } | null;
  ficha_medidas:         { id: string }[];
}

interface Props {
  data:      FichaTecnicaRow[];
  loading?:  boolean;
  onEdit?:   (f: FichaTecnicaRow) => void;
}

// ─── Helpers ─────────────────────────────────────────────────
const ESTADOS: Record<string, { label: string; color: string }> = {
  borrador:  { label: "Borrador",  color: "bg-gray-50    text-gray-600    border-gray-200"    },
  activo:    { label: "Activo",    color: "bg-emerald-50 text-emerald-700 border-emerald-200" },
  revisión:  { label: "Revisión",  color: "bg-amber-50   text-amber-700   border-amber-200"   },
  obsoleto:  { label: "Obsoleto",  color: "bg-red-50     text-red-700     border-red-200"     },
};

function EstadoBadge({ estado }: { estado: string }) {
  const s = ESTADOS[estado] ?? ESTADOS.borrador;
  return (
    <Badge variant="outline" className={`rounded-full px-3 py-0.5 text-[10px] font-bold uppercase border ${s.color}`}>
      {s.label}
    </Badge>
  );
}

// ─── Componente ───────────────────────────────────────────────
function FichasTecnicasTable({ data, loading, onEdit }: Props) {
  const router = useRouter();
  const colSpan = onEdit ? 7 : 6;

  return (
    <Table>
      <TableHeader>
        <TableRow className="hover:bg-transparent border-none">
          <TableHead className={th}>Producto</TableHead>
          <TableHead className={`${th} text-center`}>Versión</TableHead>
          <TableHead className={`${th} text-center`}>Estado</TableHead>
          <TableHead className={`${th} text-center`}>Medidas</TableHead>
          <TableHead className={`${th} text-center`}>SAM total</TableHead>
          <TableHead className={`${th} text-center`}>Costo est.</TableHead>
          <TableHead className={`${th} text-right pr-6`}>Acciones</TableHead>
        </TableRow>
      </TableHeader>

      <TableBody>
        {/* Skeleton */}
        {loading && Array.from({ length: 5 }).map((_, i) => (
          <TableRow key={`sk-${i}`} className={row}>
            <TableCell className="py-4 px-6 rounded-l-xl">
              <div className="flex items-center gap-3">
                <Skeleton className="h-10 w-10 rounded-xl shrink-0" />
                <div className="space-y-1.5">
                  <Skeleton className="h-3.5 w-36" />
                  <Skeleton className="h-3 w-20" />
                </div>
              </div>
            </TableCell>
            {[...Array(5)].map((_, j) => (
              <TableCell key={j} className="text-center">
                <Skeleton className="h-5 w-16 mx-auto rounded-full" />
              </TableCell>
            ))}
            <TableCell className="text-right px-6 rounded-r-xl">
              <div className="flex justify-end gap-1.5">
                <Skeleton className="h-8 w-8 rounded-lg" />
                <Skeleton className="h-8 w-8 rounded-lg" />
              </div>
            </TableCell>
          </TableRow>
        ))}

        {/* Sin datos */}
        {!loading && data.length === 0 && (
          <TableRow>
            <TableCell colSpan={colSpan} className="py-16 text-center">
              <div className="flex flex-col items-center gap-2">
                <FileText className="w-10 h-10 text-slate-200" />
                <p className="text-xs text-slate-400 font-semibold uppercase tracking-widest">
                  No hay fichas técnicas registradas
                </p>
              </div>
            </TableCell>
          </TableRow>
        )}

        {/* Filas */}
        {!loading && data.map((ficha) => {
          const iniciales = (ficha.productos?.nombre ?? "FT").substring(0, 2).toUpperCase();
          return (
            <TableRow key={ficha.id} className={`${row} group`}>

              {/* Producto */}
              <TableCell className="py-4 px-6 rounded-l-xl">
                <div className="flex items-center gap-3">
                  <div className="h-10 w-10 rounded-xl bg-pink-50 border border-pink-100 text-pink-600 flex items-center justify-center font-black text-xs shrink-0 group-hover:scale-105 transition-transform">
                    {ficha.productos?.imagen_url
                      ? <img src={ficha.productos.imagen_url} alt="" className="h-10 w-10 object-cover rounded-xl" />
                      : iniciales}
                  </div>
                  <div className="flex flex-col min-w-0">
                    <span className="text-sm font-bold text-slate-800 truncate">
                      {ficha.productos?.nombre ?? <span className="text-slate-400 text-xs">Sin producto</span>}
                    </span>
                    <span className="text-[10px] text-slate-400 font-mono mt-0.5">
                      {ficha.productos?.sku ?? "—"}
                    </span>
                  </div>
                </div>
              </TableCell>

              {/* Versión */}
              <TableCell className="text-center">
                <span className="text-xs font-mono font-bold text-slate-600 bg-slate-50 border border-slate-200 px-2 py-0.5 rounded-md">
                  v{ficha.version}
                </span>
              </TableCell>

              {/* Estado */}
              <TableCell className="text-center">
                <EstadoBadge estado={ficha.estado} />
              </TableCell>

              {/* Nº medidas */}
              <TableCell className="text-center">
                <span className="flex items-center justify-center gap-1 text-xs text-slate-500">
                  <Ruler size={11} className="text-slate-300" />
                  {ficha.ficha_medidas.length}
                </span>
              </TableCell>

              {/* SAM */}
              <TableCell className="text-center">
                <span className="text-xs font-semibold text-slate-600">
                  {ficha.sam_total != null ? `${ficha.sam_total} min` : <span className="text-slate-300">—</span>}
                </span>
              </TableCell>

              {/* Costo estimado */}
              <TableCell className="text-center">
                <span className="text-xs font-semibold text-slate-600">
                  {ficha.costo_estimado != null
                    ? `S/ ${Number(ficha.costo_estimado).toFixed(2)}`
                    : <span className="text-slate-300">—</span>}
                </span>
              </TableCell>

              {/* Acciones */}
              <TableCell className="text-right px-6 rounded-r-xl">
                <div className="flex justify-end items-center gap-1.5">
                  <ActionBtn title="Ver detalle" color="pink"
                    onClick={() => router.push(`/admin/Panel-Administrativo/fichas-tecnicas/${ficha.id}`)}>
                    <Eye size={15} />
                  </ActionBtn>
                  {onEdit && (
                    <ActionBtn title="Editar" color="emerald" onClick={() => onEdit(ficha)}>
                      <Edit size={15} />
                    </ActionBtn>
                  )}
                </div>
              </TableCell>

            </TableRow>
          );
        })}
      </TableBody>
    </Table>
  );
}

// ─── Botón acción ─────────────────────────────────────────────
type ColorKey = "pink" | "emerald" | "blue";
const COLOR_MAP: Record<ColorKey, string> = {
  pink:    "hover:text-pink-600    hover:border-pink-200    hover:bg-pink-50",
  emerald: "hover:text-emerald-600 hover:border-emerald-200 hover:bg-emerald-50",
  blue:    "hover:text-blue-600    hover:border-blue-200    hover:bg-blue-50",
};

function ActionBtn({ children, onClick, title, color }: {
  children: React.ReactNode; onClick: () => void; title: string; color: ColorKey;
}) {
  return (
    <Button variant="outline" size="icon" onClick={onClick} title={title}
      className={`h-8 w-8 rounded-lg border-slate-200 text-slate-400 transition-all ${COLOR_MAP[color]}`}>
      {children}
    </Button>
  );
}

const th  = "font-bold text-[10px] tracking-widest text-slate-400 uppercase py-3 px-4";
const row = "bg-white border border-slate-100 rounded-xl shadow-sm hover:shadow-md transition-all duration-150";

export default memo(FichasTecnicasTable);

