  return (
    <div className="space-y-5 bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">

      {/* ── FILA 1: Buscar + Categoría + Ordenar ─────────────── */}
      <div className="flex flex-col lg:flex-row gap-4">

        {/* Buscador */}
        <div className="relative flex-1 group">
          <Search className="absolute left-3 top-3 text-slate-400 group-focus-within:text-pink-500 w-4 h-4 transition-colors" />
          <Input
            placeholder="Buscar por nombre, SKU, versión..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-10 h-11 border-slate-200 bg-slate-50/50 focus:bg-white rounded-xl"
          />
          {searchTerm && (
            <button
              onClick={() => setSearchTerm("")}
              className="absolute right-3 top-3 text-slate-400 hover:text-slate-600"
            >
              <X className="w-4 h-4" />
            </button>
          )}
        </div>

        {/* Categoría */}
        <div className="w-full lg:w-64">
          <Select value={selectedCategoria} onValueChange={setSelectedCategoria}>
            <SelectTrigger className="h-11 rounded-xl border-slate-200 bg-slate-50/50">
              <SelectValue placeholder="Todas las categorías" />
            </SelectTrigger>
            <SelectContent className="rounded-xl">
              <SelectItem value="all">Todas las categorías</SelectItem>
              {categorias?.map((cat) => (
                <SelectItem key={cat.id} value={String(cat.id)}>
                  {cat.nombre}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>

        {/* Ordenar por costo */}
        <Button
          variant="outline"
          onClick={() => {
            if (sortOrder === "none") setSortOrder("asc");
            else if (sortOrder === "asc") setSortOrder("desc");
            else setSortOrder("none");
          }}
          className={`h-11 px-6 rounded-xl font-bold ${
            sortOrder !== "none"
              ? "bg-pink-50 border-pink-200 text-pink-700"
              : ""
          }`}
        >
          <ArrowUpDown
            className={`w-4 h-4 mr-2 transition-transform ${
              sortOrder === "desc" ? "rotate-180" : ""
            }`}
          />
          {sortOrder === "none"
            ? "Ordenar Costo"
            : `Costo: ${sortOrder === "asc" ? "Menor a Mayor" : "Mayor a Menor"}`}
        </Button>
      </div>

      {/* ── FILA 2: Estados ──────────────────────────────────── */}
      <div>
        <Label className="text-xs font-black uppercase text-slate-400 flex items-center gap-2">
          <Filter className="w-3 h-3 text-pink-500" /> Estado
        </Label>

        <div className="flex flex-wrap gap-2 mt-2">

          {/* Todos */}
          <button
            onClick={() => setEstadoFilter("")}
            className={`px-4 h-9 rounded-xl text-sm font-bold transition-all ${
              estadoFilter === ""
                ? "bg-pink-600 text-white shadow-sm"
                : "bg-slate-100 text-slate-600 hover:bg-slate-200"
            }`}
          >
            Todos
          </button>

          {ESTADOS.map(({ value, label, color }) => (
            <button
              key={value}
              onClick={() => setEstadoFilter(value)}
              className={`flex items-center gap-2 px-4 h-9 rounded-xl text-sm font-bold transition-all ${
                estadoFilter === value
                  ? "bg-pink-600 text-white shadow-sm"
                  : "bg-slate-100 text-slate-600 hover:bg-slate-200"
              }`}
            >
              <span
                className="w-2 h-2 rounded-full shrink-0"
                style={{
                  backgroundColor:
                    estadoFilter === value ? "white" : color,
                }}
              />
              {label}
            </button>
          ))}
        </div>
      </div>

      {/* ── FILA 3: Tipo de ficha ────────────────────────────── */}
      <div>
        <Label className="text-xs font-black uppercase text-slate-400 flex items-center gap-2">
          <FileText className="w-3 h-3 text-pink-500" /> Tipo de ficha
        </Label>

        <div className="flex flex-wrap gap-2 mt-2">
          {["Todas", "Con PDF", "Sin PDF", "Con Medidas", "Con Materiales"].map(
            (tipo) => (
              <button
                key={tipo}
                className="px-3 h-9 rounded-xl text-sm font-bold bg-slate-100 text-slate-600 hover:bg-slate-200 transition-all"
              >
                {tipo}
              </button>
            )
          )}
        </div>
      </div>

    </div>
  );
}

"use client";

import { useState, useMemo } from "react";
import { useFichaMedidas } from "@/lib/hooks/useFichasTecnicas";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Skeleton } from "@/components/ui/skeleton";
import { Plus, Trash2, Save, Ruler } from "lucide-react";

interface Props {
  fichaId: string;
  canEdit: boolean;
}

interface MedidaLocal {
  id?:          string;
  punto_medida: string;
  talla:        string;
  valor_cm:     string;
  tolerancia:   string;
}

export default function MedidasEditor({ fichaId, canEdit }: Props) {
  const { medidas, isLoading, save, isSaving } = useFichaMedidas(fichaId);

  const [rows, setRows] = useState<MedidaLocal[]>([]);
  const [editMode, setEditMode] = useState(false);

  // Inicializar rows desde medidas al entrar en edición
  const startEdit = () => {
    setRows(medidas.map((m: any) => ({
      id:           String(m.id),
      punto_medida: m.punto_medida,
      talla:        m.talla,
      valor_cm:     m.valor_cm   != null ? String(m.valor_cm)   : "",
      tolerancia:   m.tolerancia != null ? String(m.tolerancia) : "",
    })));
    setEditMode(true);
  };

  const cancelEdit = () => { setRows([]); setEditMode(false); };

  const addRow = () => setRows((prev) => [
    ...prev,
    { punto_medida: "", talla: "", valor_cm: "", tolerancia: "" },
  ]);

  const removeRow = (idx: number) => setRows((prev) => prev.filter((_, i) => i !== idx));

  const updateRow = (idx: number, field: keyof MedidaLocal, value: string) =>
    setRows((prev) => prev.map((r, i) => i === idx ? { ...r, [field]: value } : r));

  const handleSave = () => {
    const medidas = rows
      .filter((r) => r.punto_medida.trim() && r.talla.trim())
      .map((r) => ({
        punto_medida: r.punto_medida.trim(),
        talla:        r.talla.trim(),
        valor_cm:   r.valor_cm   ? Number(r.valor_cm)   : null,
        tolerancia: r.tolerancia ? Number(r.tolerancia) : null,
      }));
    save(medidas);
    setEditMode(false);
    setRows([]);
  };

  // Agrupar medidas por punto_medida para tabla cruzada
  const { puntos, tallas, matrix } = useMemo(() => {
    const puntosSet = new Set<string>();
    const tallasSet = new Set<string>();
    const map: Record<string, Record<string, { valor_cm: any; tolerancia: any }>> = {};

    for (const m of medidas as any[]) {
      puntosSet.add(m.punto_medida);
      tallasSet.add(m.talla);
      if (!map[m.punto_medida]) map[m.punto_medida] = {};
      map[m.punto_medida][m.talla] = { valor_cm: m.valor_cm, tolerancia: m.tolerancia };
    }

    return {
      puntos: Array.from(puntosSet).sort(),
      tallas: Array.from(tallasSet).sort(),
      matrix: map,
    };
  }, [medidas]);

  if (isLoading) return (
    <div className="space-y-3">
      {Array.from({ length: 4 }).map((_, i) => (
        <Skeleton key={i} className="h-12 w-full rounded-xl" />
      ))}
    </div>
  );

  return (
    <div className="space-y-4">
      {/* Toolbar */}
      <div className="flex items-center justify-between">
        <p className="text-sm text-slate-500 font-semibold">
          {medidas.length} puntos de medida registrados
        </p>
        {canEdit && !editMode && (
          <Button onClick={startEdit} variant="outline"
            className="border-pink-200 text-pink-600 hover:bg-pink-50 font-bold gap-2 h-9">
            <Ruler size={15} /> Editar medidas
          </Button>
        )}
        {editMode && (
          <div className="flex gap-2">
            <Button variant="outline" onClick={cancelEdit} className="h-9 border-slate-200">
              Cancelar
            </Button>
            <Button onClick={handleSave} disabled={isSaving}
              className="bg-pink-600 hover:bg-pink-700 text-white font-bold gap-2 h-9">
              <Save size={15} /> {isSaving ? "Guardando…" : "Guardar medidas"}
            </Button>
          </div>
        )}
      </div>

      {/* Vista lectura — tabla cruzada */}
      {!editMode && medidas.length > 0 && (
        <div className="bg-white rounded-xl border border-slate-100 shadow-sm overflow-x-auto">
          <table className="w-full text-sm">
            <thead>
              <tr className="border-b border-slate-100">
                <th className="text-left px-4 py-3 text-[10px] font-black uppercase tracking-widest text-slate-400 min-w-[150px]">
                  Punto de medida
                </th>
                {tallas.map((t) => (
                  <th key={t} className="px-4 py-3 text-[10px] font-black uppercase tracking-widest text-slate-400 text-center">
                    {t}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {puntos.map((punto, idx) => (
                <tr key={punto} className={idx % 2 === 0 ? "bg-white" : "bg-slate-50/50"}>
                  <td className="px-4 py-3 font-semibold text-slate-700">{punto}</td>
                  {tallas.map((talla) => {
                    const cell = matrix[punto]?.[talla];
                    return (
                      <td key={talla} className="px-4 py-3 text-center text-slate-600 tabular-nums">
                        {cell ? (
                          <span>
                            {cell.valor_cm ?? "—"}
                            {cell.tolerancia != null && (
                              <span className="text-[10px] text-slate-400 ml-1">
                                ±{cell.tolerancia}
                              </span>
                            )}
                          </span>
                        ) : "—"}
                      </td>
                    );
                  })}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Sin medidas */}
      {!editMode && medidas.length === 0 && (
        <div className="bg-white rounded-xl border border-slate-100 shadow-sm py-16 flex flex-col items-center gap-2">
          <Ruler className="w-10 h-10 text-slate-200" />
          <p className="text-xs text-slate-400 font-semibold uppercase tracking-widest">
            No hay medidas registradas
          </p>
          {canEdit && (
            <Button onClick={startEdit} size="sm"
              className="mt-2 bg-pink-600 hover:bg-pink-700 text-white font-bold gap-2">
              <Plus size={14} /> Agregar medidas
            </Button>
          )}
        </div>
      )}

      {/* Vista edición — filas */}
      {editMode && (
        <div className="bg-white rounded-xl border border-slate-100 shadow-sm overflow-hidden">
          <div className="grid grid-cols-[1fr_1fr_120px_120px_40px] gap-0 border-b border-slate-100 bg-slate-50 px-4 py-2">
            {["Punto de medida", "Talla", "Valor (cm)", "Tolerancia", ""].map((h, i) => (
              <span key={i} className="text-[10px] font-black uppercase tracking-widest text-slate-400">{h}</span>
            ))}
          </div>

          <div className="divide-y divide-slate-50">
            {rows.map((row, idx) => (
              <div key={idx} className="grid grid-cols-[1fr_1fr_120px_120px_40px] gap-2 px-4 py-2 items-center">
                <Input value={row.punto_medida} placeholder="Ej: Pecho"
                  onChange={(e) => updateRow(idx, "punto_medida", e.target.value)}
                  className="h-8 text-sm border-slate-200" />
                <Input value={row.talla} placeholder="Ej: M"
                  onChange={(e) => updateRow(idx, "talla", e.target.value)}
                  className="h-8 text-sm border-slate-200" />
                <Input type="number" value={row.valor_cm} placeholder="0.0"
                  onChange={(e) => updateRow(idx, "valor_cm", e.target.value)}
                  className="h-8 text-sm border-slate-200" />
                <Input type="number" value={row.tolerancia} placeholder="0.0"
                  onChange={(e) => updateRow(idx, "tolerancia", e.target.value)}
                  className="h-8 text-sm border-slate-200" />
                <Button variant="ghost" size="icon" onClick={() => removeRow(idx)}
                  className="h-8 w-8 text-red-400 hover:text-red-600 hover:bg-red-50">
                  <Trash2 size={14} />
                </Button>
              </div>
            ))}
          </div>

          <div className="px-4 py-3 border-t border-slate-100">
            <Button variant="outline" size="sm" onClick={addRow}
              className="border-dashed border-slate-300 text-slate-500 hover:border-pink-300 hover:text-pink-600 font-bold gap-2">
              <Plus size={14} /> Agregar fila
            </Button>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import { useForm, useFieldArray } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { Loader2, Plus, Trash2, AlertCircle } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Form } from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { toast } from "sonner";
import {
  FormField, FormControl, FormItem, FormMessage,
} from "@/components/ui/form";
import PdfUploadExtractor from "@/components/admin/common/PdfUploadExtractor";

// ─── Schema ─────────────────────────────────────────────────────────────────

const medidaSchema = z.object({
  punto_medida: z.string().min(1, "Punto de medida requerido"),
  talla:        z.string().min(1, "Talla requerida"),
  valor_cm:     z.number().nonnegative().optional(),
  tolerancia:   z.number().nonnegative().optional(),
});

const medidasUploadSchema = z.object({
  medidas: z.array(medidaSchema).min(1, "Debe haber al menos una medida"),
});

type MedidasUploadInput = z.infer<typeof medidasUploadSchema>;

// ─── Props ───────────────────────────────────────────────────────────────────

interface Props {
  fichaId: string;
  onClose: () => void;
  onSuccess: () => void;
}

// ─── Componente ─────────────────────────────────────────────────────────────

export default function MedidasUploadSheet({ fichaId, onClose, onSuccess }: Props) {
  const [isSubmitting, setIsSubmitting] = useState(false);

  const form = useForm<MedidasUploadInput>({
    resolver: zodResolver(medidasUploadSchema),
    defaultValues: {
      medidas: [{ punto_medida: "", talla: "", valor_cm: undefined, tolerancia: undefined }],
    },
  });

  const { fields, append, remove, replace } = useFieldArray({
    control: form.control,
    name: "medidas",
  });

  // ── Callback del extractor PDF de medidas ──────────────────
  const handlePdfExtracted = (data: any) => {
    if (data?.medidas?.length > 0) {
      replace(
        data.medidas.map((m: any) => ({
          punto_medida: m.punto_medida || "",
          talla:        m.talla        || "",
          valor_cm:     m.valor_cm     ? Number(m.valor_cm)   : undefined,
          tolerancia:   m.tolerancia   ? Number(m.tolerancia) : undefined,
        }))
      );
      toast.success(`Se extrajeron ${data.medidas.length} puntos de medida`);
    }
  };

  // ── Submit ─────────────────────────────────────────────────
  const onSubmit = async (data: MedidasUploadInput) => {
    try {
      setIsSubmitting(true);

      const res = await fetch(`/api/admin/fichas-tecnicas/${fichaId}/medidas/bulk`, {
        method:  "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ medidas: data.medidas }),
      });

      const result = await res.json();
      if (!res.ok) throw new Error(result.error || "Error al guardar medidas");

      toast.success("Medidas cargadas correctamente");
      onSuccess();
    } catch (error: any) {
      toast.error(error.message || "Error al guardar las medidas");
    } finally {
      setIsSubmitting(false);
    }
  };

  // ── Render ─────────────────────────────────────────────────
  return (
    <div className="fixed inset-0 bg-black/50 z-50 flex items-end animate-in slide-in-from-bottom">
      <div className="bg-white w-full max-h-[90vh] overflow-y-auto rounded-t-3xl shadow-2xl">

        {/* Header */}
        <div className="sticky top-0 bg-white border-b border-slate-200 p-6 flex items-center justify-between">
          <div>
            <h2 className="text-2xl font-black text-slate-900 uppercase">Cargar Medidas</h2>
            <p className="text-xs text-slate-400 mt-0.5">Extrae desde PDF o carga manualmente</p>
          </div>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 transition p-1">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <Form {...form}>
          <form onSubmit={form.handleSubmit(onSubmit)} className="p-6 space-y-6">

            {/* Alerta informativa */}
            <div className="bg-emerald-50 border border-emerald-200 rounded-xl p-4 flex items-start gap-3">
              <AlertCircle className="w-5 h-5 text-emerald-600 shrink-0 mt-0.5" />
              <div>
                <p className="text-sm font-bold text-emerald-900">Cortador: carga tu ficha de medidas</p>
                <p className="text-xs text-emerald-700 mt-1">
                  Sube un PDF con la tabla de medidas para extraerlas automáticamente, o cárgalas manualmente.
                </p>
              </div>
            </div>

            {/* Opción 1: PDF */}
            <div className="space-y-3">
              <p className="text-sm font-black text-slate-700 uppercase tracking-widest">
                Opción 1 — Extraer desde PDF
              </p>
              <PdfUploadExtractor
                label="Cargar PDF con tabla de medidas"
                description="Arrastra el PDF o haz clic para seleccionar"
                onExtract={handlePdfExtracted}
              />
            </div>

            {/* Divider */}
            <div className="flex items-center gap-3">
              <div className="flex-1 h-px bg-slate-200" />
              <span className="text-xs text-slate-400 font-bold uppercase tracking-widest">o</span>
              <div className="flex-1 h-px bg-slate-200" />
            </div>

            {/* Opción 2: Manual */}
            <div className="space-y-4">
              <p className="text-sm font-black text-slate-700 uppercase tracking-widest">
                Opción 2 — Cargar manualmente
              </p>

              <div className="overflow-x-auto rounded-xl border border-slate-200">
                <table className="w-full text-sm">
                  <thead className="bg-slate-50 border-b border-slate-200">
                    <tr>
                      <th className="px-4 py-3 text-left text-[10px] font-black text-slate-400 uppercase tracking-widest">Punto de Medida</th>
                      <th className="px-4 py-3 text-left text-[10px] font-black text-slate-400 uppercase tracking-widest">Talla</th>
                      <th className="px-4 py-3 text-left text-[10px] font-black text-slate-400 uppercase tracking-widest">Valor (cm)</th>
                      <th className="px-4 py-3 text-left text-[10px] font-black text-slate-400 uppercase tracking-widest">Tolerancia</th>
                      <th className="px-4 py-3 w-10" />
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {fields.map((field, idx) => (
                      <tr key={field.id} className="hover:bg-slate-50">
                        <td className="px-3 py-2">
                          <FormField
                            control={form.control}
                            name={`medidas.${idx}.punto_medida`}
                            render={({ field }) => (
                              <FormItem>
                                <FormControl>
                                  <Input {...field} placeholder="Ej: Largo" className="border-slate-200 h-8 text-xs" />
                                </FormControl>
                                <FormMessage />
                              </FormItem>
                            )}
                          />
                        </td>
                        <td className="px-3 py-2">
                          <FormField
                            control={form.control}
                            name={`medidas.${idx}.talla`}
                            render={({ field }) => (
                              <FormItem>
                                <FormControl>
                                  <Input {...field} placeholder="S, M, L..." className="border-slate-200 h-8 text-xs text-center" />
                                </FormControl>
                                <FormMessage />
                              </FormItem>
                            )}
                          />
                        </td>
                        <td className="px-3 py-2">
                          <FormField
                            control={form.control}
                            name={`medidas.${idx}.valor_cm`}
                            render={({ field }) => (
                              <FormItem>
                                <FormControl>
                                  <Input
                                    {...field}
                                    type="number" step="0.1" min="0" placeholder="0"
                                    className="border-slate-200 h-8 text-xs text-center"
                                    onChange={e => field.onChange(e.target.value ? Number(e.target.value) : undefined)}
                                  />
                                </FormControl>
                                <FormMessage />
                              </FormItem>
                            )}
                          />
                        </td>
                        <td className="px-3 py-2">
                          <FormField
                            control={form.control}
                            name={`medidas.${idx}.tolerancia`}
                            render={({ field }) => (
                              <FormItem>
                                <FormControl>
                                  <Input
                                    {...field}
                                    type="number" step="0.1" min="0" placeholder="±0"
                                    className="border-slate-200 h-8 text-xs text-center"
                                    onChange={e => field.onChange(e.target.value ? Number(e.target.value) : undefined)}
                                  />
                                </FormControl>
                                <FormMessage />
                              </FormItem>
                            )}
                          />
                        </td>
                        <td className="px-3 py-2 text-center">
                          <button
                            type="button"
                            onClick={() => remove(idx)}
                            className="text-slate-400 hover:text-red-600 transition p-1"
                          >
                            <Trash2 className="w-4 h-4" />
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>

              <Button
                type="button" variant="outline"
                className="w-full border-dashed border-slate-300 text-slate-600 hover:bg-slate-50 font-bold gap-2 h-10"
                onClick={() => append({ punto_medida: "", talla: "", valor_cm: undefined, tolerancia: undefined })}
              >
                <Plus className="w-4 h-4" /> Agregar fila
              </Button>
            </div>

            {/* Acciones */}
            <div className="flex items-center gap-3 border-t border-slate-200 pt-6">
              <Button
                type="button" variant="outline"
                className="flex-1 border-slate-200 font-bold h-11"
                onClick={onClose}
                disabled={isSubmitting}
              >
                Cancelar
              </Button>
              <Button
                type="submit"
                className="flex-1 bg-emerald-600 hover:bg-emerald-700 text-white font-bold h-11 gap-2"
                disabled={isSubmitting}
              >
                {isSubmitting && <Loader2 className="w-4 h-4 animate-spin" />}
                Guardar Medidas
              </Button>
            </div>

          </form>
        </Form>
      </div>
    </div>
  );
}

"use client";
import { useState, useEffect } from "react";
import { PackagePlus } from "lucide-react";
import type { Database } from "@/types/database";
type Categoria = Database['public']['Tables']['categorias']['Row'];
import { toast } from "sonner";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter, DialogDescription } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";

interface Props {
  isOpen: boolean;
  onClose: () => void;
  onSuccess: () => void;
}

export default function CreateInsumoDialog({ isOpen, onClose, onSuccess }: Props) {
  const [loading, setLoading] = useState(false);
  const [categorias, setCategorias] = useState<Categoria[]>([]);
  const [formData, setFormData] = useState({
    nombre: "",
    tipo: "Tela",
    unidad_medida: "Metros",
    stock_actual: "",
    stock_minimo: "",
    categoria_id: "",
  });

  useEffect(() => {
    if (isOpen) {
      fetch("/api/admin/categorias")
        .then((res) => {
          if (!res.ok) throw new Error();
          return res.json();
        })
        .then((data) => setCategorias(Array.isArray(data) ? data : []))
        .catch(() => {
          toast.error("Error al cargar categorías");
          setCategorias([]);
        });
    }
  }, [isOpen]);

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setLoading(true);

    const data = {
      nombre: formData.nombre,
      tipo: formData.tipo,
      unidad_medida: formData.unidad_medida,
      stock_actual: parseFloat(formData.stock_actual || "0"),
      stock_minimo: parseFloat(formData.stock_minimo || "0"),
      categoria_id: formData.categoria_id ? Number(formData.categoria_id) : null,
    };

    try {
      const res = await fetch("/api/admin/inventario", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      });

      if (res.ok) {
        toast.success("Nuevo insumo registrado con éxito");
        setFormData({ nombre: "", tipo: "Tela", unidad_medida: "Metros", stock_actual: "", stock_minimo: "", categoria_id: "" });
        onSuccess();
        onClose();
      } else {
        const errorData = await res.json();
        throw new Error(errorData.message || "Error en el servidor");
      }
    } catch (err: any) {
      toast.error(err.message || "Error al guardar el insumo");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="sm:max-w-[500px] border-none shadow-2xl bg-white p-0 overflow-hidden max-h-[90vh]">
        {/* Banner decorativo superior */}
        <div className="h-2 bg-pink-600 w-full" />

        <div className="p-6 overflow-y-auto max-h-[calc(90vh-8px)]">
          <DialogHeader className="mb-6">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-pink-50 rounded-lg">
                <PackagePlus className="w-6 h-6 text-pink-600" />
              </div>
              <div>
                <DialogTitle className="text-xl font-bold text-slate-800 uppercase tracking-tight">
                  Nuevo Insumo
                </DialogTitle>
                <DialogDescription className="text-slate-500">
                  Registra un nuevo material o insumo al inventario.
                </DialogDescription>
              </div>
            </div>
          </DialogHeader>

          <form onSubmit={handleSubmit} className="space-y-5">
            {/* Nombre */}
            <div className="space-y-2">
              <Label className="text-[11px] uppercase font-bold text-slate-400">
                Nombre del Material
              </Label>
              <Input 
                value={formData.nombre}
                onChange={(e) => setFormData({ ...formData, nombre: e.target.value })}
                placeholder="Ej: Tela Lino Premium" 
                required 
                disabled={loading}
                className="bg-slate-50 border-slate-200 focus:bg-white transition-all h-11"
              />
            </div>

            {/* Tipo y Unidad de Medida */}
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label className="text-[11px] uppercase font-bold text-slate-400">Tipo</Label>
                <Select 
                  value={formData.tipo} 
                  onValueChange={(value) => setFormData({ ...formData, tipo: value })}
                  disabled={loading}
                >
                  <SelectTrigger className="h-11 bg-slate-50 border-slate-200">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent className="max-h-60">
                    <SelectItem value="Tela">Tela</SelectItem>
                    <SelectItem value="Hilo">Hilo</SelectItem>
                    <SelectItem value="Avios">Avíos / Accesorios</SelectItem>
                    <SelectItem value="Embalaje">Embalaje</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label className="text-[11px] uppercase font-bold text-slate-400">U. Medida</Label>
                <Select 
                  value={formData.unidad_medida} 
                  onValueChange={(value) => setFormData({ ...formData, unidad_medida: value })}
                  disabled={loading}
                >
                  <SelectTrigger className="h-11 bg-slate-50 border-slate-200">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent className="max-h-60">
                    <SelectItem value="Metros">Metros</SelectItem>
                    <SelectItem value="Unidades">Unidades</SelectItem>
                    <SelectItem value="Conos">Conos</SelectItem>
                    <SelectItem value="Kg">Kilogramos</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>

            {/* Stock Actual y Mínimo */}
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label className="text-[11px] uppercase font-bold text-slate-400">Stock Inicial</Label>
                <Input 
                  type="number" 
                  step="0.01" 
                  min="0"
                  value={formData.stock_actual}
                  onChange={(e) => setFormData({ ...formData, stock_actual: e.target.value })}
                  placeholder="0.00"
                  required 
                  disabled={loading}
                  className="bg-slate-50 border-slate-200 focus:bg-white transition-all h-11"
                />
              </div>
              <div className="space-y-2">
                <Label className="text-[11px] uppercase font-bold text-slate-400">Stock Mínimo</Label>
                <Input 
                  type="number" 
                  step="0.01" 
                  min="0"
                  value={formData.stock_minimo}
                  onChange={(e) => setFormData({ ...formData, stock_minimo: e.target.value })}
                  placeholder="5.00"
                  disabled={loading}
                  className="bg-slate-50 border-slate-200 focus:bg-white transition-all h-11"
                />
              </div>
            </div>

            {/* Categoría */}
            <div className="space-y-2">
              <Label className="text-[11px] uppercase font-bold text-slate-400">Categoría Relacionada</Label>
