                ) : (
                  "Registrar Insumo"
                )}
              </Button>
            </DialogFooter>
          </form>
        </div>
      </DialogContent>
    </Dialog>
  );
}

"use client";
import { Loader2, X, CircleDollarSign, Package } from "lucide-react";
import { useState } from "react";
import { toast } from "sonner";
import { useInventario } from "@/lib/hooks/useInventario";

interface EditInsumoProps {
  isOpen: boolean;
  onClose: () => void;
  onSuccess: () => void;
  insumo: any; 
}

export default function EditInsumoDialog({ isOpen, onClose, onSuccess, insumo }: EditInsumoProps) {
  const [loading, setLoading] = useState(false);
  const { ajustarStock } = useInventario();

  const [operacion, setOperacion] = useState<"actualizar" | "descontar" | "incrementar">("incrementar");
  const [cantidad, setCantidad] = useState("");
  const [precioCompra, setPrecioCompra] = useState(""); // Nuevo estado para el precio

  if (!isOpen || !insumo) return null;

  const handleUpdate = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setLoading(true);

    try {
      const valorNumerico = Number(cantidad);
      const valorPrecio = precioCompra ? Number(precioCompra) : undefined;

      // Mapeo de operaciones para el hook que definimos antes
      const operacionMap: Record<string, "sumar" | "restar" | "absoluto"> = {
        incrementar: "sumar",
        descontar: "restar",
        actualizar: "absoluto"
      };

      const success = await ajustarStock({
        id: insumo.id,
        cantidad: operacion === "actualizar" ? Number((e.currentTarget.elements.namedItem("stock_actual") as HTMLInputElement).value) : valorNumerico,
        operacion: operacionMap[operacion],
        precio_unitario: valorPrecio, // Esto actualizará la ficha maestra
        costo_unitario: valorPrecio,  // Esto quedará en el historial de movimientos
        motivo: operacion === "incrementar" ? "Compra / Entrada de material" : "Ajuste manual"
      });

      if (success) {
        toast.success(`Inventario y precios actualizados`);
        onSuccess();
        onClose();
        setCantidad("");
        setPrecioCompra("");
      }
    } catch (error) {
      toast.error("Error al procesar el movimiento");
    } finally {
      setLoading(false);
    }
  };

  const nuevoStockCalculado = 
    operacion === "descontar" ? Math.max(0, insumo.stock_actual - (Number(cantidad) || 0)) :
    operacion === "incrementar" ? insumo.stock_actual + (Number(cantidad) || 0) :
    insumo.stock_actual;

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden border border-gray-100">
        {/* Header */}
        <div className="p-6 border-b border-gray-50 flex justify-between items-center bg-gray-50/50">
          <div>
            <h2 className="text-xl font-black text-gray-900 uppercase">Gestión de Stock</h2>
            <p className="text-xs text-pink-600 font-bold">{insumo.nombre}</p>
          </div>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600 transition-colors">
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleUpdate} className="p-6 space-y-4">
          {/* Selector de Operación */}
          <div className="flex gap-2 bg-gray-100 p-1 rounded-xl">
            {(["incrementar", "descontar", "actualizar"] as const).map((op) => (
              <button
                key={op}
                type="button"
                onClick={() => setOperacion(op)}
                className={`flex-1 py-2 rounded-lg text-[10px] font-black transition-all capitalize ${
                  operacion === op ? "bg-white text-pink-600 shadow-sm" : "text-gray-500"
                }`}
              >
                {op}
              </button>
            ))}
          </div>

          {/* Visualización de Cambio */}
          <div className="grid grid-cols-2 gap-3 bg-gray-50 p-3 rounded-xl border border-gray-100">
            <div className="text-center">
              <p className="text-[9px] font-bold text-gray-400 uppercase">Stock Actual</p>
              <p className="text-lg font-black text-gray-700">{insumo.stock_actual} <span className="text-[10px]">{insumo.unidad_medida}</span></p>
            </div>
            <div className={`text-center rounded-lg p-2 ${operacion === "descontar" ? "bg-red-50" : "bg-emerald-50"}`}>
              <p className="text-[9px] font-bold text-gray-400 uppercase">Proyectado</p>
              <p className={`text-lg font-black ${operacion === "descontar" ? "text-red-600" : "text-emerald-600"}`}>
                {nuevoStockCalculado}
              </p>
            </div>
          </div>

          {/* Inputs Dinámicos */}
          <div className="space-y-4">
            {operacion === "actualizar" ? (
              <div className="space-y-3">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest flex items-center gap-2">
                  <Package size={12} /> Ajuste de Inventario Físico
                </label>
                <input 
                  name="stock_actual" 
                  type="number" 
                  step="0.01" 
                  required
                  defaultValue={insumo.stock_actual} 
                  className="w-full border-gray-200 border p-3 rounded-xl focus:ring-2 focus:ring-pink-500 outline-none font-bold" 
                />
              </div>
            ) : (
              <div className="grid grid-cols-1 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Cantidad</label>
                  <input 
                    type="number" 
                    step="0.01" 
                    value={cantidad}
                    onChange={(e) => setCantidad(e.target.value)}
                    placeholder="0.00"
                    className="w-full border-gray-200 border p-3 rounded-xl focus:ring-2 focus:ring-pink-500 outline-none font-bold text-lg" 
                    required
                  />
                </div>

                {/* CAMPO CLAVE: Solo aparece en incremento (Compra) */}
                {operacion === "incrementar" && (
                  <div className="space-y-1 animate-in fade-in slide-in-from-top-2">
                    <label className="text-[10px] font-black text-pink-600 uppercase tracking-widest flex items-center gap-2">
                      <CircleDollarSign size={12} /> Nuevo Precio Unitario (S/.)
                    </label>
                    <input 
                      type="number" 
                      step="0.01" 
                      value={precioCompra}
                      onChange={(e) => setPrecioCompra(e.target.value)}
                      placeholder={insumo.precio_unitario?.toString() || "0.00"}
                      className="w-full border-pink-100 bg-pink-50/30 border p-3 rounded-xl focus:ring-2 focus:ring-pink-500 outline-none font-bold text-pink-700" 
                    />
                    <p className="text-[9px] text-gray-400 leading-tight">
                      * Al completar, se actualizará el costo en todas las fichas técnicas automáticamente.
                    </p>
                  </div>
                )}
              </div>
            )}
          </div>

          <div className="flex justify-end gap-3 pt-4">
            <button type="button" onClick={onClose} className="px-6 py-3 text-sm font-bold text-gray-400 hover:text-gray-600">
              Cerrar
            </button>
            <button 
              type="submit" 
              disabled={loading || (operacion !== "actualizar" && !cantidad)}
              className="bg-slate-900 hover:bg-slate-800 text-white px-8 py-3 rounded-xl font-black flex items-center gap-2 disabled:opacity-50 transition-all active:scale-95 shadow-xl"
            >
              {loading ? <Loader2 className="animate-spin" size={18} /> : "PROCESAR"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

'use client';

import { useState } from 'react';
import { useMateriales } from '@/lib/hooks/useMateriales';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {
  Dialog, DialogContent, DialogHeader,
  DialogTitle, DialogFooter,
} from '@/components/ui/dialog';
import {
  Select, SelectContent, SelectItem,
  SelectTrigger, SelectValue,
} from '@/components/ui/select';
import { Loader2 } from 'lucide-react';

interface Props {
  isOpen:    boolean;
  onClose:   () => void;
  onSuccess: () => void;
}

const UNIDADES = ['metros', 'kilos', 'yards', 'unidades'];
const TIPOS    = ['plano', 'punto', 'tejido', 'especial'];

export default function CreateMaterialDialog({ isOpen, onClose, onSuccess }: Props) {
  const { create, isCreating } = useMateriales();

  const [form, setForm] = useState({
    nombre:            '',
    tipo:              'plano',
    descripcion:       '',
    composicion:       '',
    gramaje:           '',
    ancho_total:       '',
    ancho_util:        '',
    color:             '',
    codigo_color:      '',
    unidad_medida:     'metros',
    stock_actual:      '0',
    stock_minimo:      '10',
    precio_unitario:   '',
    ubicacion_almacen: '',
    alerta_bajo_stock: true,
  });

  function set(field: string, value: any) {
    setForm(prev => ({ ...prev, [field]: value }));
  }

  async function handleSubmit() {
    if (!form.nombre.trim()) return;

    create({
      ...form,
      gramaje:         form.gramaje        ? Number(form.gramaje)        : undefined,
      ancho_total:     form.ancho_total     ? Number(form.ancho_total)     : undefined,
      ancho_util:      form.ancho_util      ? Number(form.ancho_util)      : undefined,
      stock_actual:    Number(form.stock_actual),
      stock_minimo:    Number(form.stock_minimo),
      precio_unitario: form.precio_unitario ? Number(form.precio_unitario) : undefined,
    });

    // useMateriales toast + invalidate ya se encarga del feedback
    onSuccess();
    handleClose();
  }

  function handleClose() {
    setForm({
      nombre: '', tipo: 'plano', descripcion: '', composicion: '',
      gramaje: '', ancho_total: '', ancho_util: '', color: '',
      codigo_color: '', unidad_medida: 'metros', stock_actual: '0',
      stock_minimo: '10', precio_unitario: '', ubicacion_almacen: '',
      alerta_bajo_stock: true,
    });
    onClose();
  }

  return (
    <Dialog open={isOpen} onOpenChange={handleClose}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="text-xl font-black text-gray-900">Registrar Material</DialogTitle>
          <p className="text-sm text-gray-500">Completa los datos del nuevo material o tela.</p>
        </DialogHeader>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 py-2">

          {/* Nombre */}
          <div className="md:col-span-2 space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Nombre *</Label>
            <Input
              placeholder="Ej: Tela algodón pima 120g"
              value={form.nombre}
              onChange={e => set('nombre', e.target.value)}
            />
          </div>

          {/* Tipo */}
          <div className="space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Tipo</Label>
            <Select value={form.tipo} onValueChange={v => set('tipo', v)}>
              <SelectTrigger><SelectValue /></SelectTrigger>
              <SelectContent>
                {TIPOS.map(t => <SelectItem key={t} value={t} className="capitalize">{t}</SelectItem>)}
              </SelectContent>
            </Select>
          </div>

          {/* Unidad */}
          <div className="space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Unidad de medida</Label>
            <Select value={form.unidad_medida} onValueChange={v => set('unidad_medida', v)}>
              <SelectTrigger><SelectValue /></SelectTrigger>
              <SelectContent>
                {UNIDADES.map(u => <SelectItem key={u} value={u} className="capitalize">{u}</SelectItem>)}
              </SelectContent>
            </Select>
          </div>

          {/* Composición */}
          <div className="space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Composición</Label>
            <Input placeholder="Ej: 100% algodón" value={form.composicion} onChange={e => set('composicion', e.target.value)} />
          </div>

          {/* Gramaje */}
          <div className="space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Gramaje (g/m²)</Label>
            <Input type="number" placeholder="Ej: 180" value={form.gramaje} onChange={e => set('gramaje', e.target.value)} />
          </div>

          {/* Ancho total */}
          <div className="space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Ancho total (m)</Label>
            <Input type="number" placeholder="Ej: 1.50" value={form.ancho_total} onChange={e => set('ancho_total', e.target.value)} />
          </div>

          {/* Ancho útil */}
          <div className="space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Ancho útil (m)</Label>
            <Input type="number" placeholder="Ej: 1.45" value={form.ancho_util} onChange={e => set('ancho_util', e.target.value)} />
          </div>

          {/* Color */}
          <div className="space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Color</Label>
            <Input placeholder="Ej: Blanco hueso" value={form.color} onChange={e => set('color', e.target.value)} />
          </div>

          {/* Código color */}
          <div className="space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Código de color (hex)</Label>
            <div className="flex gap-2 items-center">
              <Input
                placeholder="#FFFFFF"
                value={form.codigo_color}
                onChange={e => set('codigo_color', e.target.value)}
              />
              {form.codigo_color && (
                <div className="w-9 h-9 rounded-lg border shadow-sm flex-shrink-0" style={{ backgroundColor: form.codigo_color }} />
              )}
            </div>
          </div>

          {/* Stock actual */}
          <div className="space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Stock inicial</Label>
            <Input type="number" min={0} value={form.stock_actual} onChange={e => set('stock_actual', e.target.value)} />
          </div>

          {/* Stock mínimo */}
          <div className="space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Stock mínimo</Label>
            <Input type="number" min={0} value={form.stock_minimo} onChange={e => set('stock_minimo', e.target.value)} />
          </div>

          {/* Precio */}
          <div className="space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Precio unitario (S/)</Label>
            <Input type="number" min={0} step="0.01" placeholder="0.00" value={form.precio_unitario} onChange={e => set('precio_unitario', e.target.value)} />
          </div>

          {/* Ubicación */}
          <div className="space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Ubicación en almacén</Label>
            <Input placeholder="Ej: Estante A-3" value={form.ubicacion_almacen} onChange={e => set('ubicacion_almacen', e.target.value)} />
          </div>

          {/* Descripción */}
          <div className="md:col-span-2 space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Descripción</Label>
            <Input placeholder="Notas adicionales..." value={form.descripcion} onChange={e => set('descripcion', e.target.value)} />
          </div>

        </div>

        <DialogFooter className="gap-2 pt-2">
          <Button variant="outline" onClick={handleClose} disabled={isCreating}>
            Cancelar
          </Button>
          <Button
            onClick={handleSubmit}
            disabled={!form.nombre.trim() || isCreating}
            className="bg-pink-600 hover:bg-pink-700 text-white font-bold px-6"
          >
            {isCreating ? <><Loader2 className="w-4 h-4 mr-2 animate-spin" />Guardando...</> : 'Registrar Material'}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

'use client';

import { useMateriales } from '@/lib/hooks/useMateriales';
import { Button } from '@/components/ui/button';
import {
  Dialog, DialogContent, DialogHeader,
  DialogTitle, DialogFooter,
} from '@/components/ui/dialog';
import { ShieldOff, AlertTriangle, Loader2 } from 'lucide-react';
import { tienePermiso, type RolUsuario } from '@/lib/constants/roles';

interface Props {
  isOpen:     boolean;
  material:   any;
  onClose:    () => void;
  onSuccess:  () => void;
  rolUsuario: RolUsuario | null;
}

export default function DescontinuarMaterialDialog({
  isOpen, material, onClose, onSuccess, rolUsuario
}: Props) {
  const { remove, isDeleting } = useMateriales();

  if (!isOpen || !material) return null; 
  if (!rolUsuario || !tienePermiso(rolUsuario, 'descontinuar_materiales')) return null;

  async function handleDescontinuar() {
    try {
      await remove(String(material.id));
      onSuccess();
      onClose();
    } catch {
      // useMateriales maneja el toast de error internamente
    }
  }

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-md p-0 overflow-hidden border-none rounded-[28px] shadow-2xl bg-white">
        <div className="h-2 bg-amber-500 w-full" />

        <div className="p-8 space-y-6">
          <DialogHeader>
            <div className="flex items-center gap-3 mb-1">
              <div className="p-2 bg-amber-50 rounded-lg">
                <ShieldOff className="w-5 h-5 text-amber-600" />
              </div>
              <div>
                <DialogTitle className="text-lg font-black text-gray-900">
                  Descontinuar Material
                </DialogTitle>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em] mt-0.5">
                  El material quedará inactivo
                </p>
              </div>
            </div>
          </DialogHeader>

          <div className="space-y-3">
            <p className="text-sm text-gray-600">
              ¿Estás seguro de descontinuar{' '}
              <span className="font-bold text-amber-600">{material?.nombre}</span>?
            </p>
            <div className="bg-amber-50 border border-amber-100 rounded-xl p-3 space-y-1">
              {material?.stock_actual > 0 && (
                <p className="text-xs text-amber-700 font-semibold">
                  ⚠ Este material tiene{' '}
                  <strong>{material.stock_actual} {material.unidad_medida ?? 'm'}</strong> en stock.
                </p>
              )}
              <div className="flex gap-2 items-start">
                <AlertTriangle className="text-amber-500 shrink-0 mt-0.5" size={12} />
                <p className="text-[11px] text-amber-700 font-bold leading-tight italic">
                  Pasará a estado inactivo. Puedes reactivarlo en cualquier momento.
                </p>
              </div>
            </div>
          </div>

          <DialogFooter className="gap-2">
            <Button variant="outline" onClick={onClose} disabled={isDeleting}>
              Cancelar
            </Button>
            <Button
              onClick={handleDescontinuar}
              disabled={isDeleting}
              className="bg-amber-500 hover:bg-amber-600 text-white font-bold px-6 shadow-lg shadow-amber-100"
            >
              {isDeleting
                ? <><Loader2 className="w-4 h-4 mr-2 animate-spin" />Descontinuando...</>
                : 'Descontinuar'}
            </Button>
          </DialogFooter>
        </div>
      </DialogContent>
    </Dialog>
  );
}

'use client';

import { useEffect, useState } from 'react';
import { useMateriales } from '@/lib/hooks/useMateriales';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {
  Dialog, DialogContent, DialogHeader,
  DialogTitle, DialogFooter,
} from '@/components/ui/dialog';
import {
  Select, SelectContent, SelectItem,
  SelectTrigger, SelectValue,
} from '@/components/ui/select';
import { Loader2, Minus, Plus } from 'lucide-react';

interface Props {
  isOpen:    boolean;
  material:  any;
  onClose:   () => void;
  onSuccess: () => void;
}

const UNIDADES = ['metros', 'kilos', 'yards', 'unidades'];
const TIPOS    = ['plano', 'punto', 'tejido', 'especial'];

type StockOp = 'sumar' | 'restar' | 'absoluto';

export default function EditMaterialDialog({ isOpen, material, onClose, onSuccess }: Props) {
  const { update, isUpdating, ajustarStock, isAjustandoStock } = useMateriales();

  const [form, setForm] = useState({
    nombre:            '',
    tipo:              'plano',
    descripcion:       '',
    composicion:       '',
    gramaje:           '',
    ancho_total:       '',
    ancho_util:        '',
    color:             '',
    codigo_color:      '',
    unidad_medida:     'metros',
    stock_minimo:      '10',
    precio_unitario:   '',
    ubicacion_almacen: '',
    alerta_bajo_stock: true,
  });

  const [stockOp,       setStockOp]       = useState<StockOp>('sumar');
  const [stockCantidad, setStockCantidad] = useState('');
  const [stockMotivo,   setStockMotivo]   = useState('');

  // Hydrate form when material changes
  useEffect(() => {
    if (!material) return;
    setForm({
      nombre:            material.nombre            ?? '',
      tipo:              material.tipo              ?? 'plano',
      descripcion:       material.descripcion       ?? '',
      composicion:       material.composicion       ?? '',
      gramaje:           material.gramaje            != null ? String(material.gramaje)       : '',
      ancho_total:       material.ancho_total        != null ? String(material.ancho_total)   : '',
      ancho_util:        material.ancho_util         != null ? String(material.ancho_util)    : '',
      color:             material.color             ?? '',
      codigo_color:      material.codigo_color      ?? '',
      unidad_medida:     material.unidad_medida     ?? 'metros',
      stock_minimo:      String(material.stock_minimo ?? 10),
      precio_unitario:   material.precio_unitario    != null ? String(material.precio_unitario) : '',
      ubicacion_almacen: material.ubicacion_almacen ?? '',
      alerta_bajo_stock: material.alerta_bajo_stock ?? true,
    });
    setStockOp('sumar');
    setStockCantidad('');
    setStockMotivo('');
  }, [material]);

  function set(field: string, value: any) {
    setForm(prev => ({ ...prev, [field]: value }));
  }

  function handleSave() {
    update(String(material.id), {
      ...form,
      gramaje:         form.gramaje        ? Number(form.gramaje)        : null,
      ancho_total:     form.ancho_total     ? Number(form.ancho_total)     : null,
      ancho_util:      form.ancho_util      ? Number(form.ancho_util)      : null,
      stock_minimo:    Number(form.stock_minimo),
      precio_unitario: form.precio_unitario ? Number(form.precio_unitario) : null,
    });
    onSuccess();
    onClose();
  }

  function handleAjustarStock() {
    const cantidad = Number(stockCantidad);
    if (!cantidad || cantidad <= 0) return;
    ajustarStock(String(material.id), stockOp, cantidad, stockMotivo || undefined);
    setStockCantidad('');
    setStockMotivo('');
    onSuccess();
  }

  const isBusy = isUpdating || isAjustandoStock;

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="text-xl font-black text-gray-900">Editar Material</DialogTitle>
          <p className="text-sm text-gray-500">{material?.nombre}</p>
        </DialogHeader>

        {/* ── Ajuste rápido de stock ── */}
        <div className="bg-gray-50 border rounded-xl p-4 space-y-3">
          <p className="text-xs font-black uppercase tracking-wider text-gray-500">Ajuste de Stock</p>
          <div className="flex items-center gap-2">
            <span className="text-sm text-gray-500">Stock actual:</span>
            <span className="text-lg font-black text-gray-900">
              {material?.stock_actual} <span className="text-sm font-medium text-gray-400">{material?.unidad_medida ?? 'm'}</span>
            </span>
          </div>
          <div className="flex flex-col sm:flex-row gap-2">
            {/* Operación */}
            <div className="flex rounded-lg border bg-white overflow-hidden">
              {(['sumar', 'restar', 'absoluto'] as StockOp[]).map(op => (
                <button
                  key={op}
                  onClick={() => setStockOp(op)}
                  className={`px-3 py-2 text-xs font-bold capitalize transition-colors ${
                    stockOp === op ? 'bg-pink-600 text-white' : 'text-gray-500 hover:bg-gray-50'
                  }`}
                >
                  {op === 'sumar' ? <Plus className="w-3.5 h-3.5" /> : op === 'restar' ? <Minus className="w-3.5 h-3.5" /> : 'Abs'}
                </button>
              ))}
            </div>
            <Input
              type="number" min={0} placeholder="Cantidad"
              className="flex-1 h-9"
              value={stockCantidad}
              onChange={e => setStockCantidad(e.target.value)}
            />
            <Input
              placeholder="Motivo (opcional)"
              className="flex-1 h-9"
              value={stockMotivo}
              onChange={e => setStockMotivo(e.target.value)}
            />
            <Button
              size="sm"
              onClick={handleAjustarStock}
              disabled={!stockCantidad || Number(stockCantidad) <= 0 || isAjustandoStock}
              className="bg-pink-600 hover:bg-pink-700 text-white font-bold h-9 px-4 whitespace-nowrap"
            >
              {isAjustandoStock ? <Loader2 className="w-4 h-4 animate-spin" /> : 'Aplicar'}
            </Button>
          </div>
        </div>

        {/* ── Datos del material ── */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 py-2">

          <div className="md:col-span-2 space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Nombre *</Label>
            <Input value={form.nombre} onChange={e => set('nombre', e.target.value)} />
          </div>

          <div className="space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Tipo</Label>
            <Select value={form.tipo} onValueChange={v => set('tipo', v)}>
              <SelectTrigger><SelectValue /></SelectTrigger>
              <SelectContent>
                {TIPOS.map(t => <SelectItem key={t} value={t} className="capitalize">{t}</SelectItem>)}
              </SelectContent>
            </Select>
          </div>

          <div className="space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Unidad de medida</Label>
            <Select value={form.unidad_medida} onValueChange={v => set('unidad_medida', v)}>
              <SelectTrigger><SelectValue /></SelectTrigger>
              <SelectContent>
                {UNIDADES.map(u => <SelectItem key={u} value={u} className="capitalize">{u}</SelectItem>)}
              </SelectContent>
            </Select>
          </div>

          <div className="space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Composición</Label>
            <Input value={form.composicion} onChange={e => set('composicion', e.target.value)} />
          </div>

          <div className="space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Gramaje (g/m²)</Label>
            <Input type="number" value={form.gramaje} onChange={e => set('gramaje', e.target.value)} />
          </div>

          <div className="space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Ancho total (m)</Label>
            <Input type="number" value={form.ancho_total} onChange={e => set('ancho_total', e.target.value)} />
          </div>

          <div className="space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Ancho útil (m)</Label>
            <Input type="number" value={form.ancho_util} onChange={e => set('ancho_util', e.target.value)} />
          </div>

          <div className="space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Color</Label>
            <Input value={form.color} onChange={e => set('color', e.target.value)} />
          </div>

          <div className="space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Código de color (hex)</Label>
            <div className="flex gap-2 items-center">
              <Input value={form.codigo_color} onChange={e => set('codigo_color', e.target.value)} />
              {form.codigo_color && (
                <div className="w-9 h-9 rounded-lg border shadow-sm flex-shrink-0" style={{ backgroundColor: form.codigo_color }} />
              )}
            </div>
          </div>

          <div className="space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Stock mínimo</Label>
            <Input type="number" min={0} value={form.stock_minimo} onChange={e => set('stock_minimo', e.target.value)} />
          </div>

          <div className="space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Precio unitario (S/)</Label>
            <Input type="number" min={0} step="0.01" value={form.precio_unitario} onChange={e => set('precio_unitario', e.target.value)} />
          </div>

          <div className="space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Ubicación en almacén</Label>
            <Input value={form.ubicacion_almacen} onChange={e => set('ubicacion_almacen', e.target.value)} />
          </div>

          <div className="md:col-span-2 space-y-1.5">
            <Label className="font-bold text-xs uppercase tracking-wider text-gray-600">Descripción</Label>
            <Input value={form.descripcion} onChange={e => set('descripcion', e.target.value)} />
          </div>

        </div>

        <DialogFooter className="gap-2 pt-2">
          <Button variant="outline" onClick={onClose} disabled={isBusy}>Cancelar</Button>
          <Button
            onClick={handleSave}
            disabled={!form.nombre.trim() || isBusy}
            className="bg-pink-600 hover:bg-pink-700 text-white font-bold px-6"
          >
            {isUpdating ? <><Loader2 className="w-4 h-4 mr-2 animate-spin" />Guardando...</> : 'Guardar Cambios'}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

'use client';

import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import {
  Table, TableBody, TableCell, TableHead,
  TableHeader, TableRow,
} from '@/components/ui/table';
import { AlertTriangle, Edit3, Trash2, XCircle } from 'lucide-react';

interface Props {
  data:      any[];
  loading:   boolean;
  onEdit:    (item: any) => void;
  onDelete:  (item: any) => void;
  canEdit:   boolean;
  canDelete: boolean;
}

export default function MaterialesTable({ data, loading, onEdit, onDelete, canEdit, canDelete }: Props) {

  function stockBadge(m: any) {
    const actual  = Number(m.stock_actual);
    const minimo  = Number(m.stock_minimo);
    if (actual <= 0)       return <Badge className="bg-red-100 text-red-700 border-red-200 font-bold text-[10px]"><XCircle className="w-3 h-3 mr-1" />SIN STOCK</Badge>;
    if (actual <= minimo)  return <Badge className="bg-orange-100 text-orange-700 border-orange-200 font-bold text-[10px]"><AlertTriangle className="w-3 h-3 mr-1" />STOCK BAJO</Badge>;
    return <Badge className="bg-emerald-100 text-emerald-700 border-emerald-200 font-bold text-[10px]">ÓPTIMO</Badge>;
  }

  if (loading) return (
    <div className="h-64 flex flex-col items-center justify-center bg-white rounded-xl border animate-pulse">
      <div className="w-10 h-10 border-4 border-pink-500 border-t-transparent rounded-full animate-spin mb-4" />
      <p className="text-gray-400 text-sm font-bold uppercase tracking-widest">Cargando materiales...</p>
    </div>
  );

  if (data.length === 0) return (
    <div className="h-48 flex flex-col items-center justify-center bg-white rounded-xl border text-gray-400">
      <XCircle className="w-10 h-10 mb-2 opacity-30" />
      <p className="font-bold text-sm uppercase tracking-widest">Sin resultados</p>
    </div>
  );

  return (
    <div className="bg-white rounded-xl border shadow-sm overflow-hidden">
      <Table>
        <TableHeader>
          <TableRow className="bg-gray-50 border-b">
            <TableHead className="font-black text-[11px] uppercase tracking-wider text-gray-500 py-3">Material / Composición</TableHead>
            <TableHead className="font-black text-[11px] uppercase tracking-wider text-gray-500">Tipo</TableHead>
            <TableHead className="font-black text-[11px] uppercase tracking-wider text-gray-500">Color</TableHead>
            <TableHead className="font-black text-[11px] uppercase tracking-wider text-gray-500">Gramaje</TableHead>
            <TableHead className="font-black text-[11px] uppercase tracking-wider text-gray-500 text-right">Stock Actual</TableHead>
            <TableHead className="font-black text-[11px] uppercase tracking-wider text-gray-500 text-right">Precio Est.</TableHead>
            <TableHead className="font-black text-[11px] uppercase tracking-wider text-gray-500 text-center">Estado</TableHead>
            {(canEdit || canDelete) && (
              <TableHead className="font-black text-[11px] uppercase tracking-wider text-gray-500 text-center">Acciones</TableHead>
            )}
          </TableRow>
        </TableHeader>
        <TableBody>
          {data.map((m: any) => (
            <TableRow key={m.id} className="hover:bg-gray-50 transition-colors border-b last:border-0">

              {/* Nombre + composición */}
              <TableCell className="py-3">
                <div className="font-bold text-gray-900 text-sm">{m.nombre}</div>
                {m.composicion && (
                  <div className="text-xs text-gray-400 mt-0.5">{m.composicion}</div>
                )}
                {m.proveedor && (
                  <div className="text-[10px] text-pink-500 font-semibold mt-0.5">
                    {m.proveedor.razon_social ?? m.proveedor}
                  </div>
                )}
              </TableCell>

              {/* Tipo */}
              <TableCell>
                <span className="capitalize text-sm text-gray-700 font-medium">{m.tipo ?? '—'}</span>
              </TableCell>

              {/* Color */}
              <TableCell>
                <div className="flex items-center gap-2">
                  {m.codigo_color && (
                    <div
                      className="w-4 h-4 rounded-full border border-gray-200 shadow-sm flex-shrink-0"
                      style={{ backgroundColor: m.codigo_color }}
                    />
                  )}
                  <span className="text-sm text-gray-700">{m.color || '—'}</span>
                </div>
              </TableCell>

              {/* Gramaje */}
              <TableCell>
                <span className="text-sm text-gray-700">
                  {m.gramaje ? `${m.gramaje} g/m²` : '—'}
                </span>
              </TableCell>

              {/* Stock */}
              <TableCell className="text-right">
                <span className={`text-sm font-bold ${Number(m.stock_actual) <= Number(m.stock_minimo) ? 'text-red-600' : 'text-gray-900'}`}>
                  {m.stock_actual}
                </span>
                <span className="text-xs text-gray-400 ml-1">{m.unidad_medida ?? 'm'}</span>
              </TableCell>

              {/* Precio */}
              <TableCell className="text-right">
                <span className="text-sm font-bold text-gray-900">
                  S/ {Number(m.precio_unitario ?? 0).toFixed(2)}
                </span>
              </TableCell>

              {/* Estado */}
              <TableCell className="text-center">
                {stockBadge(m)}
              </TableCell>

              {/* Acciones */}
              {(canEdit || canDelete) && (
                <TableCell className="text-center">
                  <div className="flex items-center justify-center gap-1">
                    {canEdit && (
                      <Button
                        variant="ghost" size="icon"
                        className="h-8 w-8 hover:bg-blue-50 hover:text-blue-600 transition-colors"
                        onClick={() => onEdit(m)}
                      >
                        <Edit3 className="w-4 h-4" />
                      </Button>
                    )}
                    {canDelete && (
                      <Button
                        variant="ghost" size="icon"
                        className="h-8 w-8 hover:bg-red-50 hover:text-red-600 transition-colors"
                        onClick={() => onDelete(m)}
                      >
                        <Trash2 className="w-4 h-4" />
                      </Button>
                    )}
                  </div>
                </TableCell>
              )}
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </div>
  );
}

'use client';

import { ChevronRight, Home, User, LogOut, Menu as MenuIcon } from "lucide-react";
import { usePathname } from "next/navigation";
import Link from "next/link";
import { useState } from "react";
import { cn } from "@/lib/utils";
import type { usuarios, personal_interno, clientes } from "@prisma/client";
import { NotificationDropdown } from "./NotificationDropdown";
import { getSupabaseBrowserClient } from "@/lib/supabase";

// El nombre_completo ya no está en usuarios — viene de personal_interno o clientes
interface AdminHeaderProps {
  usuario: usuarios & {
    personal_interno?: Pick<personal_interno, 'nombre_completo'>[];
    clientes?:         Pick<clientes, 'razon_social'>[];
  };
}

export default function AdminHeader({ usuario }: AdminHeaderProps) {
  const pathname = usePathname();
  const supabase = getSupabaseBrowserClient();
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);

  // Resolver el nombre a mostrar: personal_interno > clientes.razon_social > email
  const nombreDisplay =
    usuario.personal_interno?.[0]?.nombre_completo ??
    usuario.clientes?.[0]?.razon_social             ??
    usuario.email;

  const generateBreadcrumbs = () => {
    const paths = pathname.split('/').filter(path => path && path !== 'admin' && path !== 'Panel-Administrativo');
    return paths.map((path, index) => {
      const label  = path.replace(/-/g, ' ').replace(/_/g, ' ');
      const isLast = index === paths.length - 1;
      return (
        <div key={path} className="flex items-center">
          <ChevronRight className="w-4 h-4 text-gray-400 mx-1 shrink-0" />
          <span className={`text-sm font-medium capitalize ${isLast ? "text-rose-600 font-semibold" : "text-gray-500"}`}>
            {label}
          </span>
        </div>
      );
    });
  };

  const handleLogout = async () => {
    try {
      await supabase.auth.signOut();
      window.location.href = '/';
    } catch (error) {
      console.error('Error al salir de GUOR Corp:', error);
    }
  };

  return (
    <header className="admin-topbar sticky top-0 z-30 flex h-16 items-center gap-4 border-b bg-white/80 backdrop-blur-md px-4 lg:px-8 shadow-sm">
      <div className="flex flex-1 items-center justify-between">

        {/* Breadcrumbs */}
        <div className="flex items-center gap-2">
          <div className="w-10 lg:hidden" />
          <nav className="hidden md:flex items-center text-gray-500">
            <Link href="/admin/Panel-Administrativo/dashboard" className="hover:text-rose-500 transition-colors">
              <Home className="w-4 h-4" />
            </Link>
            {generateBreadcrumbs()}
          </nav>
        </div>

        {/* Usuario */}
        <div className="flex items-center gap-2 sm:gap-4">
          <NotificationDropdown />
          <div className="h-8 w-px bg-gray-200 mx-1 hidden sm:block" />

          {/* User Menu Dropdown */}
          <div className="relative">
            <button
              onClick={() => setIsUserMenuOpen(!isUserMenuOpen)}
              className="admin-user-link group flex items-center gap-3 p-1 pr-2 rounded-xl transition-all duration-200 hover:bg-amber-50 cursor-pointer"
            >
              <div className="hidden sm:flex flex-col items-end transition-transform group-hover:-translate-x-1">
                <span className="admin-user-name text-sm font-bold text-gray-800 leading-none group-hover:text-black transition-colors">
                  {nombreDisplay}
                </span>
                <span className="admin-user-role text-[10px] font-medium text-gray-400 uppercase tracking-tighter group-hover:text-black/70 transition-colors">
                  {usuario.rol?.replace('_', ' ')}
                </span>
              </div>

              <div className="admin-user-avatar relative w-9 h-9 rounded-xl bg-gradient-to-br from-rose-500 to-rose-600 overflow-hidden shadow-md flex items-center justify-center">
                <User className="w-4 h-4 text-white" />
                <div className="absolute -bottom-0.5 -right-0.5 w-2.5 h-2.5 bg-emerald-500 border-2 border-white rounded-full" />
              </div>
            </button>

            {/* Dropdown Menu */}
            {isUserMenuOpen && (
              <div className="absolute right-0 mt-2 w-48 bg-white rounded-xl shadow-xl border border-gray-200 overflow-hidden animate-in fade-in zoom-in-95 duration-200">
                <Link
                  href="/admin/Panel-Administrativo/perfil"
                  onClick={() => setIsUserMenuOpen(false)}
                  className="flex items-center gap-3 px-4 py-3 text-sm font-medium text-gray-700 hover:bg-rose-50 hover:text-rose-700 transition-colors border-b border-gray-100"
                >
                  <User size={16} />
                  Mi Perfil
                </Link>

                <button
                  onClick={() => {
                    setIsUserMenuOpen(false);
                    handleLogout();
                  }}
                  className="flex items-center gap-3 w-full px-4 py-3 text-sm font-medium text-gray-700 hover:bg-red-50 hover:text-red-700 transition-colors"
                >
                  <LogOut size={16} />
                  Cerrar Sesión
                </button>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Overlay para cerrar dropdown */}
      {isUserMenuOpen && (
        <div
          className="fixed inset-0 z-20"
          onClick={() => setIsUserMenuOpen(false)}
          aria-hidden
        />
      )}
    </header>
  );
}

"use client";

import React from "react";
import { Button } from "@/components/ui/button";
import { FileSpreadsheet, FileText } from "lucide-react";
import { toast } from "sonner";
import { format } from "date-fns";
import { es } from "date-fns/locale";
import type { Movimiento } from "./MovimientosTable";

interface ExportarMovimientosProps {
  movimientos: Movimiento[];
  titulo?: string;
}

export function ExportarMovimientos({
  movimientos,
  titulo = "Movimientos de Inventario",
}: ExportarMovimientosProps) {
  const exportarExcel = async () => {
    try {
      const ExcelJS = (await import("exceljs")).default;
      const workbook = new ExcelJS.Workbook();
      const worksheet = workbook.addWorksheet("Movimientos");

      // Encabezado
      worksheet.columns = [
        { header: "Fecha", key: "fecha", width: 18 },
        { header: "Tipo", key: "tipo", width: 12 },
        { header: "Artículo", key: "articulo", width: 25 },
        { header: "Cantidad", key: "cantidad", width: 12 },
        { header: "Unidad", key: "unidad", width: 12 },
        { header: "Stock Anterior", key: "stock_anterior", width: 15 },
        { header: "Stock Posterior", key: "stock_posterior", width: 15 },
        { header: "Costo Unitario", key: "costo", width: 15 },
        { header: "Referencia", key: "referencia", width: 12 },
        { header: "Motivo", key: "motivo", width: 30 },
        { header: "Usuario", key: "usuario", width: 20 },
      ];

      // Estilos de encabezado
      worksheet.getRow(1).font = { bold: true, color: { argb: "FFFFFFFF" } };
      worksheet.getRow(1).fill = {
        type: "pattern",
        pattern: "solid",
        fgColor: { argb: "FF4472C4" },
      };

      // Datos
      movimientos.forEach((mov) => {
        const tipoLabel =
          mov.tipo_movimiento === "entrada"
            ? "Entrada"
            : mov.tipo_movimiento === "salida"
              ? "Salida"
              : "Ajuste";

        const itemName =
          mov.producto?.nombre ||
          mov.insumo?.nombre ||
          mov.material?.nombre ||
          "Desconocido";

        const unidad = mov.insumo?.unidad_medida || "unidades";

        const referencia = mov.referencia_tipo || "";

        worksheet.addRow({
          fecha: format(new Date(mov.created_at), "dd/MM/yyyy HH:mm", {
            locale: es,
          }),
          tipo: tipoLabel,
          articulo: itemName,
          cantidad: mov.cantidad,
          unidad,
          stock_anterior: 
            mov.stock_anterior != null 
              ? mov.stock_anterior.toFixed(2) 
              : "-",
          stock_posterior:
            mov.stock_posterior != null
              ? mov.stock_posterior.toFixed(2)
              : "-",
          costo: mov.costo_unitario
            ? `$${mov.costo_unitario.toFixed(2)}`
            : "-",
          referencia,
          motivo: mov.motivo || "-",
          usuario: mov.usuario?.nombre || "Sistema",
        });
      });

      // Autoajustar ancho de columnas
      worksheet.columns.forEach((column) => {
        let maxLength = 0;
        column.eachCell?.({ includeEmpty: true }, (cell) => {
          const cellLength = cell.value ? String(cell.value).length : 0;
          if (cellLength > maxLength) {
            maxLength = cellLength;
          }
        });
        column.width = Math.min(maxLength + 2, 50);
      });

      // Descargar
      const buffer = await workbook.xlsx.writeBuffer();
      const blob = new Blob([buffer], {
        type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
      });
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = url;
      link.download = `${titulo}-${format(new Date(), "yyyy-MM-dd")}.xlsx`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);

      toast.success("Excel exportado exitosamente");
    } catch (error: any) {
      console.error("Error exportando Excel:", error);
      toast.error("Error al exportar Excel");
    }
  };

  const exportarPDF = async () => {
    try {
      const jsPDF = (await import("jspdf")).default;
      await import("jspdf-autotable");

      const doc = new jsPDF();
      const pageWidth = doc.internal.pageSize.getWidth();

      // Título
      doc.setFontSize(16);
      doc.text(titulo, pageWidth / 2, 15, { align: "center" });

      // Fecha de descarga
      doc.setFontSize(10);
      doc.text(
        `Generado: ${format(new Date(), "dd/MM/yyyy HH:mm", { locale: es })}`,
        pageWidth / 2,
        22,
        { align: "center" }
      );

      // Tabla
      const tableData = movimientos.map((mov) => {
        const tipoLabel =
          mov.tipo_movimiento === "entrada"
            ? "Entrada"
            : mov.tipo_movimiento === "salida"
              ? "Salida"
              : "Ajuste";

        const itemName =
          mov.producto?.nombre ||
          mov.insumo?.nombre ||
          mov.material?.nombre ||
          "Desconocido";

        return [
          format(new Date(mov.created_at), "dd/MM/yyyy", { locale: es }),
          tipoLabel,
          itemName.substring(0, 15),
          mov.cantidad.toString(),
          mov.stock_anterior?.toFixed(1) || "-",
          mov.stock_posterior?.toFixed(1) || "-",
          mov.referencia_tipo || "",
          (mov.motivo || "-").substring(0, 15),
        ];
      });

      const table = (doc as any).autoTable({
        head: [
          [
            "Fecha",
            "Tipo",
            "Artículo",
            "Cantidad",
            "Stock Ant.",
            "Stock Post.",
            "Ref.",
            "Motivo",
          ],
        ],
        body: tableData,
        startY: 28,
        margin: 10,
        headStyles: {
          fillColor: [68, 114, 196],
          textColor: [255, 255, 255],
          fontStyle: "bold",
          halign: "center",
        },
        alternateRowStyles: {
          fillColor: [242, 242, 242],
        },
        columnStyles: {
          0: { cellWidth: 18 },
          1: { cellWidth: 15 },
          2: { cellWidth: 25 },
          3: { cellWidth: 15, halign: "right" },
          4: { cellWidth: 15, halign: "right" },
          5: { cellWidth: 15, halign: "right" },
          6: { cellWidth: 12 },
          7: { cellWidth: 25 },
        },
      });

      doc.save(
        `${titulo.replace(/\s+/g, "-")}-${format(new Date(), "yyyy-MM-dd")}.pdf`
      );
      toast.success("PDF exportado exitosamente");
    } catch (error: any) {
      console.error("Error exportando PDF:", error);
      toast.error("Error al exportar PDF");
    }
  };

  return (
    <div className="flex gap-2">
      <Button
        variant="outline"
        size="sm"
        onClick={exportarExcel}
        className="gap-2"
      >
        <FileSpreadsheet className="w-4 h-4" />
        Excel
      </Button>
      <Button
        variant="outline"
        size="sm"
        onClick={exportarPDF}
        className="gap-2"
      >
        <FileText className="w-4 h-4" />
        PDF
      </Button>
    </div>
  );
}

