                  </TableCell>
                  <TableCell className="py-4 px-5">
                    <TooltipProvider>
                      <Tooltip>
                        <TooltipTrigger asChild>
                          <div className="flex items-center gap-2 cursor-help">
                            <div className="p-1.5 bg-slate-100 rounded-lg text-slate-500">
                              <ItemIcon className="w-3.5 h-3.5" />
