'use client';

import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { useForm, useFieldArray } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { Loader2, Save, ArrowLeft, Plus, Trash2 } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import { toast } from 'sonner';
import { fetchProveedores } from '@/lib/helpers/proveedores-helpers';
import { fetchMateriales } from '@/lib/helpers/materiales-helpers';
import { fetchInsumos } from '@/lib/helpers/inventario-helpers';
import { useOrdenesCompra } from '@/lib/hooks/useOrdenesCompra';

// ─────────────────────────────────────────────────────────────
// ESQUEMAS DE VALIDACIÓN CORREGIDOS
// ─────────────────────────────────────────────────────────────
const itemFormSchema = z.object({
  tipo: z.enum(['material', 'insumo']),
  ref_id: z.string().min(1, 'Seleccione un ítem'), 
  cantidad_pedida: z.number({ message: 'Cantidad inválida' }).positive('Cantidad inválida'),
  precio_unitario: z.number({ message: 'Precio inválido' }).nonnegative('Precio inválido'),
  notas: z.string().optional(), 
});

const formSchema = z.object({
  proveedor_id: z.string().min(1, 'Seleccione un proveedor'),
  fecha_prometida: z.string().optional(),
  notas: z.string().optional(),
  items: z.array(itemFormSchema).min(1, 'Agregue al menos un ítem'),
});

type FormValues = z.infer<typeof formSchema>; 

interface Props {
  cotizacionId?: string | null; 
  proveedorIdPreselect?: string | null; 
  modoCotizacion?: boolean; 
}

export function OrdenCompraForm({
  cotizacionId, 
  proveedorIdPreselect, 
  modoCotizacion = false, 
}: Props) {
  const router = useRouter(); 
  const { crear, crearDesdeCotizacion, isCreating } = useOrdenesCompra({ enabled: false }); 

  const [proveedores, setProveedores] = useState<{ id: string; razon_social: string }[]>([]);
  const [materiales, setMateriales] = useState<{ id: number; nombre: string }[]>([]);
  const [insumos, setInsumos] = useState<{ id: number; nombre: string }[]>([]); 
  const [loadingCatalogos, setLoadingCatalogos] = useState(true); 

  const form = useForm<FormValues>({
    resolver: zodResolver(formSchema), 
    defaultValues: {
      proveedor_id: proveedorIdPreselect ?? '', 
      fecha_prometida: '', 
      notas: '', 
      items: [ 
        { tipo: 'insumo', ref_id: '', cantidad_pedida: 1, precio_unitario: 0, notas: '' }, 
      ], 
    },
  });

  const { fields, append, remove } = useFieldArray({ control: form.control, name: 'items' });
  const watchedItems = form.watch('items');

  useEffect(() => {
    async function load() {
      try {
        const [provRes, mats, insRes] = await Promise.all([
          fetchProveedores(1, 200, '', 'activo'), 
          fetchMateriales(), 
          fetchInsumos(), 
        ]);
        const provList = provRes.data ?? []; 
        setProveedores(
          provList.map((p: { id: string | number; razon_social: string }) => ({ 
            id: String(p.id), 
            razon_social: p.razon_social, 
          })),
        );
        setMateriales(mats.map((m: { id: number; nombre: string }) => ({ id: m.id, nombre: m.nombre }))); 
        setInsumos(
          (insRes.insumos ?? []).map((i: { id: number; nombre: string }) => ({ 
            id: i.id, 
            nombre: i.nombre, 
          })),
        );
      } catch {
        toast.error('Error al cargar catálogos'); 
      } finally {
        setLoadingCatalogos(false); 
      }
    }
    load(); 
  }, []);

  const subtotal = watchedItems.reduce(
    (acc, item) => acc + (item.cantidad_pedida || 0) * (item.precio_unitario || 0), 
    0, 
  );

  const onSubmit = async (data: FormValues) => {
    try {
      if (modoCotizacion && cotizacionId) { 
        const res = await crearDesdeCotizacion({
          cotizacion_proveedor_id: Number(cotizacionId), 
          fecha_prometida: data.fecha_prometida ? new Date(data.fecha_prometida) : null, 
          notas: data.notas || null, 
        });
        if (!res.success) throw new Error(res.error || 'Error al generar orden'); 
        router.push(
          `/admin/Panel-Administrativo/ordenes-compra/${(res.data as { id: number }).id}`,
        );
        return;
      }

      const items = data.items.map((item) => ({
        material_id: item.tipo === 'material' ? Number(item.ref_id) : null, 
        insumo_id: item.tipo === 'insumo' ? Number(item.ref_id) : null, 
        cantidad_pedida: item.cantidad_pedida, 
        precio_unitario: item.precio_unitario, 
        notas: item.notas || null, 
      }));

      const res = await crear({
        proveedor_id: Number(data.proveedor_id), 
        cotizacion_proveedor_id: cotizacionId ? Number(cotizacionId) : null, 
        fecha_prometida: data.fecha_prometida ? new Date(data.fecha_prometida) : null, 
        notas: data.notas || null, 
        items, 
      });
      if (!res.success) throw new Error(res.error || 'Error al crear orden'); 
      router.push(
        `/admin/Panel-Administrativo/ordenes-compra/${(res.data as { id: number }).id}`, 
      );
    } catch (e: unknown) {
      toast.error(e instanceof Error ? e.message : 'Error al guardar'); 
    }
  };

  if (loadingCatalogos) {
    return (
      <div className="flex justify-center py-20">
        <Loader2 className="w-8 h-8 animate-spin text-rose-500" />
      </div>
    );
  }

  return (
    <Form {...form}>
      <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-8 max-w-4xl">
        <div className="flex items-center gap-3">
          <Button
            type="button"
            variant="ghost"
            size="sm"
            onClick={() => router.back()}
          >
            <ArrowLeft className="w-4 h-4 mr-1" /> Volver 
          </Button>
        </div>

        {modoCotizacion && cotizacionId && (
          <div className="p-4 rounded-2xl bg-blue-50 border border-blue-100 text-sm text-blue-800">
            Generando orden desde cotización <strong>#{cotizacionId}</strong>. Los ítems se
            copiarán automáticamente al confirmar. 
          </div>
        )}

        <div className="bg-white rounded-3xl shadow-xl border border-slate-100 p-8 space-y-6">
          <h2 className="text-xl font-black text-slate-900 uppercase tracking-tight">
            Datos generales
          </h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <FormField
              control={form.control} 
              name="proveedor_id"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Proveedor *</FormLabel>
                  <Select
                    value={field.value} 
                    onValueChange={field.onChange} 
                    disabled={modoCotizacion} 
                  >
                    <FormControl>
                      <SelectTrigger> 
                        <SelectValue placeholder="Seleccionar proveedor" /> 
                      </SelectTrigger> 
                    </FormControl>
                    <SelectContent> 
                      {proveedores.map((p) => (
                        <SelectItem key={p.id} value={p.id}> 
                          {p.razon_social} 
                        </SelectItem> 
                      ))}
                    </SelectContent>
                  </Select>
                  <FormMessage />
                </FormItem>
              )}
            />

            <FormField
              control={form.control}
              name="fecha_prometida"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Fecha prometida</FormLabel> 
                  <FormControl>
                    <Input type="date" {...field} /> 
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />
          </div>

          <FormField
            control={form.control}
            name="notas"
            render={({ field }) => (
              <FormItem> 
                <FormLabel>Notas</FormLabel> 
                <FormControl>
                  <Textarea rows={3} placeholder="Observaciones..." {...field} /> 
                </FormControl>
                <FormMessage />
              </FormItem> 
            )}
          />
        </div>

        {!modoCotizacion && (
          <div className="bg-white rounded-3xl shadow-xl border border-slate-100 p-8 space-y-6">
            <div className="flex items-center justify-between">
              <h2 className="text-xl font-black text-slate-900 uppercase tracking-tight"> 
                Ítems
              </h2>
              <Button
                type="button"
                variant="outline"
                size="sm"
                onClick={() =>
                  append({ 
                    tipo: 'insumo', 
                    ref_id: '', 
                    cantidad_pedida: 1, 
                    precio_unitario: 0, 
                    notas: '', 
                  })
                }
              >
                <Plus className="w-4 h-4 mr-1" /> Agregar 
              </Button>
            </div>

            {fields.map((field, index) => {
              const tipo = form.watch(`items.${index}.tipo`); 
              const opciones = tipo === 'material' ? materiales : insumos; 
              return (
                <div
                  key={field.id}
                  className="grid grid-cols-1 md:grid-cols-12 gap-3 p-4 rounded-2xl bg-slate-50 border border-slate-100"
                >
                  <FormField
                    control={form.control} 
                    name={`items.${index}.tipo`}
                    render={({ field: f }) => (
                      <FormItem className="md:col-span-2">
                        <FormLabel>Tipo</FormLabel> 
                        <Select value={f.value} onValueChange={f.onChange}> 
                          <FormControl>
                            <SelectTrigger> 
                              <SelectValue /> 
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            <SelectItem value="material">Material</SelectItem> 
                            <SelectItem value="insumo">Insumo</SelectItem> 
                          </SelectContent>
                        </Select>
                      </FormItem>
                    )}
                  />
                  <FormField
                    control={form.control} 
                    name={`items.${index}.ref_id`}
                    render={({ field: f }) => (
                      <FormItem className="md:col-span-4">
                        <FormLabel>Producto</FormLabel>
                        <Select value={f.value} onValueChange={f.onChange}> 
                          <FormControl>
                            <SelectTrigger> 
                              <SelectValue placeholder="Seleccionar" /> 
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            {opciones.map((o) => ( 
                              <SelectItem key={o.id} value={String(o.id)}> 
                                {o.nombre} 
                              </SelectItem> 
                            ))}
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  {/* CANTIDAD CONTROLADA CONTRA NaN */}
                  <FormField
                    control={form.control} 
                    name={`items.${index}.cantidad_pedida`}
                    render={({ field: f }) => (
                      <FormItem className="md:col-span-2">
                        <FormLabel>Cantidad</FormLabel> 
                        <FormControl>
                          <Input
                            type="number"
                            step="0.01" 
                            min="0" 
                            {...f}
                            value={Number.isNaN(f.value) ? '' : f.value}
                            onChange={(e) => f.onChange(e.target.valueAsNumber)}
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  {/* PRECIO UNITARIO CONTROLADO CONTRA NaN */}
                  <FormField
                    control={form.control}
                    name={`items.${index}.precio_unitario`}
                    render={({ field: f }) => (
                      <FormItem className="md:col-span-2">
                        <FormLabel>P. unit.</FormLabel> 
                        <FormControl>
                          <Input
                            type="number"
                            step="0.01" 
                            min="0" 
                            {...f}
                            value={Number.isNaN(f.value) ? '' : f.value}
                            onChange={(e) => f.onChange(e.target.valueAsNumber)}
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <div className="md:col-span-2 flex items-end">
                    <Button
                      type="button"
                      variant="ghost"
                      size="sm" 
                      className="text-red-500" 
                      onClick={() => remove(index)} 
                      disabled={fields.length <= 1} 
                    >
                      <Trash2 className="w-4 h-4" /> 
                    </Button>
                  </div>
                </div>
              );
            })}

            <p className="text-right text-lg font-black text-slate-900">
              Total: S/ {subtotal.toLocaleString('es-PE', { minimumFractionDigits: 2 })} 
            </p>
          </div>
        )}

        <div className="flex justify-end gap-3">
          <Button type="button" variant="outline" onClick={() => router.back()}>
            Cancelar 
          </Button>
          <Button type="submit" disabled={isCreating} className="bg-rose-600 hover:bg-rose-700"> 
            {isCreating ? ( 
              <Loader2 className="w-4 h-4 animate-spin mr-2" /> 
            ) : (
              <Save className="w-4 h-4 mr-2" /> 
            )}
            {modoCotizacion ? 'Generar orden de compra' : 'Crear orden de compra'} 
          </Button>
        </div>
      </form>
    </Form>
  );
}

'use client';

import { useState } from 'react';
import { FileText, RefreshCw, Download, ExternalLink } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { toast } from 'sonner';

interface Props {
  ordenId: string | number;
  pdfUrl?: string | null;
  onRegenerated?: () => void;
}

export function OrdenCompraDocumentoTab({ ordenId, pdfUrl, onRegenerated }: Props) {
  const [regenerating, setRegenerating] = useState(false);
  const [url, setUrl] = useState(pdfUrl ?? '');

  const handleRegenerar = async () => {
    setRegenerating(true);
    try {
      const res = await fetch(`/api/admin/ordenes-compra/${ordenId}/documento`, {
        method: 'POST',
      });
      const json = await res.json();
      if (!res.ok) throw new Error(json.error || 'Error al generar documento');
      setUrl(`${json.data.pdf_url}?t=${Date.now()}`);
      toast.success('Documento actualizado');
      onRegenerated?.();
    } catch (e: unknown) {
      toast.error(e instanceof Error ? e.message : 'Error');
    } finally {
      setRegenerating(false);
    }
  };

  const displayUrl = url || pdfUrl;

  return (
    <div className="space-y-4">
      <div className="flex flex-wrap items-center justify-between gap-3 rounded-2xl border border-amber-100 bg-gradient-to-r from-amber-50/60 to-white p-4">
        <div className="flex items-center gap-3">
          <div className="p-2.5 rounded-xl bg-amber-600 text-white">
            <FileText className="w-5 h-5" />
          </div>
          <div>
            <h3 className="font-bold text-slate-900">Documento PDF</h3>
            <p className="text-xs text-slate-500">
              Orden de compra oficial — estilo corporativo GUOR
            </p>
          </div>
        </div>
        <div className="flex gap-2">
          <Button
            variant="outline"
            size="sm"
            className="rounded-xl"
            onClick={handleRegenerar}
            disabled={regenerating}
          >
            <RefreshCw className={`w-4 h-4 mr-1 ${regenerating ? 'animate-spin' : ''}`} />
            Regenerar
          </Button>
          {displayUrl && (
            <>
              <Button
                type="button"
                variant="outline"
                size="sm"
                className="rounded-xl"
                onClick={() => window.open(displayUrl, '_blank', 'noopener,noreferrer')}
              >
                <ExternalLink className="w-4 h-4 mr-1" />
                Abrir
              </Button>
              <Button
                type="button"
                size="sm"
                className="rounded-xl bg-amber-700 hover:bg-amber-800"
                onClick={() => {
                  const link = document.createElement('a');
                  link.href = displayUrl;
                  link.download = `orden-compra-${ordenId}.pdf`;
                  link.rel = 'noopener noreferrer';
                  link.click();
                }}
              >
                <Download className="w-4 h-4 mr-1" />
                Descargar
              </Button>
            </>
          )}
        </div>
      </div>

      {displayUrl ? (
        <div className="rounded-2xl border border-slate-200 bg-slate-100 overflow-hidden shadow-inner min-h-[70vh]">
          <iframe
            title="Orden de compra PDF"
            src={`${displayUrl}${displayUrl.includes('?') ? '&' : '?'}t=${Date.now()}`}
            className="w-full h-[75vh] bg-white"
          />
        </div>
      ) : (
        <div className="rounded-2xl border border-dashed border-amber-200 bg-amber-50/30 p-16 text-center">
          <FileText className="w-12 h-12 text-amber-300 mx-auto mb-3" />
          <p className="text-slate-600 mb-4">No hay documento disponible aún.</p>
          <Button onClick={handleRegenerar} disabled={regenerating}>
            Generar documento PDF
          </Button>
        </div>
      )}
    </div>
  );
}

