                                : <XCircle className="w-4 h-4" />}
                            {val.charAt(0).toUpperCase() + val.slice(1)}
                        </button>
                    ))}
                </div>
            </div>

            {/* Fecha entrega al cortador */}
            <div>
                <FieldLabel>Fecha de entrega al cortador</FieldLabel>
                <div className="relative">
                    <CalendarDays className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300" />
                    <input
                        type="date"
                        value={fechaEntrega}
                        onChange={(e) => setFecha(e.target.value)}
                        className="w-full pl-10 pr-4 py-2.5 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-violet-400"
                    />
                </div>
            </div>

            {/* Observaciones */}
            <div>
                <FieldLabel>Observaciones</FieldLabel>
                <textarea
                    value={obs}
                    onChange={(e) => setObs(e.target.value)}
                    rows={3}
                    placeholder="Notas sobre el diseño, materiales, instrucciones especiales..."
                    className="w-full px-4 py-2.5 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-violet-400 resize-none"
                />
            </div>

            <SubmitButton loading={loading} onClick={handleSubmit} label="Completar y avanzar a Corte" color="violet" />
        </SectionCard>
    );
}

"use client";

import { useState } from "react";
import { Shirt, Clock, Loader2, CheckCircle2, XCircle, AlertTriangle, ChevronRight } from "lucide-react";
import { toast } from "sonner";
import { SectionCard } from "../shared/SectionCard";
import { FieldLabel } from "../shared/FieldLabel";

interface Props {
    orden: any;
    onComplete: () => void;
}

const ESTADOS_CONFECCION = [
    { value: "pendiente", label: "Pendiente", Icon: Clock },
    { value: "en_proceso", label: "En proceso", Icon: Loader2 },
    { value: "completada", label: "Completada", Icon: CheckCircle2 },
    { value: "rechazada", label: "Rechazada", Icon: XCircle },
] as const;

export function FormTaller({ orden, onComplete }: Props) {
    const [estadoConf, setEstadoConf] = useState<string>(orden.estado_confeccion ?? "pendiente");
    const [prendas, setPrendas] = useState<string>(orden.prendas_completadas ?? "");
    const [incidencia, setIncidencia] = useState<string>(orden.incidencia_confeccion ?? "");
    const [loading, setLoading] = useState(false);

    const progreso = orden.cantidad && Number(prendas) > 0
        ? Math.min(Math.round((Number(prendas) / orden.cantidad) * 100), 100)
        : 0;

    const handleGuardar = async (completar = false) => {
        setLoading(true);
        try {
            const res = await fetch(`/api/ordenes-produccion/${orden.id}/etapa`, {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    estado_confeccion: estadoConf,
                    prendas_completadas: prendas ? Number(prendas) : null,
                    incidencia_confeccion: incidencia || null,
                    completar,
                }),
            });
            if (!res.ok) throw new Error();
            if (completar) {
                toast.success("Confección completada — avanzando a Remallado");
                onComplete();
            } else {
                toast.success("Avance guardado");
            }
        } catch {
            toast.error("No se pudo guardar");
        } finally {
            setLoading(false);
        }
    };

    return (
        <SectionCard>
            {/* Header */}
            <div className="flex items-center gap-3 pb-2 border-b border-slate-100">
                <div className="w-8 h-8 bg-rose-50 rounded-xl flex items-center justify-center">
                    <Shirt className="w-4 h-4 text-rose-600" />
                </div>
                <div>
                    <p className="text-sm font-black text-slate-800">Confección — Taller Externo</p>
                    <p className="text-xs text-slate-400">Actualiza el estado y registra el avance</p>
                </div>
            </div>

            {/* Estado confección */}
            <div>
                <FieldLabel required>Estado de confección</FieldLabel>
                <div className="grid grid-cols-2 gap-2">
                    {ESTADOS_CONFECCION.map(({ value, label, Icon }) => (
                        <button
                            key={value}
                            type="button"
                            onClick={() => setEstadoConf(value)}
                            className={`flex items-center gap-2 px-4 py-2.5 rounded-xl border-2 text-sm font-bold transition-all ${estadoConf === value
                                    ? "border-rose-500 bg-rose-50 text-rose-700"
                                    : "border-slate-200 text-slate-400 hover:border-rose-200"
                                }`}
                        >
                            <Icon className="w-4 h-4" />
                            {label}
                        </button>
                    ))}
                </div>
            </div>

            {/* Prendas completadas + barra */}
            <div>
                <FieldLabel>Prendas completadas</FieldLabel>
                <div className="flex items-center gap-3">
                    <input
                        type="number"
                        min={0}
                        value={prendas}
                        onChange={(e) => setPrendas(e.target.value)}
                        placeholder="0"
                        className="w-full px-4 py-2.5 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-rose-400"
                    />
                    {orden.cantidad && (
                        <span className="text-xs text-slate-400 whitespace-nowrap font-medium shrink-0">
                            de {orden.cantidad}
                        </span>
                    )}
                </div>
                {orden.cantidad && (
                    <div className="mt-2 space-y-1">
                        <div className="h-1.5 bg-slate-100 rounded-full overflow-hidden">
                            <div
                                className="h-full bg-rose-500 rounded-full transition-all duration-500"
                                style={{ width: `${progreso}%` }}
                            />
                        </div>
                        <p className="text-[11px] text-slate-400 text-right">{progreso}% completado</p>
                    </div>
                )}
            </div>

            {/* Incidencias */}
            <div>
                <div className="flex items-center gap-1.5 mb-1.5">
                    <AlertTriangle className="w-3.5 h-3.5 text-amber-500 shrink-0" />
                    <FieldLabel>Reportar incidencia</FieldLabel>
                </div>
                <textarea
                    value={incidencia}
                    onChange={(e) => setIncidencia(e.target.value)}
                    rows={3}
                    placeholder="Describe cualquier problema, rechazo o demora..."
                    className="w-full px-4 py-2.5 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-rose-400 resize-none"
                />
            </div>

            {/* Dos botones */}
            <div className="flex gap-3">
                <button
                    type="button"
                    onClick={() => handleGuardar(false)}
                    disabled={loading}
                    className="flex-1 py-2.5 border-2 border-slate-200 rounded-xl text-sm font-bold text-slate-600 hover:bg-slate-50 transition-colors disabled:opacity-50"
                >
                    Guardar avance
                </button>
                <button
                    type="button"
                    onClick={() => handleGuardar(true)}
                    disabled={loading || estadoConf !== "completada"}
                    className="flex-1 flex items-center justify-center gap-2 py-2.5 bg-rose-600 hover:bg-rose-700 text-white rounded-xl text-sm font-bold transition-colors disabled:opacity-40"
                >
                    {loading
                        ? <Loader2 className="w-4 h-4 animate-spin" />
                        : <ChevronRight className="w-4 h-4" />}
                    Completar y avanzar
                </button>
            </div>

            {estadoConf !== "completada" && (
                <p className="text-[11px] text-slate-400 text-center -mt-2">
                    El estado debe ser "Completada" para avanzar a la siguiente etapa
                </p>
            )}
        </SectionCard>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { X, Loader2, DollarSign, Hash, CreditCard, FileText, StickyNote } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { toast } from 'sonner';

const METODOS_PAGO = [
  { value: 'efectivo',          label: 'Efectivo' },
  { value: 'transferencia_bcp', label: 'Transferencia BCP' },
  { value: 'yape',              label: 'Yape' },
  { value: 'plin',              label: 'Plin' },
  { value: 'visa',              label: 'Visa' },
  { value: 'mastercard',        label: 'Mastercard' },
];

const TIPOS_PAGO = [
  { value: 'adelanto',      label: 'Adelanto' },
  { value: 'cuota',         label: 'Cuota' },
  { value: 'saldo_final',   label: 'Saldo Final' },
  { value: 'pago_completo', label: 'Pago Completo' },
];

interface PagoFormData {
  pedido_id: string;
  monto: string;
  metodo_pago: string;
  tipo: string;
  notas: string;
}

interface Props {
  onClose: () => void;
  onSuccess: () => void;
}

const EMPTY: PagoFormData = {
  pedido_id: '',
  monto: '',
  metodo_pago: '',
  tipo: 'pago_completo',
  notas: '',
};

export default function PagoFormModal({ onClose, onSuccess }: Props) {
  const [form, setForm] = useState<PagoFormData>(EMPTY);
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isSaving, setIsSaving] = useState(false);

  const handleChange = (field: keyof PagoFormData, value: string) => {
    setForm(prev => ({ ...prev, [field]: value }));
    setErrors(prev => { const c = { ...prev }; delete c[field]; return c; });
  };

  const validate = (): boolean => {
    const e: Record<string, string> = {};
    if (!form.pedido_id.trim()) e.pedido_id = 'El ID del pedido es requerido';
    if (!form.monto.trim() || parseFloat(form.monto) <= 0) e.monto = 'El monto debe ser mayor a 0';
    if (!form.metodo_pago) e.metodo_pago = 'Seleccione un método de pago';
    if (!form.tipo) e.tipo = 'Seleccione el tipo de pago';
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;
    setIsSaving(true);

    try {
      const res = await fetch('/api/admin/pagos', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          pedido_id: parseInt(form.pedido_id),
          monto: parseFloat(form.monto),
          metodo_pago: form.metodo_pago,
          tipo: form.tipo,
          notas: form.notas || null,
        }),
      });

      if (!res.ok) {
        const body = await res.json().catch(() => ({}));
        throw new Error(body?.error ?? 'Error al registrar pago');
      }

      toast.success('Pago registrado exitosamente');
      onSuccess();
      onClose();
    } catch (err: any) {
      toast.error(err.message ?? 'Error al registrar pago');
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div
      className="fixed inset-0 bg-black/40 backdrop-blur-sm z-50 flex items-center justify-center p-4"
      onClick={onClose}
    >
      <div
        className="bg-white rounded-2xl shadow-2xl w-full max-w-lg max-h-[90vh] overflow-y-auto"
        onClick={e => e.stopPropagation()}
      >
        {/* Gradient strip */}
        <div className="h-1.5 bg-gradient-to-r from-emerald-500 via-teal-500 to-cyan-500 rounded-t-2xl" />

        {/* Header */}
        <div className="flex items-center justify-between p-6 border-b border-gray-100">
          <div className="flex items-center gap-3">
            <div className="p-2.5 bg-emerald-50 rounded-xl border border-emerald-100">
              <DollarSign className="w-5 h-5 text-emerald-600" />
            </div>
            <div>
              <h2 className="text-lg font-black text-slate-900 tracking-tight">Registrar Pago</h2>
              <p className="text-xs text-slate-400 mt-0.5">Asocia un pago a un pedido existente</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-xl transition-colors">
            <X className="w-5 h-5 text-gray-400" />
          </button>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          {/* Pedido ID */}
          <div>
            <label className="text-[10px] uppercase font-bold text-slate-400 flex items-center gap-1.5 mb-1.5">
              <Hash className="w-3.5 h-3.5" /> N.° de Pedido *
            </label>
            <Input
              type="number"
              value={form.pedido_id}
              onChange={e => handleChange('pedido_id', e.target.value)}
              placeholder="Ej: 1042"
              className={errors.pedido_id ? 'border-red-400 focus:ring-red-400' : 'bg-slate-50 border-slate-200 focus:bg-white focus-visible:ring-emerald-400'}
            />
            {errors.pedido_id && <p className="text-xs text-red-500 mt-1">{errors.pedido_id}</p>}
          </div>

          {/* Monto */}
          <div>
            <label className="text-[10px] uppercase font-bold text-slate-400 flex items-center gap-1.5 mb-1.5">
              <DollarSign className="w-3.5 h-3.5" /> Monto (S/) *
            </label>
            <Input
              type="number"
              step="0.01"
              min="0"
              value={form.monto}
              onChange={e => handleChange('monto', e.target.value)}
              placeholder="0.00"
              className={errors.monto ? 'border-red-400 focus:ring-red-400' : 'bg-slate-50 border-slate-200 focus:bg-white focus-visible:ring-emerald-400'}
            />
            {errors.monto && <p className="text-xs text-red-500 mt-1">{errors.monto}</p>}
          </div>

          {/* Método de Pago & Tipo */}
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="text-[10px] uppercase font-bold text-slate-400 flex items-center gap-1.5 mb-1.5">
                <CreditCard className="w-3.5 h-3.5" /> Método de Pago *
              </label>
              <select
                value={form.metodo_pago}
                onChange={e => handleChange('metodo_pago', e.target.value)}
                className={`w-full h-10 px-3 text-sm border rounded-lg focus:outline-none focus:ring-2 transition-all cursor-pointer ${
                  errors.metodo_pago
                    ? 'border-red-400 focus:ring-red-400'
                    : 'bg-slate-50 border-slate-200 focus:bg-white focus:ring-emerald-400'
                }`}
              >
                <option value="">Seleccionar…</option>
                {METODOS_PAGO.map(m => (
                  <option key={m.value} value={m.value}>{m.label}</option>
                ))}
              </select>
              {errors.metodo_pago && <p className="text-xs text-red-500 mt-1">{errors.metodo_pago}</p>}
            </div>

            <div>
              <label className="text-[10px] uppercase font-bold text-slate-400 flex items-center gap-1.5 mb-1.5">
                <FileText className="w-3.5 h-3.5" /> Tipo de Pago *
              </label>
              <select
                value={form.tipo}
                onChange={e => handleChange('tipo', e.target.value)}
                className={`w-full h-10 px-3 text-sm border rounded-lg focus:outline-none focus:ring-2 transition-all cursor-pointer ${
                  errors.tipo
                    ? 'border-red-400 focus:ring-red-400'
                    : 'bg-slate-50 border-slate-200 focus:bg-white focus:ring-emerald-400'
                }`}
              >
                <option value="">Seleccionar…</option>
                {TIPOS_PAGO.map(t => (
                  <option key={t.value} value={t.value}>{t.label}</option>
                ))}
              </select>
              {errors.tipo && <p className="text-xs text-red-500 mt-1">{errors.tipo}</p>}
            </div>
          </div>

          {/* Notas */}
          <div>
            <label className="text-[10px] uppercase font-bold text-slate-400 flex items-center gap-1.5 mb-1.5">
              <StickyNote className="w-3.5 h-3.5" /> Notas (opcional)
            </label>
            <Textarea
              value={form.notas}
              onChange={e => handleChange('notas', e.target.value)}
              placeholder="N.° operación, referencia bancaria, etc."
              className="resize-none bg-slate-50 border-slate-200 focus:bg-white focus-visible:ring-emerald-400"
              rows={2}
            />
          </div>

          {/* Footer */}
          <div className="flex gap-3 pt-4 border-t border-gray-100">
            <Button type="button" variant="outline" onClick={onClose} className="flex-1 h-11 rounded-xl font-bold" disabled={isSaving}>
              Cancelar
            </Button>
            <Button
              type="submit"
              className="flex-1 h-11 rounded-xl font-black uppercase text-[11px] tracking-widest bg-emerald-600 hover:bg-emerald-700 text-white shadow-lg shadow-emerald-100 transition-all active:scale-95"
              disabled={isSaving}
            >
              {isSaving ? (
                <><Loader2 className="w-4 h-4 animate-spin mr-2" />Registrando…</>
              ) : 'Registrar Pago'}
            </Button>
          </div>
        </form>
      </div>
    </div>
  );
}

'use client';

import { useState } from 'react';
import { X, DollarSign, CreditCard, FileText, Calendar, User, CheckCircle, XCircle, Loader2, ShieldCheck, Clock } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { toast } from 'sonner';
import type { Pago } from './PagosTable';

// ─────────────────────────────────────────────────────────────
// DETAIL MODAL
// ─────────────────────────────────────────────────────────────

const ESTADO_STYLES: Record<string, string> = {
  pendiente:  'bg-amber-50 text-amber-700 border-amber-200',
  verificado: 'bg-emerald-50 text-emerald-700 border-emerald-200',
  rechazado:  'bg-red-50 text-red-700 border-red-200',
};

const METODO_LABELS: Record<string, string> = {
  efectivo:          'Efectivo',
  transferencia_bcp: 'Transferencia BCP',
  yape:              'Yape',
  plin:              'Plin',
  visa:              'Visa',
  mastercard:        'Mastercard',
};

const TIPO_LABELS: Record<string, string> = {
  adelanto:      'Adelanto',
  cuota:         'Cuota',
  saldo_final:   'Saldo Final',
  pago_completo: 'Pago Completo',
};

function formatMoney(value: number | string | null | undefined) {
  const n = typeof value === 'string' ? parseFloat(value) : value ?? 0;
  return `S/ ${n.toLocaleString('es-PE', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
}

function formatDate(d: string | null | undefined) {
  if (!d) return '—';
  return new Date(d).toLocaleDateString('es-PE', { day: '2-digit', month: 'long', year: 'numeric' });
}

interface DetailProps {
  pago: Pago;
  onClose: () => void;
}

export function PagoDetailModal({ pago, onClose }: DetailProps) {
  const fields = [
    { label: 'Monto',          value: formatMoney(pago.monto),                    icon: <DollarSign className="w-3.5 h-3.5" /> },
    { label: 'Método de Pago', value: METODO_LABELS[pago.metodo_pago] ?? pago.metodo_pago, icon: <CreditCard className="w-3.5 h-3.5" /> },
    { label: 'Tipo',           value: TIPO_LABELS[pago.tipo] ?? pago.tipo,        icon: <FileText className="w-3.5 h-3.5" /> },
    { label: 'Fecha de Pago',  value: formatDate(pago.fecha_pago),                icon: <Calendar className="w-3.5 h-3.5" /> },
    { label: 'Registrado por', value: pago.usuario?.nombre_completo ?? '—',       icon: <User className="w-3.5 h-3.5" /> },
  ];

  return (
    <div
      className="fixed inset-0 bg-black/40 backdrop-blur-sm z-50 flex items-center justify-center p-4"
      onClick={onClose}
    >
      <div
        className="bg-white rounded-2xl shadow-2xl w-full max-w-md"
        onClick={e => e.stopPropagation()}
      >
        {/* Gradient strip */}
        <div className="h-1.5 bg-gradient-to-r from-emerald-500 via-teal-500 to-cyan-500 rounded-t-2xl" />

        {/* Header */}
        <div className="flex items-center justify-between p-6 border-b border-gray-100">
          <div className="flex items-center gap-3">
            <div className="p-2.5 bg-emerald-50 rounded-xl border border-emerald-100">
              <DollarSign className="w-5 h-5 text-emerald-600" />
            </div>
            <div>
              <h3 className="text-lg font-black text-gray-900 tracking-tight">
                Pedido #{pago.pedido_id}
              </h3>
              <p className="text-xs text-gray-500 mt-0.5">
                {pago.pedidos?.clientes?.razon_social ?? 'Cliente no especificado'}
              </p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-xl transition-colors">
            <X className="w-5 h-5 text-gray-400" />
          </button>
        </div>

        {/* Fields */}
        <div className="p-6 space-y-4">
          <div className="space-y-1">
            {fields.map(f => (
              <div key={f.label} className="flex justify-between items-center py-2.5 px-3 border-b last:border-0 border-gray-100">
                <div className="flex items-center gap-2 text-gray-500">
                  {f.icon}
                  <span className="text-xs font-semibold uppercase tracking-wider">{f.label}</span>
                </div>
                <span className="text-sm font-medium text-gray-900">{f.value}</span>
              </div>
            ))}
          </div>

          {/* Estado */}
          <div className="flex justify-between items-center py-2.5 px-3 bg-gray-50 rounded-xl">
            <div className="flex items-center gap-2 text-gray-500">
              <ShieldCheck className="w-3.5 h-3.5" />
              <span className="text-xs font-semibold uppercase tracking-wider">Estado</span>
            </div>
            <Badge variant="outline" className={`text-[10px] uppercase font-bold tracking-wider ${ESTADO_STYLES[pago.estado] ?? ''}`}>
              {pago.estado}
            </Badge>
          </div>

          {/* Verificación info */}
          {pago.verificado_at && (
            <div className="flex justify-between items-center py-2.5 px-3 bg-emerald-50/50 rounded-xl border border-emerald-100">
              <div className="flex items-center gap-2 text-emerald-600">
                <CheckCircle className="w-3.5 h-3.5" />
                <span className="text-xs font-semibold uppercase tracking-wider">Verificado</span>
              </div>
              <div className="text-right">
                <p className="text-xs font-medium text-emerald-700">{formatDate(pago.verificado_at)}</p>
                {pago.verificado_por_usuario && (
                  <p className="text-[10px] text-emerald-500">por {pago.verificado_por_usuario.nombre_completo}</p>
                )}
              </div>
            </div>
          )}

          {/* Notas */}
          {pago.notas && (
            <div className="bg-slate-50 rounded-xl p-3 border border-slate-100">
              <p className="text-[10px] uppercase font-bold text-slate-400 tracking-wider mb-1">Notas</p>
              <p className="text-sm text-slate-700">{pago.notas}</p>
            </div>
          )}

          {/* Resumen del pedido */}
          {pago.pedidos && (
            <div className="bg-indigo-50/50 rounded-xl p-3 border border-indigo-100">
              <p className="text-[10px] uppercase font-bold text-indigo-400 tracking-wider mb-2">Resumen del Pedido</p>
              <div className="grid grid-cols-3 gap-2 text-center">
                <div>
                  <p className="text-lg font-black text-indigo-700">{formatMoney(pago.pedidos.total)}</p>
                  <p className="text-[10px] text-indigo-400 uppercase font-semibold">Total</p>
                </div>
                <div>
                  <p className="text-lg font-black text-emerald-600">{formatMoney(pago.pedidos.monto_pagado)}</p>
                  <p className="text-[10px] text-emerald-400 uppercase font-semibold">Pagado</p>
                </div>
                <div>
                  <p className="text-lg font-black text-amber-600">{formatMoney(pago.pedidos.saldo_pendiente)}</p>
                  <p className="text-[10px] text-amber-400 uppercase font-semibold">Pendiente</p>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────
// VERIFY MODAL
// ─────────────────────────────────────────────────────────────

interface VerifyProps {
  pago: Pago;
  onClose: () => void;
  onSuccess: () => void;
}

export function PagoVerifyModal({ pago, onClose, onSuccess }: VerifyProps) {
  const [isProcessing, setIsProcessing] = useState(false);

  const handleAction = async (action: 'verificado' | 'rechazado') => {
    setIsProcessing(true);
    try {
      const res = await fetch(`/api/admin/pagos/${pago.id_uuid}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ estado: action }),
      });

      if (!res.ok) throw new Error('Error al actualizar');

      toast.success(
        action === 'verificado'
          ? `Pago de ${formatMoney(pago.monto)} verificado exitosamente`
          : `Pago de ${formatMoney(pago.monto)} rechazado`
      );
      onSuccess();
      onClose();
    } catch (error) {
      toast.error('Error al procesar la acción');
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div
      className="fixed inset-0 bg-black/40 backdrop-blur-sm z-50 flex items-center justify-center p-4"
      onClick={onClose}
    >
      <div
        className="bg-white rounded-2xl shadow-2xl w-full max-w-sm p-6 text-center"
        onClick={e => e.stopPropagation()}
      >
        <div className="w-14 h-14 bg-blue-50 rounded-full flex items-center justify-center mx-auto mb-4">
          <ShieldCheck className="w-7 h-7 text-blue-500" />
        </div>
        <h3 className="text-lg font-bold text-gray-900">Verificar Pago</h3>
        <p className="text-sm text-gray-500 mt-2">
          Pago de <span className="font-bold text-gray-900">{formatMoney(pago.monto)}</span> para el
          Pedido <span className="font-bold text-gray-900">#{pago.pedido_id}</span>.
        </p>
        <p className="text-xs text-gray-400 mt-1">
          Método: {METODO_LABELS[pago.metodo_pago] ?? pago.metodo_pago}
        </p>

        <div className="flex gap-3 mt-6">
          <Button
            onClick={() => handleAction('rechazado')}
            variant="outline"
            className="flex-1 h-11 border-red-200 text-red-600 hover:bg-red-50"
            disabled={isProcessing}
          >
            <XCircle className="w-4 h-4 mr-1.5" />
            Rechazar
          </Button>
          <Button
            onClick={() => handleAction('verificado')}
            className="flex-1 h-11 bg-emerald-600 hover:bg-emerald-700 text-white"
            disabled={isProcessing}
          >
            {isProcessing ? (
              <><Loader2 className="w-4 h-4 animate-spin mr-2" />Procesando…</>
            ) : (
              <><CheckCircle className="w-4 h-4 mr-1.5" />Verificar</>
            )}
          </Button>
        </div>
      </div>
    </div>
  );
}

"use client";

