function ImpactItem({ icon, text }: { icon: React.ReactNode; text: string }) {
  return (
    <div className="flex items-start gap-3 bg-white/60 backdrop-blur-sm p-3 rounded-2xl border border-rose-100 shadow-sm">
      <div className="text-red-600 mt-0.5 shrink-0">
        {icon}
      </div>
      <p className="text-[11px] font-bold text-slate-500 leading-tight">
        {text}
      </p>
    </div>
  );
}

"use client";

import { useState, useEffect, useMemo } from "react";
import {
  Dialog,
  DialogContent,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { 
  Search, 
  ShoppingCart, 
  Trash2, 
  Plus, 
  Minus, 
  User, 
  Package, 
  Loader2,
  X,
  CreditCard,
  Receipt,
  Sparkles,
  ArrowRight,
} from "lucide-react";
import { toast } from "sonner";
import { 
  Select, 
  SelectContent, 
  SelectItem, 
  SelectTrigger, 
  SelectValue 
} from "@/components/ui/select";
import { cn } from "@/lib/utils";

// Estilos constantes para coherencia visual de GUOR PRO
const ERP_LABEL = "text-[11px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2.5 mb-3";
const ERP_INPUT_BOX = "bg-slate-50/50 backdrop-blur-sm border border-slate-200/50 rounded-[24px] focus-within:border-pink-300 focus-within:bg-white focus-within:shadow-2xl focus-within:shadow-pink-50/50 transition-all duration-500";

export default function CreatePedidoDialog({ isOpen, onClose, onSuccess }: any) {
  const [loading, setLoading] = useState(false);
  const [clientes, setClientes] = useState<any[]>([]);
  const [productos, setProductos] = useState<any[]>([]);
  
  const [selectedCliente, setSelectedCliente] = useState<string>("");
  const [searchProd, setSearchProd] = useState("");
  const [carrito, setCarrito] = useState<any[]>([]);

  useEffect(() => {
    if (isOpen) {
      const loadInitialData = async () => {
        try {
          const [cliRes, prodRes] = await Promise.all([
            fetch('/api/admin/clientes'),
            fetch('/api/admin/productos')
          ]);
          const cliData = await cliRes.json();
          const prodData = await prodRes.json();
          setClientes(cliData || []);
          setProductos(prodData.filter((p: any) => p.stock > 0) || []);
        } catch (error) {
          toast.error("Error al sincronizar datos de inventario");
        }
      };
      loadInitialData();
    }
  }, [isOpen]);

  const filteredProducts = useMemo(() => {
    if (!searchProd) return [];
    return productos.filter(p => 
      p.nombre.toLowerCase().includes(searchProd.toLowerCase()) || 
      p.sku?.toLowerCase().includes(searchProd.toLowerCase())
    ).slice(0, 6);
  }, [searchProd, productos]);

  const addToCart = (prod: any) => {
    const exists = carrito.find(item => item.id === prod.id);
    if (exists) {
      if (exists.cantidad >= prod.stock) return toast.error("Stock máximo alcanzado");
      setCarrito(carrito.map(item => item.id === prod.id ? { ...item, cantidad: item.cantidad + 1 } : item));
    } else {
      setCarrito([...carrito, { ...prod, cantidad: 1 }]);
    }
    setSearchProd("");
  };

  const updateQuantity = (id: number, delta: number) => {
    setCarrito(carrito.map(item => {
      if (item.id === id) {
        const newQty = item.cantidad + delta;
        if (newQty > item.stock) { toast.error("Límite de stock"); return item; }
        return newQty > 0 ? { ...item, cantidad: newQty } : item;
      }
      return item;
    }));
  };

  const removeFromCart = (id: number) => {
    setCarrito(carrito.filter(item => item.id !== id));
    toast.info("Prenda removida del carrito");
  };

  const total = carrito.reduce((acc, item) => acc + (item.precio * item.cantidad), 0);

  const handleSave = async () => {
    if (!selectedCliente) return toast.error("Seleccione un cliente");
    if (carrito.length === 0) return toast.error("El carrito está vacío");

    setLoading(true);
    try {
      const pedidoData = {
        cliente_id: selectedCliente,
        metodo_pago: "EFECTIVO",
        subtotal: total / 1.18,
        impuesto: total - (total / 1.18),
        total: total,
        productos: carrito.map(item => ({
          id: item.id,
          cantidad: item.cantidad,
          precio: item.precio
        }))
      };

      const response = await fetch('/api/admin/pedidos', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(pedidoData),
      });

      if (!response.ok) throw new Error("Error al procesar pedido");

      toast.success("¡Venta registrada correctamente!");
      onSuccess();
      onClose();
      setCarrito([]);
      setSelectedCliente("");
    } catch (err: any) {
      toast.error(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-6xl h-[92vh] bg-white/95 backdrop-blur-2xl rounded-[48px] overflow-hidden p-0 border border-white/20 shadow-[0_32px_128px_-16px_rgba(0,0,0,0.15)] flex flex-col animate-in zoom-in-95 duration-500">
        
        {/* HEADER DE CAJA PREMIUM */}
        <div className="px-10 py-10 border-b border-slate-100/50 flex items-center justify-between relative overflow-hidden bg-white">
          <div className="absolute top-0 right-0 w-64 h-64 bg-pink-50/30 rounded-full -mr-32 -mt-32 blur-3xl animate-pulse"></div>
          <div className="relative flex items-center gap-6">
            <div className="p-4 bg-gradient-to-br from-pink-500 to-rose-600 rounded-[28px] shadow-lg shadow-pink-200/50 rotate-3 transition-transform hover:rotate-0">
              <ShoppingCart className="w-8 h-8 text-white" />
            </div>
            <div>
              <div className="flex items-center gap-3">
                <DialogTitle className="text-3xl font-black text-[#1a2b4b] uppercase tracking-tighter">
                  Terminal de Ventas
                </DialogTitle>
                <div className="px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full text-[10px] font-black uppercase tracking-widest flex items-center gap-1.5">
                  <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></div> En Línea
                </div>
              </div>
              <p className="text-slate-400 text-sm font-semibold mt-1">GUOR PRO System <span className="mx-2 opacity-30">•</span> Caja Centralizada de Operaciones</p>
            </div>
          </div>
          <button 
            onClick={onClose} 
            className="p-4 bg-slate-50 hover:bg-rose-50 rounded-full transition-all group relative z-10"
          >
            <X className="w-6 h-6 text-slate-400 group-hover:text-rose-500 transition-colors" />
          </button>
        </div>

        <div className="flex-1 flex overflow-hidden">
          
          {/* PANEL IZQUIERDO: CONFIGURACIÓN Y BÚSQUEDA */}
          <div className="flex-1 p-10 space-y-10 overflow-y-auto custom-scrollbar bg-white/50">
            
            {/* SECCIÓN CLIENTE CON DISEÑO DE TARJETA */}
            <div className="space-y-4">
              <Label className={ERP_LABEL}><User className="w-4 h-4" /> Entidad Responsable</Label>
              <Select onValueChange={setSelectedCliente} value={selectedCliente}>
                <SelectTrigger className="bg-white border border-slate-200 h-16 rounded-[24px] px-6 font-bold text-slate-700 shadow-sm hover:shadow-md transition-all focus:ring-4 focus:ring-pink-50/50">
                  <SelectValue placeholder="Busca o selecciona un cliente corporativo..." />
                </SelectTrigger>
                <SelectContent className="rounded-[32px] border-none shadow-[0_20px_50px_-12px_rgba(0,0,0,0.15)] p-3 backdrop-blur-xl bg-white/95">
                  {clientes.map(c => (
                    <SelectItem key={c.id} value={c.id.toString()} className="rounded-2xl py-4 px-5 font-bold mb-2 focus:bg-pink-50 transition-colors">
                      <div className="flex items-center gap-4">
                        <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center font-black text-slate-400 text-[10px]">{c.razon_social?.substring(0, 2).toUpperCase()}</div>
                        <div className="flex flex-col">
                          <span className="text-slate-900">{c.razon_social}</span>
                          <span className="text-[10px] text-pink-500 font-black uppercase tracking-widest">RUC: {c.ruc}</span>
                        </div>
                      </div>
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {/* BUSCADOR DE PRODUCTOS CON RESULTADOS FLOTANTES */}
            <div className="space-y-4 relative">
              <div className="flex justify-between items-center">
                <Label className={ERP_LABEL}><Package className="w-4 h-4" /> Catálogo de Inventario</Label>
                <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">Stock en tiempo real</span>
              </div>
              <div className={cn("flex items-center px-6 h-20", ERP_INPUT_BOX)}>
                <Search className="w-6 h-6 text-slate-300 mr-4" />
                <Input 
                  placeholder="Introduce nombre de prenda, color o SKU..." 
                  className="bg-transparent border-none h-full font-bold focus-visible:ring-0 shadow-none text-xl text-slate-800 placeholder:text-slate-300"
                  value={searchProd}
                  onChange={(e) => setSearchProd(e.target.value)}
                />
                {searchProd && (
                   <button onClick={() => setSearchProd("")} className="p-2 hover:bg-slate-200 rounded-xl transition-all">
                      <X className="w-4 h-4 text-slate-400" />
                   </button>
                )}
              </div>

              {/* Resultados de búsqueda con efecto glass */}
              {filteredProducts.length > 0 && (
                <div className="absolute z-50 w-full bg-white/95 backdrop-blur-xl border border-slate-200/50 rounded-[32px] shadow-[0_24px_48px_-12px_rgba(0,0,0,0.1)] mt-3 overflow-hidden animate-in fade-in slide-in-from-top-4 duration-500 p-2">
                  {filteredProducts.map(p => (
                    <button
                      key={p.id}
                      onClick={() => addToCart(p)}
                      className="w-full p-4 text-left hover:bg-pink-50/50 rounded-2xl flex justify-between items-center transition-all duration-300 group"
                    >
                      <div className="flex items-center gap-5">
                        <div className="w-14 h-14 bg-slate-100 rounded-2xl flex items-center justify-center relative overflow-hidden group-hover:scale-105 transition-transform">
                          {p.imagen_url ? <img src={p.imagen_url} alt="" className="w-full h-full object-cover" /> : <Package className="w-6 h-6 text-slate-300" />}
                        </div>
                        <div>
                          <p className="font-black text-slate-800 text-lg leading-tight group-hover:text-pink-600 transition-colors">{p.nombre}</p>
                          <div className="flex items-center gap-3 mt-1">
                            <span className="text-[10px] text-slate-400 font-black uppercase tracking-widest">SKU: {p.sku || 'N/A'}</span>
                            <span className="w-1 h-1 rounded-full bg-slate-200"></span>
                            <span className={cn(
                              "text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded-md",
                              p.stock < 10 ? "bg-rose-50 text-rose-500" : "bg-emerald-50 text-emerald-500"
                            )}>
                              {p.stock} Disponibles
                            </span>
                          </div>
                        </div>
                      </div>
                      <div className="flex items-center gap-4">
                        <div className="text-right">
                          <p className="text-[10px] font-black text-slate-300 uppercase tracking-widest mb-0.5">Precio Unit.</p>
                          <p className="font-black text-[#1a2b4b] text-xl tracking-tighter">S/ {p.precio.toFixed(2)}</p>
                        </div>
                        <div className="p-3 bg-white border border-slate-100 rounded-xl group-hover:bg-pink-500 group-hover:text-white group-hover:border-pink-500 transition-all shadow-sm">
                           <Plus className="w-5 h-5" />
                        </div>
                      </div>
                    </button>
                  ))}
                  <div className="p-4 bg-slate-50/50 text-center">
                     <p className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em]">Fin de resultados</p>
                  </div>
                </div>
              )}
            </div>

            {/* SECCIÓN DE MÉTODOS Y DETALLES */}
            <div className="grid grid-cols-2 gap-6">
               <div className="p-8 bg-gradient-to-br from-slate-50 to-white rounded-[40px] border border-slate-100 hover:shadow-lg transition-all duration-500 group">
                  <div className="flex items-center gap-4 mb-4">
                    <div className="p-3 bg-violet-50 text-violet-600 rounded-2xl group-hover:scale-110 transition-transform">
                      <CreditCard className="w-6 h-6" />
                    </div>
                    <p className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">Condición de Pago</p>
                  </div>
                  <p className="text-xl font-black text-slate-800">Efectivo / Caja Chapa</p>
               </div>
               <div className="p-8 bg-gradient-to-br from-slate-50 to-white rounded-[40px] border border-slate-100 hover:shadow-lg transition-all duration-500 group">
                  <div className="flex items-center gap-4 mb-4">
                    <div className="p-3 bg-sky-50 text-sky-600 rounded-2xl group-hover:scale-110 transition-transform">
                      <Receipt className="w-6 h-6" />
                    </div>
                    <p className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">Documento Fiscal</p>
                  </div>
                  <p className="text-xl font-black text-slate-800">Nota de Pedido Interna</p>
               </div>
            </div>
          </div>

          {/* PANEL DERECHO: RESUMEN Y CHECKOUT (MÁS OSCURO Y PROFESIONAL) */}
          <div className="w-[480px] bg-slate-900 border-l border-white/5 p-10 flex flex-col relative">
            <div className="absolute top-0 right-0 w-full h-full bg-[radial-gradient(circle_at_bottom_right,_var(--tw-gradient-stops))] from-pink-500/5 via-transparent to-transparent pointer-events-none"></div>
            
            <h3 className="text-[12px] font-black text-pink-400 uppercase tracking-[0.3em] flex items-center gap-3">
              <Sparkles className="w-4 h-4" /> Detalle de Liquidación
            </h3>
            
            <div className="flex-1 overflow-y-auto space-y-6 my-8 pr-2 custom-scrollbar relative z-10">
              {carrito.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center opacity-20 grayscale-0">
                  <div className="w-32 h-32 bg-slate-800 rounded-full flex items-center justify-center mb-6">
                    <ShoppingCart className="w-12 h-12 text-slate-400" />
                  </div>
                  <p className="text-xs font-black uppercase tracking-[0.3em] text-slate-500">Esperando Selección</p>
                </div>
              ) : (
                carrito.map(item => (
                  <div key={item.id} className="bg-slate-800/50 backdrop-blur-md p-6 rounded-[32px] border border-white/5 flex flex-col gap-4 group hover:bg-slate-800 transition-all">
                    <div className="flex justify-between items-start">
                      <div className="flex-1">
                        <p className="font-black text-base text-white leading-tight group-hover:text-pink-400 transition-colors">{item.nombre}</p>
                        <p className="text-[11px] text-slate-500 font-bold mt-1 uppercase tracking-widest">S/ {item.precio.toFixed(2)} / unidad</p>
                      </div>
                      <button 
                        onClick={() => removeFromCart(item.id)} 
                        className="text-slate-600 hover:text-rose-500 transition-all p-2 hover:bg-rose-500/10 rounded-xl"
                      >
                        <Trash2 className="w-5 h-5" />
                      </button>
                    </div>
                    
                    <div className="flex items-center justify-between">
                      <div className="flex items-center bg-slate-950 rounded-[20px] p-1.5 border border-white/5">
                        <button 
                          onClick={() => updateQuantity(item.id, -1)} 
                          className="w-10 h-10 flex items-center justify-center hover:bg-slate-800 rounded-2xl transition-all text-slate-400 hover:text-white"
                        >
                          <Minus className="w-4 h-4" />
                        </button>
                        <span className="w-12 text-center font-black text-lg text-white">{item.cantidad}</span>
                        <button 
                          onClick={() => updateQuantity(item.id, 1)} 
                          className="w-10 h-10 flex items-center justify-center hover:bg-slate-800 rounded-2xl transition-all text-slate-400 hover:text-white"
                        >
                          <Plus className="w-4 h-4" />
                        </button>
                      </div>
                      <div className="text-right">
                         <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Subtotal</p>
                         <p className="font-black text-white text-2xl tracking-tighter">S/ {(item.precio * item.cantidad).toFixed(2)}</p>
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>

            {/* TOTALES Y ACCIÓN FINAL */}
            <div className="mt-auto space-y-8 pt-8 border-t border-white/10 relative z-10">
              <div className="space-y-3">
                 <div className="flex justify-between items-center text-slate-500 font-bold text-xs uppercase tracking-[0.2em]">
                    <span>Base Imponible</span>
                    <span>S/ {(total / 1.18).toFixed(2)}</span>
                 </div>
                 <div className="flex justify-between items-center text-slate-500 font-bold text-xs uppercase tracking-[0.2em]">
                    <span>Impuestos (18%)</span>
                    <span>S/ {(total - (total / 1.18)).toFixed(2)}</span>
                 </div>
              </div>

              <div className="flex justify-between items-end bg-white/5 p-8 rounded-[36px] border border-white/5">
                <span className="text-[12px] font-black text-pink-400 uppercase tracking-[0.4em] mb-2">Total Final</span>
                <span className="text-5xl font-black text-white tracking-tighter">S/ {total.toFixed(2)}</span>
              </div>
              
              <div className="flex flex-col gap-4">
                <Button 
                  onClick={handleSave} 
                  disabled={loading || carrito.length === 0} 
                  className="w-full h-24 bg-gradient-to-r from-pink-500 to-rose-600 hover:from-pink-600 hover:to-rose-700 text-white rounded-[32px] font-black text-2xl shadow-2xl shadow-pink-900/50 transition-all active:scale-95 flex items-center justify-center gap-4 group"
                >
                  {loading ? (
                    <Loader2 className="w-8 h-8 animate-spin" />
                  ) : (
                    <>
                      <span>Procesar Venta</span>
                      <ArrowRight className="w-8 h-8 group-hover:translate-x-2 transition-transform" />
                    </>
                  )}
                </Button>
                <button 
                  onClick={onClose} 
                  className="w-full py-4 text-center text-slate-500 text-[10px] font-black uppercase tracking-[0.3em] hover:text-white transition-colors"
                >
                  Cancelar Operación
                </button>
              </div>
            </div>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

"use client";

import { Eye, Printer, Truck, Calendar, User, Hash, XCircle } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";

// 1. Interfaces tipadas
interface PedidosTableProps {
  data: any[];
  onView: (pedido: any) => void;
  onCancel?: (pedido: any) => void;
  onUpdateStatus?: (pedido: any) => void;
}

export default function PedidosTable({ 
  data, 
  onView, 
  onCancel, 
  onUpdateStatus 
}: PedidosTableProps) {

  // Helper para los Badges de estado
  const getStatusBadge = (status: string) => {
    const styles: Record<string, string> = {
      solicitud: "bg-blue-50 text-blue-600 border-blue-100",
      cotizado: "bg-purple-50 text-purple-600 border-purple-100",
      aprobado: "bg-orange-50 text-orange-600 border-orange-100",
      pagado: "bg-emerald-50 text-emerald-600 border-emerald-100",
      en_proceso: "bg-pink-50 text-pink-600 border-pink-100",
      finalizado: "bg-slate-50 text-slate-600 border-slate-100",
      cancelado: "bg-rose-50 text-rose-600 border-rose-100",
      };
    const label: Record<string, string> = {
      solicitud: "Solicitud",
      cotizado: "Cotizado",
      aprobado: "Aprobado",
      pagado: "Pagado",
      en_proceso: "En Taller",
      finalizado: "Completado",
      cancelado: "Anulado",

    };

    return (
      <Badge
        className={`rounded-full px-4 py-1 text-[10px] font-black border-2 uppercase transition-colors ${
          styles[status] || "bg-gray-50 text-gray-500 border-gray-100"
        }`}
        variant="outline"
      >
        {label[status] || status}
      </Badge>
    );
  };

  return (
    <div className="space-y-4">
      <div className="overflow-x-auto pb-4">
        <table className="w-full border-separate border-spacing-y-3">
          <thead>
            <tr className="text-left">
              <th className="px-6 py-2 font-black text-[11px] tracking-widest text-slate-400 uppercase">Orden</th>
              <th className="px-6 py-2 font-black text-[11px] tracking-widest text-slate-400 uppercase">Cliente</th>
              <th className="px-6 py-2 font-black text-[11px] tracking-widest text-slate-400 uppercase text-center">Fecha</th>
              <th className="px-6 py-2 font-black text-[11px] tracking-widest text-slate-400 uppercase text-center">Estado</th>
              <th className="px-6 py-2 font-black text-[11px] tracking-widest text-slate-400 uppercase text-right">Acciones</th>
            </tr>
          </thead>
          <tbody>
            {data.length === 0 ? (
              <tr>
                <td colSpan={5} className="bg-white rounded-2xl border border-slate-100 py-16 text-center shadow-sm">
                  <p className="text-slate-400 font-bold uppercase text-xs tracking-widest">No hay pedidos registrados</p>
                </td>
              </tr>
            ) : (
              data.map((pedido) => (
                <tr key={pedido.id} className="group transition-all duration-200">
                  {/* ID y Total */}
                  <td className="bg-white border-y border-l border-slate-100 py-5 px-6 rounded-l-2xl shadow-sm group-hover:shadow-md transition-all">
                    <div className="flex items-center gap-3">
                      <div className="h-10 w-10 rounded-xl bg-pink-50 text-pink-600 flex items-center justify-center border border-pink-100 shrink-0">
                        <Hash size={16} />
                      </div>
                      <div className="flex flex-col">
                        <span className="font-black text-pink-600 text-sm tracking-tight">
                          #{pedido.id.toString().padStart(4, '0')}
                        </span>
                        <span className="text-slate-900 font-black text-sm uppercase">
                          S/ {pedido.total?.toFixed(2)}
                        </span>
                      </div>
                    </div>
                  </td>

                  {/* Cliente */}
                  <td className="bg-white border-y border-slate-100 py-5 px-6 shadow-sm group-hover:shadow-md transition-all">
                    <div className="flex items-center gap-3">
                      <div className="h-8 w-8 rounded-lg bg-slate-50 flex items-center justify-center text-slate-400 border border-slate-100 shrink-0">
                        <User size={14} />
                      </div>
                      <div className="flex flex-col">
                        <span className="font-bold text-slate-700 text-[13px] uppercase tracking-tight line-clamp-1">
                          {pedido.clientes?.razon_social || "CLIENTE NO IDENTIFICADO"}
                        </span>
                        <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">
                          RUC: {pedido.clientes?.ruc || "---"}
                        </span>
                      </div>
                    </div>
                  </td>

                  {/* Fecha */}
                  <td className="bg-white border-y border-slate-100 text-center shadow-sm group-hover:shadow-md transition-all">
                    <div className="inline-flex items-center gap-2 text-slate-500 font-bold text-[11px] bg-slate-50 px-3 py-1.5 rounded-lg border border-slate-100 uppercase tracking-tighter">
                      <Calendar size={13} className="text-slate-400" />
                      {new Date(pedido.created_at).toLocaleDateString()}
                    </div>
                  </td>

                  {/* Estado */}
                  <td className="bg-white border-y border-slate-100 text-center shadow-sm group-hover:shadow-md transition-all">
                    {getStatusBadge(pedido.estado)}
                  </td>

                  {/* Acciones */}
                  <td className="bg-white border-y border-r border-slate-100 px-6 rounded-r-2xl text-right shadow-sm group-hover:shadow-md transition-all">
                    <div className="flex justify-end items-center gap-2">
                      {/* Ver Detalles */}
                      <Button 
                        variant="outline" 
                        size="icon" 
                        onClick={() => onView(pedido)}
                        className="h-9 w-9 rounded-xl border-slate-200 text-slate-400 hover:text-blue-600 hover:border-blue-200 hover:bg-blue-50 transition-all"
                        title="Ver Detalles"
                      >
                        <Eye size={16} />
                      </Button>

                      {/* Actualizar Estado (Logística/Envío) */}
                      {onUpdateStatus && (
                        <Button 
                          variant="outline" 
                          size="icon" 
                          onClick={() => onUpdateStatus(pedido)}
                          className="h-9 w-9 rounded-xl border-slate-200 text-slate-400 hover:text-orange-600 hover:border-orange-200 hover:bg-orange-50 transition-all"
                          title="Actualizar Estado"
                        >
                          <Truck size={16} />
                        </Button>
                      )}

                      {/* Imprimir */}
                      <Button 
                        variant="outline" 
                        size="icon" 
                        className="h-9 w-9 rounded-xl border-slate-200 text-slate-400 hover:text-slate-600 hover:border-slate-300 hover:bg-slate-100 transition-all"
                        title="Imprimir"
                      >
                        <Printer size={16} />
                      </Button>

                      {/* Cancelar / Anular */}
                      {onCancel && pedido.estado !== 'cancelado' && (
                        <Button 
                          variant="outline" 
                          size="icon" 
                          onClick={() => {
                            console.log("Iniciando anulación pedido:", pedido.id);
                            onCancel(pedido);
                          }}
                          className="h-9 w-9 rounded-xl border-slate-200 text-slate-400 hover:text-red-600 hover:border-red-200 hover:bg-red-50 transition-all"
                          title="Anular Pedido"
                        >
                          <XCircle size={16} />
                        </Button>
                      )}
                    </div>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

"use client";

import SearchInput from "../common/SearchInput";
import FilterSelect from "../common/FilterSelect";
import { Button } from "@/components/ui/button";
import { RefreshCw } from "lucide-react";
import { cn } from "@/lib/utils";

interface PedidosToolbarProps {
  searchTerm: string;
  setSearchTerm: (v: string) => void;
  dateFilter: string;
  setDateFilter: (v: any) => void;
  onPageReset: () => void;
  isLoading: boolean;
  onRefresh: () => void;
}

export default function PedidosToolbar({
  searchTerm,
  setSearchTerm,
  dateFilter,
  setDateFilter,
  onPageReset,
  isLoading,
  onRefresh,
}: PedidosToolbarProps) {
  const handleSearchChange = (v: string) => {
    setSearchTerm(v);
    onPageReset();
  };

  const handleDateChange = (v: string) => {
    setDateFilter(v);
    onPageReset();
  };

  return (
    <div className="flex flex-col md:flex-row gap-4 items-center bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
      <SearchInput
        placeholder="Buscar por cliente o N° de pedido..."
        value={searchTerm}
        onChange={handleSearchChange}
      />

      <div className="flex items-center gap-3 w-full md:w-auto">
        <FilterSelect
          placeholder="Fecha"
          value={dateFilter}
          onValueChange={handleDateChange}
          options={[
            { label: "Cualquier fecha", value: "todas" },
            { label: "Hoy", value: "hoy" },
            { label: "Últimos 7 días", value: "semana" },
            { label: "Este mes", value: "mes" },
          ]}
        />

        <Button
          variant="outline"
          className="h-11 w-11 p-0 border-gray-200 rounded-xl hover:bg-gray-50 transition-all active:scale-95"
          onClick={onRefresh}
          disabled={isLoading}
        >
          <RefreshCw className={cn("w-4 h-4 text-gray-500", isLoading && "animate-spin")} />
        </Button>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { getSupabaseBrowserClient } from "@/lib/supabase";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import {
  Receipt,
  Printer,
  Calendar,
  Hash,
  User,
  CreditCard,
  Package,
  ArrowLeft,
  CheckCircle2,
  FileText,
  Clock,
  ExternalLink,
  Loader2
} from "lucide-react";
import { cn } from "@/lib/utils";

export default function ViewPedidoDialog({ isOpen, pedido, onClose }: any) {
  const [detalles, setDetalles] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (isOpen && pedido?.id) {
      const loadDetalles = async () => {
        setLoading(true);
        try {
          const supabase = getSupabaseBrowserClient();
          const { data, error } = await supabase
            .from("pedido_items" as any) // Corregido a pedido_items según el esquema actual
            .select("*, productos(nombre, sku)")
            .eq("pedido_id", pedido.id);
          if (error) throw error;
          setDetalles(data || []);
        } catch (error) {
          console.error("Error:", error);
        } finally {
          setLoading(false);
        }
      };
      loadDetalles();
    }
  }, [isOpen, pedido]);

  if (!pedido) return null;

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-xl bg-slate-50/50 backdrop-blur-3xl border-none shadow-[0_32px_64px_-16px_rgba(0,0,0,0.2)] p-0 overflow-hidden rounded-[48px] animate-in slide-in-from-bottom-4 duration-500">

        {/* HEADER PREMIUM: Oscuro y Tecnológico */}
        <div className="bg-slate-900 p-10 text-white relative overflow-hidden">
          <div className="absolute top-0 right-0 w-64 h-64 bg-pink-600/10 rounded-full -mr-32 -mt-32 blur-3xl animate-pulse" />
          <div className="absolute bottom-0 left-0 w-32 h-32 bg-sky-600/10 rounded-full -ml-16 -mb-16 blur-2xl" />

          <div className="flex justify-between items-start relative z-10">
            <div className="p-4 bg-white/5 backdrop-blur-xl border border-white/10 rounded-2xl shadow-xl">
              <Receipt className="w-7 h-7 text-pink-400" />
            </div>
            <div className="flex gap-3">
              <Button
                variant="ghost"
                size="icon"
                className="bg-white/5 hover:bg-white/20 text-white rounded-2xl h-12 w-12 border border-white/5 transition-all active:scale-95"
                onClick={() => window.print()}
              >
                <Printer className="w-5 h-5" />
              </Button>
            </div>
          </div>

          <div className="mt-10 space-y-2 relative z-10">
            <div className="flex items-center gap-3">
              <DialogTitle className="text-4xl font-black tracking-tighter uppercase">
                Comprobante
              </DialogTitle>
              <div className="px-3 py-1 bg-pink-500/20 text-pink-400 rounded-full text-[10px] font-black uppercase tracking-[0.2em] border border-pink-500/30">
                Digital ID
              </div>
            </div>
            <DialogDescription className="text-slate-500 font-bold text-[11px] uppercase tracking-[0.3em] flex items-center gap-2">
              <Hash className="w-3.5 h-3.5 text-pink-500/50" /> Operación: {String(pedido.id).padStart(8, '0')}
            </DialogDescription>
          </div>
        </div>

        {/* CUERPO DEL DOCUMENTO: Estilo Limpio y Estructurado */}
        <div className="p-10 -mt-6 relative z-20">
          <div className="bg-white rounded-[40px] shadow-[0_20px_40px_-12px_rgba(0,0,0,0.1)] border border-slate-100/50 overflow-hidden">

            {/* Metadatos de Cabecera */}
            <div className="p-6 border-b border-dashed border-slate-100 grid grid-cols-2 gap-6 bg-slate-50/50">
              <div className="space-y-2">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                  <Clock className="w-3.5 h-3.5" /> Fecha Registro
                </p>
                <p className="text-sm font-black text-slate-700">
                  {new Date(pedido.created_at).toLocaleDateString('es-PE', { day: '2-digit', month: 'long', year: 'numeric' })}
                </p>
              </div>
              <div className="space-y-2 text-right">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2 justify-end">
                  <CheckCircle2 className="w-3.5 h-3.5" /> Estado Actual
                </p>
                <span className={cn(
                  "text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest border",
                  pedido.estado === 'entregado' ? "bg-emerald-50 text-emerald-600 border-emerald-100" : "bg-amber-50 text-amber-600 border-amber-100"
                )}>
                  {pedido.estado || 'Procesando'}
                </span>
              </div>
            </div>

            {/* Perfil del Cliente */}
            <div className="p-8 flex items-center justify-between border-b border-slate-50 group cursor-default">
              <div className="flex items-center gap-5">
                <div className="w-14 h-14 bg-gradient-to-br from-pink-50 to-white rounded-[20px] flex items-center justify-center border border-pink-100 shadow-sm group-hover:scale-105 transition-transform">
                  <User className="w-7 h-7 text-pink-500" />
                </div>
                <div>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Titular de Cuenta</p>
                  <p className="text-lg font-black text-slate-800 leading-tight">{pedido.clientes?.razon_social || "Venta de Mostrador"}</p>
                </div>
              </div>
              <Button variant="ghost" size="icon" className="rounded-full hover:bg-slate-50">
                <ExternalLink className="w-4 h-4 text-slate-300" />
              </Button>
            </div>

            {/* Desglose de Artículos */}
            <div className="p-8">
              <div className="flex justify-between items-center mb-6">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
                  <Package className="w-4 h-4" /> Detalle de Pedido
                </p>
                <span className="text-[10px] font-black text-slate-300">{detalles.length} Ítems</span>
              </div>

              <div className="space-y-5 max-h-[30vh] overflow-y-auto pr-3 custom-scrollbar">
                {loading ? (
                  <div className="flex flex-col items-center py-10 gap-3">
                    <Loader2 className="w-8 h-8 animate-spin text-pink-500" />
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sincronizando Base de Datos...</p>
                  </div>
                ) : detalles.length === 0 ? (
                  <div className="py-10 text-center text-slate-400 font-bold uppercase text-[10px]">No hay detalles disponibles</div>
                ) : detalles.map((item) => (
                  <div key={item.id} className="flex justify-between items-center group">
                    <div className="flex gap-4">
                      <div className="text-[11px] font-black bg-slate-900 text-white w-7 h-7 rounded-xl flex items-center justify-center shadow-lg group-hover:scale-110 transition-transform">
                        {item.cantidad}
                      </div>
                      <div>
                        <p className="text-sm font-black text-slate-800 group-hover:text-pink-600 transition-colors">
                          {item.productos?.nombre}
                        </p>
                        <div className="flex items-center gap-2 mt-1">
                          <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">SKU: {item.productos?.sku || 'N/A'}</p>
                          <span className="w-1 h-1 rounded-full bg-slate-200"></span>
                          <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">S/ {Number(item.precio_unitario || 0).toFixed(2)} c/u</p>
                        </div>
                      </div>
                    </div>
                    <p className="font-black text-slate-900 text-lg tracking-tighter">
                      S/ {(Number(item.precio_unitario || 0) * item.cantidad).toFixed(2)}
                    </p>
                  </div>
                ))}
              </div>
            </div>

            {/* PIE DE PÁGINA: Totalización Liquidación */}
            <div className="p-8 bg-slate-950 text-white border-t border-white/5 relative overflow-hidden">
              <div className="absolute top-0 right-0 w-32 h-32 bg-pink-500/5 rounded-full -mr-16 -mt-16 blur-3xl" />
              <div className="flex justify-between items-end relative z-10">
                <div className="space-y-1">
                  <p className="text-[11px] font-black text-pink-500 uppercase tracking-[0.3em]">Total Final</p>
                  <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest flex items-center gap-2">
                    <FileText className="w-3.5 h-3.5" /> Incluye IGV (18%)
                  </p>
                </div>
                <div className="text-right">
                  <p className="text-5xl font-black tracking-tighter text-white">
                    <span className="text-xl text-pink-500 mr-2">S/</span>
                    {Number(pedido.total || 0).toLocaleString('es-PE', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                  </p>
                </div>
              </div>
            </div>
          </div>

          {/* Botón de Cierre con Estilo de Retroceso */}
          <button
            onClick={onClose}
            className="w-full mt-10 py-5 rounded-[24px] bg-slate-100 hover:bg-slate-200 text-slate-500 font-black text-xs uppercase tracking-[0.2em] transition-all flex items-center justify-center gap-3 active:scale-95 border border-transparent hover:border-slate-300 shadow-sm"
          >
            <ArrowLeft className="w-4 h-4" />
            Volver al Listado
          </button>
        </div>
      </DialogContent>
    </Dialog>
  );
}

