import { useState } from "react";
import { useForm } from "react-hook-form";
import { toast } from "sonner";
import { X, Factory, Loader2, Save } from "lucide-react";
import { Input }  from "@/components/ui/input";
import { Label }  from "@/components/ui/label";
import { Button } from "@/components/ui/button";

const FIELD_LABEL = "text-[10px] font-black text-gray-400 uppercase tracking-[0.15em] block mb-1.5";
const FIELD_INPUT = "bg-gray-50 border-gray-200 h-10 rounded-lg text-sm font-medium text-gray-700 focus-visible:ring-2 focus-visible:ring-pink-300";

interface CrearOrdenModalProps {
  isOpen:    boolean;
  onClose:   () => void;
  pedido:    any;
  talleres:  any[];
  onSuccess: (orden: any) => void;
}

export function CrearOrdenModal({ isOpen, onClose, pedido, talleres, onSuccess }: CrearOrdenModalProps) {
  const [loading, setLoading] = useState(false);

  // Items del pedido que tienen ficha técnica
  const itemsConFicha = (pedido.items ?? []).filter(
    (item: any) => item.productos?.fichas_tecnicas_id
  );

  const { register, handleSubmit, watch, reset, formState: { errors } } = useForm({
    defaultValues: {
      producto_id:         "",
      taller_id:           "",
      cantidad_solicitada: pedido.total_unidades ?? "",
      fecha_entrega:       "",
      notas:               "",
    },
  });

  const productoSeleccionado = watch("producto_id");
  const itemSeleccionado     = itemsConFicha.find(
    (item: any) => item.productos?.id?.toString() === productoSeleccionado
  );
  const fichaId = itemSeleccionado?.productos?.fichas_tecnicas_id;

  const onSubmit = async (data: any) => {
    if (!fichaId) {
      toast.error("El producto seleccionado no tiene ficha técnica. Créala primero.");
      return;
    }

    setLoading(true);
    try {
      const res = await fetch("/api/admin/ordenes-produccion", {
        method:  "POST",
        headers: { "Content-Type": "application/json" },
        body:    JSON.stringify({
          producto_id:         data.producto_id,
          taller_id:           data.taller_id,
          ficha_id:            fichaId,
          cantidad_solicitada: data.cantidad_solicitada,
          fecha_entrega:       data.fecha_entrega || null,
          notas:               data.notas || null,
        }),
      });

      const result = await res.json();
      if (!res.ok) throw new Error(result.error);

      toast.success("Orden de producción creada");
      reset();
      onSuccess(result.data);
    } catch (error: any) {
      toast.error(error.message);
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/40">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg">

        {/* Header modal */}
        <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-pink-600 rounded-lg">
              <Factory className="text-white w-4 h-4" />
            </div>
            <div>
              <h3 className="text-sm font-black text-gray-800 uppercase tracking-widest">
                Nueva orden de producción
              </h3>
              <p className="text-[11px] text-gray-400">Pedido #{pedido.id}</p>
            </div>
          </div>
          <button
            onClick={() => { reset(); onClose(); }}
            className="p-1.5 text-gray-400 hover:text-gray-700 hover:bg-gray-100 rounded-lg transition-colors"
          >
            <X size={16} />
          </button>
        </div>

        {/* Formulario */}
        <form onSubmit={handleSubmit(onSubmit)} className="p-6 space-y-4">

          {/* Producto */}
          <div>
            <Label className={FIELD_LABEL}>Producto del pedido</Label>
            {itemsConFicha.length === 0 ? (
              <div className="bg-amber-50 border border-amber-100 rounded-lg px-4 py-3 text-xs font-bold text-amber-700">
                Ningún producto del pedido tiene ficha técnica. Créalas primero en el módulo de productos.
              </div>
            ) : (
              <select
                {...register("producto_id", { required: "Selecciona un producto" })}
                className="w-full h-10 px-3 rounded-lg border border-gray-200 bg-gray-50 text-sm font-medium text-gray-700 focus:outline-none focus:ring-2 focus:ring-pink-300"
              >
                <option value="">Seleccionar producto...</option>
                {itemsConFicha.map((item: any) => (
                  <option key={item.id} value={item.productos?.id}>
                    {item.productos?.nombre} — {item.variantes_producto?.color} / {item.variantes_producto?.talla}
                  </option>
                ))}
              </select>
            )}
            {errors.producto_id && (
              <p className="text-[11px] text-red-500 font-semibold mt-1">{errors.producto_id.message as string}</p>
            )}
          </div>

          {/* Ficha detectada */}
          {fichaId && (
            <div className="bg-emerald-50 border border-emerald-100 rounded-lg px-4 py-2.5 text-xs font-bold text-emerald-700">
              Ficha técnica detectada automáticamente
            </div>
          )}

          {/* Taller */}
          <div>
            <Label className={FIELD_LABEL}>Taller</Label>
            <select
              {...register("taller_id", { required: "Selecciona un taller" })}
              className="w-full h-10 px-3 rounded-lg border border-gray-200 bg-gray-50 text-sm font-medium text-gray-700 focus:outline-none focus:ring-2 focus:ring-pink-300"
            >
              <option value="">Seleccionar taller...</option>
              {talleres.map((t: any) => (
                <option key={t.id} value={t.id}>
                  {t.nombre} {t.especialidad ? `· ${t.especialidad}` : ""}
                </option>
              ))}
            </select>
            {errors.taller_id && (
              <p className="text-[11px] text-red-500 font-semibold mt-1">{errors.taller_id.message as string}</p>
            )}
          </div>

          <div className="grid grid-cols-2 gap-4">
            {/* Cantidad */}
            <div>
              <Label className={FIELD_LABEL}>Cantidad solicitada</Label>
              <Input
                type="number"
                min={1}
                {...register("cantidad_solicitada", { required: true, min: 1 })}
                className={FIELD_INPUT}
              />
            </div>

            {/* Fecha entrega */}
            <div>
              <Label className={FIELD_LABEL}>Fecha de entrega</Label>
              <Input
                type="date"
                {...register("fecha_entrega")}
                className={FIELD_INPUT}
              />
            </div>
          </div>

          {/* Notas */}
          <div>
            <Label className={FIELD_LABEL}>Notas</Label>
            <textarea
              {...register("notas")}
              placeholder="Instrucciones especiales para el taller..."
              className="w-full px-3 py-2 rounded-lg border border-gray-200 bg-gray-50 text-sm text-gray-700 focus:outline-none focus:ring-2 focus:ring-pink-300 min-h-[70px] resize-none"
            />
          </div>

          {/* Acciones */}
          <div className="flex justify-end gap-3 pt-2 border-t border-gray-100">
            <Button
              type="button"
              variant="outline"
              onClick={() => { reset(); onClose(); }}
              className="h-9 px-4 font-semibold border-gray-200 text-gray-600"
            >
              Cancelar
            </Button>
            <Button
              type="submit"
              disabled={loading || itemsConFicha.length === 0}
              className="bg-pink-600 hover:bg-pink-700 text-white h-9 px-5 font-bold gap-2 disabled:opacity-60"
            >
              {loading ? (
                <Loader2 className="w-4 h-4 animate-spin" />
              ) : (
                <><Save size={14} /> Crear orden</>
              )}
            </Button>
          </div>
        </form>
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { toast } from "sonner";
import { Factory, ChevronDown, ChevronUp, Loader2 } from "lucide-react";

const ESTADO_COLORS: Record<string, string> = {
  pendiente:    "bg-amber-100 text-amber-700",
  en_proceso:   "bg-blue-100 text-blue-700",
  completada:   "bg-emerald-100 text-emerald-700",
  rechazada:    "bg-red-100 text-red-700",
  enviada:      "bg-purple-100 text-purple-700",
};

const ETAPAS = ["corte", "costura", "bordado", "acabado", "control_calidad", "entrega"];

interface Props {
  ordenes:  any[];
  onUpdate: (orden: any) => void;
}

export function OrdenesProduccionList({ ordenes, onUpdate }: Props) {
  const [expandida, setExpandida] = useState<string | null>(null);
  const [loading,   setLoading]   = useState<string | null>(null);

  const actualizarEtapa = async (ordenId: string, etapa: string) => {
    setLoading(ordenId);
    try {
      const res = await fetch("/api/admin/seguimiento-produccion", {
        method:  "POST",
        headers: { "Content-Type": "application/json" },
        body:    JSON.stringify({ orden_id: ordenId, etapa }),
      });
      const result = await res.json();
      if (!res.ok) throw new Error(result.error);
      toast.success(`Etapa actualizada: ${etapa}`);
    } catch (error: any) {
      toast.error(error.message);
    } finally {
      setLoading(null);
    }
  };

  if (!ordenes.length) {
    return (
      <div className="bg-white rounded-xl border border-gray-100 shadow-sm p-10 text-center space-y-3">
        <Factory className="mx-auto text-gray-300" size={32} />
        <p className="text-sm font-bold text-gray-400">Sin órdenes de producción</p>
        <p className="text-xs text-gray-400">
          Usa el botón <span className="font-bold text-pink-600">Nueva orden de producción</span> para crear una.
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-3">
      {ordenes.map((orden: any) => {
        const isOpen    = expandida === orden.id;
        const etapaActual = orden.seguimientos?.[0]?.etapa ?? null;

        return (
          <div key={orden.id} className="bg-white rounded-xl border border-gray-100 shadow-sm overflow-hidden">

            {/* Cabecera orden */}
            <div
              className="flex items-center justify-between px-5 py-4 cursor-pointer hover:bg-gray-50 transition-colors"
              onClick={() => setExpandida(isOpen ? null : orden.id)}
            >
              <div className="flex items-center gap-3">
                <Factory size={16} className="text-pink-500 shrink-0" />
                <div>
                  <p className="text-sm font-bold text-gray-800">
                    {orden.producto?.nombre ?? "Producto"}
                    <span className="text-gray-400 font-mono text-xs ml-2">#{orden.id}</span>
                  </p>
                  <p className="text-xs text-gray-400 mt-0.5">
                    Taller: <span className="font-bold text-gray-600">{orden.taller?.nombre ?? "—"}</span>
                    {" · "}{orden.cantidad_solicitada} uds.
                    {orden.fecha_entrega && ` · Entrega: ${new Date(orden.fecha_entrega).toLocaleDateString('es-PE')}`}
                  </p>
                </div>
              </div>
              <div className="flex items-center gap-3">
                <span className={`text-[11px] font-bold px-2.5 py-0.5 rounded-full ${ESTADO_COLORS[orden.estado] ?? "bg-gray-100 text-gray-500"}`}>
                  {orden.estado}
                </span>
                {isOpen ? <ChevronUp size={15} className="text-gray-400" /> : <ChevronDown size={15} className="text-gray-400" />}
              </div>
            </div>

            {/* Detalle expandido */}
            {isOpen && (
              <div className="border-t border-gray-100 px-5 py-4 space-y-4">

                {/* Etapas */}
                <div>
                  <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3">
                    Etapa actual
                  </p>
                  <div className="flex flex-wrap gap-2">
                    {ETAPAS.map(etapa => (
                      <button
                        key={etapa}
                        onClick={() => actualizarEtapa(orden.id, etapa)}
                        disabled={loading === orden.id}
                        className={`text-xs font-bold px-3 py-1.5 rounded-lg transition-all border ${
                          etapaActual === etapa
                            ? "bg-pink-600 text-white border-pink-600"
                            : "bg-gray-50 text-gray-500 border-gray-200 hover:border-pink-300 hover:text-pink-600"
                        }`}
                      >
                        {loading === orden.id && etapaActual !== etapa ? (
                          <Loader2 size={11} className="animate-spin" />
                        ) : (
                          etapa.replace(/_/g, " ")
                        )}
                      </button>
                    ))}
                  </div>
                </div>

                {/* Info ficha */}
                {orden.ficha && (
                  <div className="bg-gray-50 rounded-lg p-3 flex items-center gap-3">
                    <div>
                      <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Ficha técnica</p>
                      <p className="text-xs font-bold text-gray-700 mt-0.5">
                        v{orden.ficha.version}
                        <span className="ml-2 font-normal text-gray-400">{orden.ficha.estado}</span>
                      </p>
                    </div>
                  </div>
                )}

                {/* Notas */}
                {orden.notas && (
                  <div>
                    <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Notas</p>
                    <p className="text-xs text-gray-600">{orden.notas}</p>
                  </div>
                )}
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

"use client";

import { useState } from "react";
import { ArrowLeft, ShoppingBag, Clock, Factory } from "lucide-react";
import Link from "next/link";
import { usePermissions } from "@/lib/hooks/usePermissions";
import { PedidoHeader }         from "./PedidoHeader";
import { PedidoItems }          from "./PedidoItems";
import { PedidoSeguimiento }    from "./PedidoSeguimiento";
import { OrdenesProduccionList } from "./OrdenesProduccionList";
import { CrearOrdenModal }       from "./CrearOrdenModal";
import { usePedidos }          from "@/lib/hooks/usePedidos";
import { useOrdenesProduccion } from "@/lib/hooks/useOrdenProduccion";
import { ESTADO_PEDIDO_LABELS, PRIORIDAD_PEDIDO_LABELS } from "@/lib/schemas/pedidos"

const TABS = [
  { id: "items",      label: "Items",          icon: ShoppingBag },
  { id: "seguimiento", label: "Seguimiento",   icon: Clock       },
  { id: "produccion",  label: "Producción",    icon: Factory     },
] as const;

type TabId = typeof TABS[number]["id"];

interface PedidoDetalleProps {
  pedido:   any;
  talleres: any[];
}

const ESTADO_COLORS: Record<string, string> = {
  pendiente:           "bg-amber-100 text-amber-700",
  en_produccion:       "bg-blue-100 text-blue-700",
  listo_para_despacho: "bg-emerald-100 text-emerald-700",
  entregado:           "bg-gray-100 text-gray-600",
  cancelado:           "bg-red-100 text-red-700",
};

const PRIORIDAD_COLORS: Record<string, string> = {
  baja:   "bg-gray-100 text-gray-500",
  normal: "bg-blue-100 text-blue-600",
};

export default function PedidoDetalle({ pedido, talleres }: PedidoDetalleProps) {
  const [activeTab,      setActiveTab]      = useState<TabId>("items");
  const [modalOpen,      setModalOpen]      = useState(false);
  const { update, registrarSeguimiento, isUpdating } = usePedidos();
  const { ordenes, create, registrarEtapa, isCreating } = useOrdenesProduccion();
  const { can } = usePermissions();

  const puedeCrearOrden = can("create", "confecciones") || can("edit", "productos");

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-6xl mx-auto p-4 md:p-8 space-y-6">

        {/* Header */}
        <div>
          <Link
            href="/admin/Panel-Administrativo/pedidos"
            className="inline-flex items-center gap-1.5 text-pink-600 hover:text-pink-700 text-xs font-bold uppercase tracking-widest mb-3 transition-colors"
          >
            <ArrowLeft size={13} />
            Volver a Pedidos
          </Link>

          <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
            <div className="flex items-center gap-3">
              <div className="p-2.5 bg-pink-600 rounded-xl">
                <ShoppingBag className="text-white w-5 h-5" />
              </div>
              <div>
                <h1 className="text-2xl font-bold text-gray-900">
                  Pedido #{pedido.id}
                </h1>
                <div className="flex items-center gap-2 mt-1">
                  <span className={`text-[11px] font-bold px-2.5 py-0.5 rounded-full ${ESTADO_COLORS[pedido.estado] ?? "bg-gray-100 text-gray-600"}`}>
                    {ESTADO_PEDIDO_LABELS[pedido.estado as keyof typeof ESTADO_PEDIDO_LABELS] ?? pedido.estado}
                  </span>
                  <span className={`text-[11px] font-bold px-2.5 py-0.5 rounded-full ${PRIORIDAD_COLORS[pedido.prioridad] ?? "bg-gray-100 text-gray-500"}`}>
                    {PRIORIDAD_PEDIDO_LABELS[pedido.prioridad as keyof typeof PRIORIDAD_PEDIDO_LABELS] ?? pedido.prioridad}
                  </span>
                </div>
              </div>
            </div>

            {puedeCrearOrden && (
              <button
                onClick={() => setModalOpen(true)}
                className="flex items-center gap-2 bg-pink-600 hover:bg-pink-700 text-white text-xs font-bold uppercase tracking-widest px-4 py-2.5 rounded-xl transition-all active:scale-95"
              >
                <Factory size={14} />
                Nueva orden de producción
              </button>
            )}
          </div>
        </div>

        {/* Info cliente + totales */}
        <PedidoHeader pedido={pedido} />

        {/* Tabs */}
        <div className="flex gap-1 bg-white border border-gray-100 rounded-xl p-1 shadow-sm w-fit">
          {TABS.map(({ id, label, icon: Icon }) => (
            <button
              key={id}
              onClick={() => setActiveTab(id)}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg text-xs font-bold uppercase tracking-widest transition-all ${
                activeTab === id
                  ? "bg-pink-600 text-white shadow-sm"
                  : "text-gray-400 hover:text-gray-700 hover:bg-gray-50"
              }`}
            >
              <Icon size={13} />
              {label}
              {id === "produccion" && ordenes.length > 0 && (
                <span className="bg-white/20 text-white text-[10px] font-black px-1.5 py-0.5 rounded-full">
                  {ordenes.length}
                </span>
              )}
            </button>
          ))}
        </div>

        {/* Contenido tabs */}
        {activeTab === "items" && (
          <PedidoItems items={pedido.pedido_items ?? []} />
        )}
        {activeTab === "seguimiento" && (
          <PedidoSeguimiento
            pedidoId={pedido.id}
            seguimientos={pedido.seguimiento_pedido ?? []}
            isLoading={isUpdating}
            onUpdate={(data) => registrarSeguimiento({ pedido_id: pedido.id, ...data })}
          />
        )}
        {activeTab === "produccion" && (
          <OrdenesProduccionList
            ordenes={pedido.confecciones ?? []} 
            onUpdate={(actualizada) => registrarEtapa({ orden_id: actualizada.id, etapa: actualizada.etapa_actual })}
          />
        )}
      </div>

      {/* Modal crear orden */}
      <CrearOrdenModal
        isOpen={modalOpen}
        onClose={() => setModalOpen(false)}
        pedido={pedido}
        talleres={talleres}
        onSuccess={(data) => {
          create(data);   
          setModalOpen(false);
          setActiveTab("produccion");
        }}
      />
    </div>
  );
}

