        {/* ── Sin datos ── */}
        {!loading && data.length === 0 && (
          <TableRow>
            <TableCell colSpan={colSpan} className="py-16 text-center">
              <div className="flex flex-col items-center gap-2">
                <User className="w-10 h-10 text-slate-200" />
