  const [mensaje,     setMensaje]     = useState('');
  const [chat,        setChat]        = useState<ChatMessage[]>([MENSAJE_INICIAL]);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [chat, loading]);

  // Si se colapsa, cerramos el chat también
  const handleCollapse = () => {
    setCollapsed(true);
    setIsOpen(false);
  };

  const handleExpand = () => {
    setCollapsed(false);
  };

  const enviarMensaje = async (texto: string) => {
    const textoTrimmed = texto.trim();
    if (!textoTrimmed || loading) return;

    const nuevoChat: ChatMessage[] = [...chat, { role: 'user', content: textoTrimmed }];
    setChat(nuevoChat);
    setMensaje('');
    setLoading(true);

    try {
      const historialParaAPI = nuevoChat
        .slice(1)
        .map(m => ({ role: m.role === 'user' ? 'user' : 'model', content: m.content }));

      const res = await fetch('/api/portal/chat', {
        method:  'POST',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({ messages: historialParaAPI, cliente_id: cliente?.id }),
      });

      if (!res.ok) {
        const errData = await res.json().catch(() => ({}));
        if (res.status === 401) {
          setChat(prev => [...prev, { role: 'bot', content: 'Su sesión ha expirado. Por favor, inicie sesión nuevamente.' }]);
          return;
        }
        throw new Error(errData.error || `Error ${res.status}`);
      }

      const data = await res.json();
      if (!data.text) throw new Error('Respuesta vacía');
      setChat(prev => [...prev, { role: 'bot', content: data.text }]);
    } catch (error: any) {
      setChat(prev => [...prev, { role: 'bot', content: 'No pude procesar su consulta. Por favor, intente nuevamente.' }]);
    } finally {
      setLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); enviarMensaje(mensaje); }
  };

  return (
    <>
      {/* ── Tab para re-expandir (visible solo cuando está colapsado) ── */}
      {collapsed && (
        <button
          onClick={handleExpand}
          title="Mostrar asistente"
          className="fixed bottom-8 right-0 z-[9999] flex items-center gap-1.5 py-3 pl-3 pr-2 rounded-l-2xl shadow-xl transition-all hover:pr-3 group"
          style={{
            background: '#1a1409',
            border: '1.5px solid #D4AF37',
            borderRight: 'none',
          }}
        >
          <NexusIcon size={16} />
          <ChevronLeft size={14} color="#D4AF37" className="group-hover:-translate-x-0.5 transition-transform" />
        </button>
      )}

      {/* ── Contenedor principal de botones ── */}
      <div
        className="fixed bottom-8 right-8 z-[9999] flex flex-col items-end gap-3 transition-all duration-300"
        style={{
          transform: collapsed ? 'translateX(calc(100% + 2rem))' : 'translateX(0)',
          opacity:   collapsed ? 0 : 1,
