'use client';

import { useState, useEffect } from 'react';
import { getSupabaseBrowserClient } from '@/lib/supabase';
import type { Usuario } from '@/types/auth';

export function useAuth() {
  const [user, setUser] = useState<Usuario | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let isMounted = true;
    const supabase = getSupabaseBrowserClient();
    const initAuth = async () => {
      try {
        // Obtener sesión inicial
        const { data: { session }, error } = await supabase.auth.getSession();

        if (error) {
          console.error('[AUTH] Error obteniendo sesión inicial:', error);
          if (isMounted) setLoading(false);
          return;
        }

        if (session?.user && isMounted) {
          await loadUserData(session.user.id);
        } else if (isMounted) {
          setLoading(false);
        }
      } catch (error) {
        console.error('[AUTH] Error en inicialización de auth:', error);
        if (isMounted) setLoading(false);
      }
    };

    initAuth();

    // Escuchar cambios de auth - usar solo UNA suscripción
    const { data: { subscription } } = supabase.auth.onAuthStateChange(
      async (event: any, session: any) => {
        if (!isMounted) return;

        console.log('[AUTH] Event:', event);
        if (session?.user) {
          await loadUserData(session.user.id);
        } else {
          setUser(null);
          setLoading(false);
        }
      }
    );

    return () => {
      isMounted = false;
      subscription.unsubscribe();
    };
  }, []); // Sin dependencias para que solo se ejecute una vez
  const supabase = getSupabaseBrowserClient();
  const loadUserData = async (authId: string) => {
    try {
      const { data, error } = await supabase
        .from('usuarios')
        .select('*')
        .eq('auth_id', authId)
        .single();

      if (error) throw error;
      setUser(data as Usuario);
    } catch (error) {
      console.error('[AUTH] Error loading user data:', error);
      setUser(null);
    } finally {
      setLoading(false);
    }
  };

  return { user, loading };
}

'use client';

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { toast } from 'sonner';
import {
  fetchClientes,
  fetchClienteById,
  updateCliente,
  desactivarCliente,
} from '@/lib/helpers/clientes-helpers';

export const CLIENTES_KEY = 'clientes';

export function useClientes(params?: {
  busqueda?:     string;
  tipo_cliente?: string;
  activo?:       string;
}) {
  const queryClient = useQueryClient();

  const query = useQuery({
    queryKey: [CLIENTES_KEY, params],
    queryFn:  () => fetchClientes(params),
    refetchOnWindowFocus: false,
  });

  const updateMutation = useMutation({
    mutationFn: ({ id, data }: { id: string; data: any }) => updateCliente(id, data),
    onSuccess: (res) => {
      if (!res.success) { toast.error(res.error ?? 'Error al actualizar'); return; }
      toast.success('Cliente actualizado');
      queryClient.invalidateQueries({ queryKey: [CLIENTES_KEY] });
    },
    onError: () => toast.error('Error de conexión'),
  });

  const desactivarMutation = useMutation({
    mutationFn: desactivarCliente,
    onSuccess: (res) => {
      if (!res.success) { toast.error(res.error ?? 'Error'); return; }
      toast.success('Cliente desactivado');
      queryClient.invalidateQueries({ queryKey: [CLIENTES_KEY] });
    },
    onError: () => toast.error('Error de conexión'),
  });

  return {
    clientes:  query.data ?? [],
    isLoading: query.isLoading,
    refetch:   query.refetch,

    update:      (id: string, data: any) => updateMutation.mutate({ id, data }),
    desactivar:  (id: string)            => desactivarMutation.mutate(id),

    isUpdating:    updateMutation.isPending,
    isDesactivando: desactivarMutation.isPending,
  };
}

export function useCliente(id: string) {
  return useQuery({
    queryKey: [CLIENTES_KEY, id],
    queryFn:  () => fetchClienteById(id),
    enabled:  !!id,
    refetchOnWindowFocus: false,
  });
}

import { useState, useCallback } from 'react';
import { CrearComprobante, Comprobante } from '@/lib/schemas/comprobantes';

export function useComprobantes() {
  const [comprobantes, setComprobantes] = useState<Comprobante[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const obtenerComprobantes = useCallback(async (filtros?: any) => {
    setLoading(true);
    setError(null);
    try {
      const params = new URLSearchParams(filtros || {});
      const response = await fetch(`/api/comprobantes?${params}`);
      if (!response.ok) throw new Error('Error al obtener comprobantes');

      const data: Comprobante[] = await response.json();
      setComprobantes(data);
      return data;
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Error desconocido');
      throw err;
    } finally {
      setLoading(false);
    }
  }, []);

  const crearComprobante = useCallback(async (datos: CrearComprobante) => {
    try {
      const response = await fetch('/api/comprobantes', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(datos),
      });
      if (!response.ok) throw new Error('Error al crear comprobante');

      const nuevoComprobante: Comprobante = await response.json();
      setComprobantes(prev => [...prev, nuevoComprobante]);
      return nuevoComprobante;
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Error desconocido');
      throw err;
    }
  }, []);

  const anularComprobante = useCallback(async (comprobanteId: string, motivo: string) => {
    try {
      const response = await fetch(`/api/comprobantes/${comprobanteId}/anular`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ motivo }),
      });
      if (!response.ok) throw new Error('Error al anular comprobante');

      const comprobanteActualizado: Comprobante = await response.json();
      setComprobantes(prev => prev.map(c => c.id === Number(comprobanteId) ? comprobanteActualizado : c));
      return comprobanteActualizado;
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Error desconocido');
      throw err;
    }
  }, []);

  const enviarComprobante = useCallback(async (comprobanteId: string, emailDestino: string) => {
    try {
      const response = await fetch(`/api/comprobantes/${comprobanteId}/enviar`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ emailDestino }),
      });
      if (!response.ok) throw new Error('Error al enviar comprobante');
      return await response.json();
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Error desconocido');
      throw err;
    }
  }, []);

  const descargarPDF = useCallback(async (comprobanteId: string) => {
    try {
      const response = await fetch(`/api/comprobantes/${comprobanteId}/pdf`);
      if (!response.ok) throw new Error('Error al descargar PDF');
      return await response.blob();
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Error desconocido');
      throw err;
    }
  }, []);

  return {
    comprobantes,
    loading,
    error,
    obtenerComprobantes,
    crearComprobante,
    anularComprobante,
    enviarComprobante,
    descargarPDF,
  };
}

'use client';

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
